INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (20, 'Document P. Ponorul Nou #1', 'Raport conservare patrimoniu - obiectiv 86. Am evaluat starea a 103 inscriptii istorice. Dintre acestea, 137 necesita interventie urgenta. Am curatat 444 metri patrati de graffiti modern. Am instalat 39 panouri informative la intrare. Bariera de protectie acopera 133 metri liniari. Am documentat 407 urme de vandalism. Raportul a fost transmis autoritatilor locale in 317 exemplare. Am propus clasificarea a 351 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 262 persoane simultan. Am instruit 223 ghizi locali. Costul estimat al lucrarilor: 356 lei. Termenul de finalizare: 194 luni.', 'doc_existing_c2_1.txt', 604, NULL, 'text_document', 1775820082);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (46, 2, 'cave', 20, 1775820082);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (47, 9, 'cave_place', 20, 1775820082);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (21, 'Document P. Ponorul Nou #2', 'Raport formare speologica - curs nr. 251. Am instruit 196 cursanti. Durata cursului: 308 zile. Am efectuat 316 sesiuni practice in pestera. Fiecare cursant a parcurs 202 metri de galerie. Am acoperit 174 module teoretice. Examenul final a fost promovat de 50 participanti. Am distribuit 71 seturi de echipament pentru practica. Feedback-ul mediu: 32 din 10. Urmatorul curs incepe in 181 saptamani.', 'doc_existing_c2_2.txt', 397, NULL, 'text_document', 1775820082);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (48, 2, 'cave', 21, 1775820082);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (49, 5, 'cave_area', 21, 1775820082);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (50, 14, 'cave_place', 21, 1775820082);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (22, 'Document P. Ponorul Nou #3', 'Raport conservare patrimoniu - obiectiv 269. Am evaluat starea a 89 inscriptii istorice. Dintre acestea, 269 necesita interventie urgenta. Am curatat 191 metri patrati de graffiti modern. Am instalat 180 panouri informative la intrare. Bariera de protectie acopera 68 metri liniari. Am documentat 387 urme de vandalism. Raportul a fost transmis autoritatilor locale in 271 exemplare. Am propus clasificarea a 201 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 227 persoane simultan. Am instruit 333 ghizi locali. Costul estimat al lucrarilor: 155 lei. Termenul de finalizare: 327 luni.', 'doc_existing_c2_3.txt', 604, NULL, 'text_document', 1775820082);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (51, 2, 'cave', 22, 1775820082);
