INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (53, 11, 'cave_place', 22, 1775820082);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (23, 'Document P. Ponorul Nou #4', 'Inventar echipament - depozit subteran 152. Total corzi disponibile: 180 metri. Dintre acestea, 281 metri necesita inlocuire. Am verificat 360 carabiniere si 9 plachete. Corzi statice diametru 10mm: 143 bucati. Am adaugat 111 saci de transport noi. Lampi de rezerva: 23 bucati cu baterii pline. Stocul de carbid: 282 kilograme. Truse de prim ajutor: 12 complete, verificate. Echipamentul este depozitat la 20 metri de intrare. Urmatoarea verificare programata peste 272 saptamani. Am retras din uz 481 echipamente expirate. Bugetul anual de echipament: 268 lei.', 'doc_existing_c2_4.txt', 561, NULL, 'text_document', 1775820082);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (54, 2, 'cave', 23, 1775820082);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (24, 'Document P. Ponorul Nou #5', 'Raport climatologic subteran - statia 156. Senzorul a inregistrat 36 cicluri complete de temperatura. Temperatura medie anuala: 94 grade Celsius. Amplitudinea termica maxima: 431 grade. Umiditatea relativa medie: 381 procente. Concentratia de CO2: 188 ppm. Curentul de aer maxim masurat: 232 metri pe secunda. Directia predominanta a curentului: sector 411. Datalogerul a functionat 126 zile fara intrerupere. Am descarcat 468 megabytes de date brute. Presiunea barometrica la intrare: 51 mbar. Evaporarea masurata: 8 milimetri pe luna. Am comparat datele cu 88 statii meteorologice de suprafata. Raportul complet include 180 grafice si tabele. Monitorizarea continua de 264 luni confirma stabilitatea climatica.', 'doc_existing_c2_5.txt', 712, NULL, 'text_document', 1775820082);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (55, 2, 'cave', 24, 1775820082);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (56, 5, 'cave_area', 24, 1775820082);
