INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (44, 'Document PeÈ™tera AscendentÄƒ din Guguiova #1', 'Fisa tehnica echipare put - verticala nr. 418. Adancimea: 132 metri. Am instalat 365 spituri din otel inoxidabil. Distanta intre spituri: 158 metri. Lungimea corzii principale: 443 metri. Coarda de siguranta: 353 metri. Am montat 33 protectoare de franghie. Fractionarea se face la 170 metri de buza putului. Deviatia este la 300 metri sub fractionare. Am testat echiparea cu 488 coborari. Ultimul control al spiturilor: acum 148 luni.', 'doc_existing_c4_1.txt', 435, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (100, 4, 'cave', 44, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (101, 13, 'cave_area', 44, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (102, 169, 'cave_place', 44, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (45, 'Document PeÈ™tera AscendentÄƒ din Guguiova #2', 'Raport climatologic subteran - statia 115. Senzorul a inregistrat 53 cicluri complete de temperatura. Temperatura medie anuala: 281 grade Celsius. Amplitudinea termica maxima: 77 grade. Umiditatea relativa medie: 93 procente. Concentratia de CO2: 396 ppm. Curentul de aer maxim masurat: 2 metri pe secunda. Directia predominanta a curentului: sector 206. Datalogerul a functionat 187 zile fara intrerupere. Am descarcat 153 megabytes de date brute. Presiunea barometrica la intrare: 338 mbar. Evaporarea masurata: 447 milimetri pe luna. Am comparat datele cu 260 statii meteorologice de suprafata. Raportul complet include 252 grafice si tabele. Monitorizarea continua de 140 luni confirma stabilitatea climatica.', 'doc_existing_c4_2.txt', 713, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (103, 4, 'cave', 45, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (46, 'Document PeÈ™tera AscendentÄƒ din Guguiova #3', 'Jurnal de expeditie subterana - ziua 39. Am intrat in pestera la ora 373. Parcursul pana la tabara subterana a durat 381 ore. Am transportat 258 kilograme de echipament. La tabara temperatura era de 173 grade. Am montat 258 corturi in sala mare. Rezerva de apa potabila este de 222 litri. Am planificat 8 obiective de explorat. Primul obiectiv se afla la 125 metri de tabara. Comunicarea radio functioneaza pe o distanta de 17 metri. Am verificat starea corzilor pe 131 puturi. Am acumulat 262 ore de topografie. Fotodocumentarea a produs 36 imagini RAW. Urmatoarea tura de explorare incepe in 355 ore. Echipa este formata acum din 467 persoane active. Atmosfera din galeria inferioara contine 416 procente CO2. Am stabilit o limita de siguranta la 213 metri distanta. Stocul de baterii este suficient pentru 109 ore de functionare. Moralul echipei este excelent dupa 3 zile sub pamant.', 'doc_existing_c4_3.txt', 886, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (104, 4, 'cave', 46, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (105, 191, 'cave_place', 46, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (47, 'Document PeÈ™tera AscendentÄƒ din Guguiova #4', 'Plan de explorare - obiectiv 148. Am identificat 412 galerii laterale neexplorate. Lungimea estimata: 337 metri pe fiecare. Sunt necesare 7 zile de explorare. Echipa recomandata: 332 persoane. Echipament vertical necesar pentru 161 puturi. Am pregatit 55 kilograme de echipament. Rezerva de carbid: 180 kilograme. Punctul de plecare este statia topografica 377. Comunicarea radio va fi testata la 30 puncte. Am obtinut 186 autorizatii necesare. Data planificata: peste 312 saptamani. Bugetul estimat: 174 lei.', 'doc_existing_c4_4.txt', 509, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (106, 4, 'cave', 47, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (107, 11, 'cave_area', 47, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (108, 175, 'cave_place', 47, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (48, 'Document PeÈ™tera AscendentÄƒ din Guguiova #5', 'Nota de mentenanta balize - traseul 382. Am verificat 208 balize reflectorizante. Dintre acestea, 97 au fost inlocuite. Am adaugat 412 balize noi in zonele nemarcate. Distanta medie intre balize: 28 metri. Am folosit 416 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 299 metri cu lampa frontala. Am eliminat 283 marcaje vechi si confuze. Traseul total balizat: 354 metri. Urmatoarea verificare: peste 181 luni. Materialul consumat: 242 benzi reflectorizante.', 'doc_existing_c4_5.txt', 483, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (109, 4, 'cave', 48, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (110, 14, 'cave_area', 48, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (49, 'Document PeÈ™tera AscendentÄƒ din Guguiova #6', 'Nota de mentenanta balize - traseul 158. Am verificat 426 balize reflectorizante. Dintre acestea, 433 au fost inlocuite. Am adaugat 185 balize noi in zonele nemarcate. Distanta medie intre balize: 269 metri. Am folosit 311 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 243 metri cu lampa frontala. Am eliminat 57 marcaje vechi si confuze. Traseul total balizat: 419 metri. Urmatoarea verificare: peste 38 luni. Materialul consumat: 486 benzi reflectorizante.', 'doc_existing_c4_6.txt', 483, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (111, 4, 'cave', 49, 1775820083);
