INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (50, 'Document PeÈ™tera AscendentÄƒ din Guguiova #7', 'Plan de explorare - obiectiv 460. Am identificat 127 galerii laterale neexplorate. Lungimea estimata: 28 metri pe fiecare. Sunt necesare 415 zile de explorare. Echipa recomandata: 123 persoane. Echipament vertical necesar pentru 372 puturi. Am pregatit 174 kilograme de echipament. Rezerva de carbid: 143 kilograme. Punctul de plecare este statia topografica 263. Comunicarea radio va fi testata la 470 puncte. Am obtinut 285 autorizatii necesare. Data planificata: peste 113 saptamani. Bugetul estimat: 93 lei.', 'doc_existing_c4_7.txt', 511, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (114, 4, 'cave', 50, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (115, 187, 'cave_place', 50, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (51, 'Document PeÈ™tera AscendentÄƒ din Guguiova #8', 'Observatii topografice - tura nr. 34. Am efectuat 43 vizari cu busola si clinometrul. Lungimea poligonalei este de 424 metri. Diferenta de nivel totala: 29 metri. Am folosit statia nr. 294 ca baza. Eroarea de inchidere a poligonalei a fost sub 500 procente. Galeria prezinta un azimut predominant de 214 grade. Panta medie a galeriei este de 69 grade. Latimea variaza intre 443 si aproximativ dublu. Inaltimea maxima a sectiunii este de 41 metri. Am setat 349 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 180. Estimare galerie nemasurata: 273 metri. Am notat 299 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:246. Informam administratia ariei protejate despre descoperirea de la sectorul 484.', 'doc_existing_c4_8.txt', 748, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (116, 4, 'cave', 51, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (52, 'Document PeÈ™tera AscendentÄƒ din Guguiova #9', 'Inventar echipament - depozit subteran 462. Total corzi disponibile: 256 metri. Dintre acestea, 42 metri necesita inlocuire. Am verificat 67 carabiniere si 329 plachete. Corzi statice diametru 10mm: 76 bucati. Am adaugat 199 saci de transport noi. Lampi de rezerva: 225 bucati cu baterii pline. Stocul de carbid: 376 kilograme. Truse de prim ajutor: 269 complete, verificate. Echipamentul este depozitat la 25 metri de intrare. Urmatoarea verificare programata peste 256 saptamani. Am retras din uz 396 echipamente expirate. Bugetul anual de echipament: 69 lei.', 'doc_existing_c4_9.txt', 561, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (117, 4, 'cave', 52, 1775820083);
