INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (53, 'Document PeÈ™tera AscendentÄƒ din Guguiova #10', 'Observatii topografice - tura nr. 406. Am efectuat 294 vizari cu busola si clinometrul. Lungimea poligonalei este de 102 metri. Diferenta de nivel totala: 471 metri. Am folosit statia nr. 39 ca baza. Eroarea de inchidere a poligonalei a fost sub 418 procente. Galeria prezinta un azimut predominant de 138 grade. Panta medie a galeriei este de 173 grade. Latimea variaza intre 114 si aproximativ dublu. Inaltimea maxima a sectiunii este de 206 metri. Am setat 48 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 420. Estimare galerie nemasurata: 458 metri. Am notat 81 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:474. Informam administratia ariei protejate despre descoperirea de la sectorul 202.', 'doc_existing_c4_10.txt', 750, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (120, 4, 'cave', 53, 1775820083);
