INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (57, 'Document PeÈ™tera cu SÄƒritoare din Guguiova #1', 'Raport climatologic subteran - statia 189. Senzorul a inregistrat 362 cicluri complete de temperatura. Temperatura medie anuala: 358 grade Celsius. Amplitudinea termica maxima: 212 grade. Umiditatea relativa medie: 473 procente. Concentratia de CO2: 439 ppm. Curentul de aer maxim masurat: 263 metri pe secunda. Directia predominanta a curentului: sector 96. Datalogerul a functionat 98 zile fara intrerupere. Am descarcat 435 megabytes de date brute. Presiunea barometrica la intrare: 73 mbar. Evaporarea masurata: 274 milimetri pe luna. Am comparat datele cu 385 statii meteorologice de suprafata. Raportul complet include 183 grafice si tabele. Monitorizarea continua de 400 luni confirma stabilitatea climatica.', 'doc_existing_c5_1.txt', 715, NULL, 'text_document', 1775820083);
