INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (58, 'Document PeÈ™tera cu SÄƒritoare din Guguiova #2', 'Registru vizitatori - luna 299. Total vizitatori inregistrati: 182. Dintre acestia, 413 au participat la ture ghidate. Am organizat 73 ture pentru grupuri scolare. Media participantilor per tura: 405 persoane. Am distribuit 254 pliante informative. Am colectat 405 chestionare de feedback. Nota medie acordata: 456 din 10. Am inregistrat 354 incidente minore. Veniturile din taxe: 86 lei. Am angajat 230 ghizi suplimentari. Programul de vizitare a fost extins cu 373 ore pe saptamana.', 'doc_existing_c5_2.txt', 484, NULL, 'text_document', 1775820083);
