INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (59, 'Document PeÈ™tera cu SÄƒritoare din Guguiova #3', 'Raport climatologic subteran - statia 497. Senzorul a inregistrat 225 cicluri complete de temperatura. Temperatura medie anuala: 489 grade Celsius. Amplitudinea termica maxima: 426 grade. Umiditatea relativa medie: 371 procente. Concentratia de CO2: 496 ppm. Curentul de aer maxim masurat: 232 metri pe secunda. Directia predominanta a curentului: sector 179. Datalogerul a functionat 460 zile fara intrerupere. Am descarcat 494 megabytes de date brute. Presiunea barometrica la intrare: 163 mbar. Evaporarea masurata: 222 milimetri pe luna. Am comparat datele cu 32 statii meteorologice de suprafata. Raportul complet include 2 grafice si tabele. Monitorizarea continua de 301 luni confirma stabilitatea climatica.', 'doc_existing_c5_3.txt', 715, NULL, 'text_document', 1775820083);
