INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (60, 'Document PeÈ™tera cu SÄƒritoare din Guguiova #4', 'Registru vizitatori - luna 304. Total vizitatori inregistrati: 424. Dintre acestia, 14 au participat la ture ghidate. Am organizat 391 ture pentru grupuri scolare. Media participantilor per tura: 417 persoane. Am distribuit 495 pliante informative. Am colectat 471 chestionare de feedback. Nota medie acordata: 85 din 10. Am inregistrat 87 incidente minore. Veniturile din taxe: 108 lei. Am angajat 349 ghizi suplimentari. Programul de vizitare a fost extins cu 330 ore pe saptamana.', 'doc_existing_c5_4.txt', 483, NULL, 'text_document', 1775820083);
