INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (61, 'Document PeÈ™tera cu SÄƒritoare din Guguiova #5', 'Inventar echipament - depozit subteran 115. Total corzi disponibile: 342 metri. Dintre acestea, 185 metri necesita inlocuire. Am verificat 410 carabiniere si 394 plachete. Corzi statice diametru 10mm: 236 bucati. Am adaugat 317 saci de transport noi. Lampi de rezerva: 60 bucati cu baterii pline. Stocul de carbid: 367 kilograme. Truse de prim ajutor: 286 complete, verificate. Echipamentul este depozitat la 37 metri de intrare. Urmatoarea verificare programata peste 445 saptamani. Am retras din uz 371 echipamente expirate. Bugetul anual de echipament: 5 lei.', 'doc_existing_c5_5.txt', 562, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (142, 5, 'cave', 61, 1775820083);
