INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (62, 'Document PeÈ™tera cu SÄƒritoare din Guguiova #6', 'Raport conservare patrimoniu - obiectiv 56. Am evaluat starea a 132 inscriptii istorice. Dintre acestea, 419 necesita interventie urgenta. Am curatat 121 metri patrati de graffiti modern. Am instalat 181 panouri informative la intrare. Bariera de protectie acopera 267 metri liniari. Am documentat 11 urme de vandalism. Raportul a fost transmis autoritatilor locale in 38 exemplare. Am propus clasificarea a 100 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 468 persoane simultan. Am instruit 105 ghizi locali. Costul estimat al lucrarilor: 296 lei. Termenul de finalizare: 127 luni.', 'doc_existing_c5_6.txt', 603, NULL, 'text_document', 1775820083);
