INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (63, 'Document PeÈ™tera cu SÄƒritoare din Guguiova #7', 'Raport formare speologica - curs nr. 19. Am instruit 145 cursanti. Durata cursului: 411 zile. Am efectuat 399 sesiuni practice in pestera. Fiecare cursant a parcurs 314 metri de galerie. Am acoperit 341 module teoretice. Examenul final a fost promovat de 111 participanti. Am distribuit 267 seturi de echipament pentru practica. Feedback-ul mediu: 23 din 10. Urmatorul curs incepe in 404 saptamani.', 'doc_existing_c5_7.txt', 398, NULL, 'text_document', 1775820083);
