INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (66, 'Document PeÈ™tera cu SÄƒritoare din Guguiova #10', 'Nota de mentenanta balize - traseul 427. Am verificat 243 balize reflectorizante. Dintre acestea, 63 au fost inlocuite. Am adaugat 197 balize noi in zonele nemarcate. Distanta medie intre balize: 93 metri. Am folosit 70 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 38 metri cu lampa frontala. Am eliminat 192 marcaje vechi si confuze. Traseul total balizat: 138 metri. Urmatoarea verificare: peste 417 luni. Materialul consumat: 245 benzi reflectorizante.', 'doc_existing_c5_10.txt', 481, NULL, 'text_document', 1775820083);
