INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (67, 'Document PeÈ™tera cu SÄƒritoare din Guguiova #11', 'Fisa tehnica echipare put - verticala nr. 91. Adancimea: 439 metri. Am instalat 55 spituri din otel inoxidabil. Distanta intre spituri: 432 metri. Lungimea corzii principale: 455 metri. Coarda de siguranta: 363 metri. Am montat 306 protectoare de franghie. Fractionarea se face la 290 metri de buza putului. Deviatia este la 221 metri sub fractionare. Am testat echiparea cu 358 coborari. Ultimul control al spiturilor: acum 252 luni.', 'doc_existing_c5_11.txt', 434, NULL, 'text_document', 1775820083);
