INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (91, 'Document PeÈ™tera X1 din Piatra Lupului #1', 'Plan de explorare - obiectiv 179. Am identificat 209 galerii laterale neexplorate. Lungimea estimata: 239 metri pe fiecare. Sunt necesare 84 zile de explorare. Echipa recomandata: 93 persoane. Echipament vertical necesar pentru 401 puturi. Am pregatit 233 kilograme de echipament. Rezerva de carbid: 326 kilograme. Punctul de plecare este statia topografica 213. Comunicarea radio va fi testata la 262 puncte. Am obtinut 122 autorizatii necesare. Data planificata: peste 451 saptamani. Bugetul estimat: 105 lei.', 'doc_existing_c6_1.txt', 511, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (215, 6, 'cave', 91, 1775820083);
