INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (92, 'Document PeÈ™tera X1 din Piatra Lupului #2', 'Inventar echipament - depozit subteran 330. Total corzi disponibile: 121 metri. Dintre acestea, 331 metri necesita inlocuire. Am verificat 447 carabiniere si 130 plachete. Corzi statice diametru 10mm: 308 bucati. Am adaugat 216 saci de transport noi. Lampi de rezerva: 405 bucati cu baterii pline. Stocul de carbid: 322 kilograme. Truse de prim ajutor: 80 complete, verificate. Echipamentul este depozitat la 422 metri de intrare. Urmatoarea verificare programata peste 384 saptamani. Am retras din uz 449 echipamente expirate. Bugetul anual de echipament: 394 lei.', 'doc_existing_c6_2.txt', 565, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (217, 6, 'cave', 92, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (218, 103, 'cave_place', 92, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (93, 'Document PeÈ™tera X1 din Piatra Lupului #3', 'Raport conservare patrimoniu - obiectiv 354. Am evaluat starea a 336 inscriptii istorice. Dintre acestea, 377 necesita interventie urgenta. Am curatat 467 metri patrati de graffiti modern. Am instalat 51 panouri informative la intrare. Bariera de protectie acopera 464 metri liniari. Am documentat 96 urme de vandalism. Raportul a fost transmis autoritatilor locale in 498 exemplare. Am propus clasificarea a 368 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 39 persoane simultan. Am instruit 378 ghizi locali. Costul estimat al lucrarilor: 346 lei. Termenul de finalizare: 78 luni.', 'doc_existing_c6_3.txt', 602, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (219, 6, 'cave', 93, 1775820083);
