INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (94, 'Document PeÈ™tera X1 din Piatra Lupului #4', 'Nota de mentenanta balize - traseul 448. Am verificat 11 balize reflectorizante. Dintre acestea, 40 au fost inlocuite. Am adaugat 284 balize noi in zonele nemarcate. Distanta medie intre balize: 205 metri. Am folosit 202 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 469 metri cu lampa frontala. Am eliminat 84 marcaje vechi si confuze. Traseul total balizat: 114 metri. Urmatoarea verificare: peste 32 luni. Materialul consumat: 175 benzi reflectorizante.', 'doc_existing_c6_4.txt', 481, NULL, 'text_document', 1775820083);
