INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (97, 'Document PeÈ™tera X1 din Piatra Lupului #7', 'Raport formare speologica - curs nr. 155. Am instruit 382 cursanti. Durata cursului: 46 zile. Am efectuat 395 sesiuni practice in pestera. Fiecare cursant a parcurs 41 metri de galerie. Am acoperit 494 module teoretice. Examenul final a fost promovat de 108 participanti. Am distribuit 230 seturi de echipament pentru practica. Feedback-ul mediu: 57 din 10. Urmatorul curs incepe in 315 saptamani.', 'doc_existing_c6_7.txt', 397, NULL, 'text_document', 1775820083);
