INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (110, 'Document PeÈ™tera B1 din Piatra Lupului #1', 'Raport conservare patrimoniu - obiectiv 44. Am evaluat starea a 150 inscriptii istorice. Dintre acestea, 445 necesita interventie urgenta. Am curatat 249 metri patrati de graffiti modern. Am instalat 352 panouri informative la intrare. Bariera de protectie acopera 234 metri liniari. Am documentat 17 urme de vandalism. Raportul a fost transmis autoritatilor locale in 464 exemplare. Am propus clasificarea a 12 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 159 persoane simultan. Am instruit 278 ghizi locali. Costul estimat al lucrarilor: 191 lei. Termenul de finalizare: 360 luni.', 'doc_existing_c7_1.txt', 603, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (258, 7, 'cave', 110, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (259, 27, 'cave_area', 110, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (260, 310, 'cave_place', 110, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (111, 'Document PeÈ™tera B1 din Piatra Lupului #2', 'Inventar echipament - depozit subteran 261. Total corzi disponibile: 56 metri. Dintre acestea, 499 metri necesita inlocuire. Am verificat 33 carabiniere si 34 plachete. Corzi statice diametru 10mm: 432 bucati. Am adaugat 55 saci de transport noi. Lampi de rezerva: 369 bucati cu baterii pline. Stocul de carbid: 473 kilograme. Truse de prim ajutor: 3 complete, verificate. Echipamentul este depozitat la 488 metri de intrare. Urmatoarea verificare programata peste 338 saptamani. Am retras din uz 225 echipamente expirate. Bugetul anual de echipament: 325 lei.', 'doc_existing_c7_2.txt', 560, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (261, 7, 'cave', 111, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (262, 303, 'cave_place', 111, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (112, 'Document PeÈ™tera B1 din Piatra Lupului #3', 'Raport conservare patrimoniu - obiectiv 460. Am evaluat starea a 368 inscriptii istorice. Dintre acestea, 347 necesita interventie urgenta. Am curatat 135 metri patrati de graffiti modern. Am instalat 394 panouri informative la intrare. Bariera de protectie acopera 255 metri liniari. Am documentat 254 urme de vandalism. Raportul a fost transmis autoritatilor locale in 225 exemplare. Am propus clasificarea a 4 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 111 persoane simultan. Am instruit 423 ghizi locali. Costul estimat al lucrarilor: 449 lei. Termenul de finalizare: 31 luni.', 'doc_existing_c7_3.txt', 603, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (263, 7, 'cave', 112, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (264, 27, 'cave_area', 112, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (265, 298, 'cave_place', 112, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (113, 'Document PeÈ™tera B1 din Piatra Lupului #4', 'Jurnal de expeditie subterana - ziua 378. Am intrat in pestera la ora 357. Parcursul pana la tabara subterana a durat 274 ore. Am transportat 481 kilograme de echipament. La tabara temperatura era de 163 grade. Am montat 241 corturi in sala mare. Rezerva de apa potabila este de 338 litri. Am planificat 105 obiective de explorat. Primul obiectiv se afla la 226 metri de tabara. Comunicarea radio functioneaza pe o distanta de 9 metri. Am verificat starea corzilor pe 268 puturi. Am acumulat 77 ore de topografie. Fotodocumentarea a produs 394 imagini RAW. Urmatoarea tura de explorare incepe in 70 ore. Echipa este formata acum din 46 persoane active. Atmosfera din galeria inferioara contine 339 procente CO2. Am stabilit o limita de siguranta la 339 metri distanta. Stocul de baterii este suficient pentru 465 ore de functionare. Moralul echipei este excelent dupa 92 zile sub pamant.', 'doc_existing_c7_4.txt', 887, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (266, 7, 'cave', 113, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (267, 288, 'cave_place', 113, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (114, 'Document PeÈ™tera B1 din Piatra Lupului #5', 'Raport conservare patrimoniu - obiectiv 120. Am evaluat starea a 462 inscriptii istorice. Dintre acestea, 483 necesita interventie urgenta. Am curatat 460 metri patrati de graffiti modern. Am instalat 129 panouri informative la intrare. Bariera de protectie acopera 168 metri liniari. Am documentat 200 urme de vandalism. Raportul a fost transmis autoritatilor locale in 104 exemplare. Am propus clasificarea a 305 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 468 persoane simultan. Am instruit 219 ghizi locali. Costul estimat al lucrarilor: 469 lei. Termenul de finalizare: 185 luni.', 'doc_existing_c7_5.txt', 606, NULL, 'text_document', 1775820083);
