INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (116, 'Document PeÈ™tera B2 din Piatra Lupului #1', 'Observatii topografice - tura nr. 254. Am efectuat 314 vizari cu busola si clinometrul. Lungimea poligonalei este de 12 metri. Diferenta de nivel totala: 75 metri. Am folosit statia nr. 281 ca baza. Eroarea de inchidere a poligonalei a fost sub 169 procente. Galeria prezinta un azimut predominant de 397 grade. Panta medie a galeriei este de 283 grade. Latimea variaza intre 272 si aproximativ dublu. Inaltimea maxima a sectiunii este de 7 metri. Am setat 55 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 318. Estimare galerie nemasurata: 458 metri. Am notat 486 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:256. Informam administratia ariei protejate despre descoperirea de la sectorul 325.', 'doc_existing_c8_1.txt', 748, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (272, 8, 'cave', 116, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (273, 28, 'cave_area', 116, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (274, 377, 'cave_place', 116, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (117, 'Document PeÈ™tera B2 din Piatra Lupului #2', 'Jurnal de expeditie subterana - ziua 476. Am intrat in pestera la ora 442. Parcursul pana la tabara subterana a durat 78 ore. Am transportat 341 kilograme de echipament. La tabara temperatura era de 281 grade. Am montat 360 corturi in sala mare. Rezerva de apa potabila este de 393 litri. Am planificat 72 obiective de explorat. Primul obiectiv se afla la 95 metri de tabara. Comunicarea radio functioneaza pe o distanta de 100 metri. Am verificat starea corzilor pe 484 puturi. Am acumulat 340 ore de topografie. Fotodocumentarea a produs 137 imagini RAW. Urmatoarea tura de explorare incepe in 356 ore. Echipa este formata acum din 459 persoane active. Atmosfera din galeria inferioara contine 92 procente CO2. Am stabilit o limita de siguranta la 134 metri distanta. Stocul de baterii este suficient pentru 3 ore de functionare. Moralul echipei este excelent dupa 165 zile sub pamant.', 'doc_existing_c8_2.txt', 887, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (275, 8, 'cave', 117, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (276, 362, 'cave_place', 117, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (118, 'Document PeÈ™tera B2 din Piatra Lupului #3', 'Raport conservare patrimoniu - obiectiv 432. Am evaluat starea a 197 inscriptii istorice. Dintre acestea, 148 necesita interventie urgenta. Am curatat 221 metri patrati de graffiti modern. Am instalat 196 panouri informative la intrare. Bariera de protectie acopera 351 metri liniari. Am documentat 468 urme de vandalism. Raportul a fost transmis autoritatilor locale in 196 exemplare. Am propus clasificarea a 202 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 470 persoane simultan. Am instruit 272 ghizi locali. Costul estimat al lucrarilor: 50 lei. Termenul de finalizare: 242 luni.', 'doc_existing_c8_3.txt', 605, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (277, 8, 'cave', 118, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (278, 33, 'cave_area', 118, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (279, 378, 'cave_place', 118, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (119, 'Document PeÈ™tera B2 din Piatra Lupului #4', 'Raport conservare patrimoniu - obiectiv 343. Am evaluat starea a 69 inscriptii istorice. Dintre acestea, 341 necesita interventie urgenta. Am curatat 396 metri patrati de graffiti modern. Am instalat 137 panouri informative la intrare. Bariera de protectie acopera 466 metri liniari. Am documentat 165 urme de vandalism. Raportul a fost transmis autoritatilor locale in 21 exemplare. Am propus clasificarea a 197 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 304 persoane simultan. Am instruit 475 ghizi locali. Costul estimat al lucrarilor: 335 lei. Termenul de finalizare: 248 luni.', 'doc_existing_c8_4.txt', 604, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (280, 8, 'cave', 119, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (281, 379, 'cave_place', 119, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (120, 'Document PeÈ™tera B2 din Piatra Lupului #5', 'Raport formare speologica - curs nr. 484. Am instruit 405 cursanti. Durata cursului: 441 zile. Am efectuat 129 sesiuni practice in pestera. Fiecare cursant a parcurs 212 metri de galerie. Am acoperit 230 module teoretice. Examenul final a fost promovat de 78 participanti. Am distribuit 138 seturi de echipament pentru practica. Feedback-ul mediu: 338 din 10. Urmatorul curs incepe in 2 saptamani.', 'doc_existing_c8_5.txt', 397, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (282, 8, 'cave', 120, 1775820083);
