INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (121, 'Document PeÈ™tera B2 din Piatra Lupului #6', 'Raport formare speologica - curs nr. 98. Am instruit 249 cursanti. Durata cursului: 200 zile. Am efectuat 165 sesiuni practice in pestera. Fiecare cursant a parcurs 195 metri de galerie. Am acoperit 238 module teoretice. Examenul final a fost promovat de 342 participanti. Am distribuit 369 seturi de echipament pentru practica. Feedback-ul mediu: 425 din 10. Urmatorul curs incepe in 37 saptamani.', 'doc_existing_c8_6.txt', 398, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (285, 8, 'cave', 121, 1775820083);
