INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (122, 'Document PeÈ™tera B2 din Piatra Lupului #7', 'Inventar echipament - depozit subteran 395. Total corzi disponibile: 242 metri. Dintre acestea, 266 metri necesita inlocuire. Am verificat 196 carabiniere si 497 plachete. Corzi statice diametru 10mm: 79 bucati. Am adaugat 38 saci de transport noi. Lampi de rezerva: 268 bucati cu baterii pline. Stocul de carbid: 439 kilograme. Truse de prim ajutor: 82 complete, verificate. Echipamentul este depozitat la 18 metri de intrare. Urmatoarea verificare programata peste 31 saptamani. Am retras din uz 270 echipamente expirate. Bugetul anual de echipament: 80 lei.', 'doc_existing_c8_7.txt', 560, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (288, 8, 'cave', 122, 1775820083);
