INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (141, 'Document PeÈ™tera B3 din Piatra Lupului #1', 'Plan de explorare - obiectiv 308. Am identificat 300 galerii laterale neexplorate. Lungimea estimata: 272 metri pe fiecare. Sunt necesare 380 zile de explorare. Echipa recomandata: 224 persoane. Echipament vertical necesar pentru 359 puturi. Am pregatit 393 kilograme de echipament. Rezerva de carbid: 98 kilograme. Punctul de plecare este statia topografica 115. Comunicarea radio va fi testata la 252 puncte. Am obtinut 412 autorizatii necesare. Data planificata: peste 417 saptamani. Bugetul estimat: 455 lei.', 'doc_existing_c9_1.txt', 512, NULL, 'text_document', 1775820083);
