INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (142, 'Document PeÈ™tera B3 din Piatra Lupului #2', 'Plan de explorare - obiectiv 290. Am identificat 442 galerii laterale neexplorate. Lungimea estimata: 135 metri pe fiecare. Sunt necesare 220 zile de explorare. Echipa recomandata: 225 persoane. Echipament vertical necesar pentru 323 puturi. Am pregatit 242 kilograme de echipament. Rezerva de carbid: 196 kilograme. Punctul de plecare este statia topografica 398. Comunicarea radio va fi testata la 425 puncte. Am obtinut 245 autorizatii necesare. Data planificata: peste 429 saptamani. Bugetul estimat: 246 lei.', 'doc_existing_c9_2.txt', 513, NULL, 'text_document', 1775820083);
