INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (143, 'Document PeÈ™tera B3 din Piatra Lupului #3', 'Observatii topografice - tura nr. 338. Am efectuat 206 vizari cu busola si clinometrul. Lungimea poligonalei este de 370 metri. Diferenta de nivel totala: 229 metri. Am folosit statia nr. 349 ca baza. Eroarea de inchidere a poligonalei a fost sub 104 procente. Galeria prezinta un azimut predominant de 412 grade. Panta medie a galeriei este de 264 grade. Latimea variaza intre 82 si aproximativ dublu. Inaltimea maxima a sectiunii este de 177 metri. Am setat 66 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 410. Estimare galerie nemasurata: 247 metri. Am notat 453 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:397. Informam administratia ariei protejate despre descoperirea de la sectorul 453.', 'doc_existing_c9_3.txt', 751, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (339, 9, 'cave', 143, 1775820083);
