INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (144, 'Document PeÈ™tera B3 din Piatra Lupului #4', 'Nota de mentenanta balize - traseul 49. Am verificat 428 balize reflectorizante. Dintre acestea, 438 au fost inlocuite. Am adaugat 199 balize noi in zonele nemarcate. Distanta medie intre balize: 95 metri. Am folosit 55 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 284 metri cu lampa frontala. Am eliminat 301 marcaje vechi si confuze. Traseul total balizat: 398 metri. Urmatoarea verificare: peste 33 luni. Materialul consumat: 353 benzi reflectorizante.', 'doc_existing_c9_4.txt', 481, NULL, 'text_document', 1775820083);
