INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (146, 'Document PeÈ™tera B3 din Piatra Lupului #6', 'Observatii topografice - tura nr. 91. Am efectuat 156 vizari cu busola si clinometrul. Lungimea poligonalei este de 403 metri. Diferenta de nivel totala: 37 metri. Am folosit statia nr. 141 ca baza. Eroarea de inchidere a poligonalei a fost sub 471 procente. Galeria prezinta un azimut predominant de 362 grade. Panta medie a galeriei este de 499 grade. Latimea variaza intre 188 si aproximativ dublu. Inaltimea maxima a sectiunii este de 227 metri. Am setat 289 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 368. Estimare galerie nemasurata: 209 metri. Am notat 175 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:328. Informam administratia ariei protejate despre descoperirea de la sectorul 116.', 'doc_existing_c9_6.txt', 751, NULL, 'text_document', 1775820083);
