INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (147, 'Document PeÈ™tera B3 din Piatra Lupului #7', 'Raport climatologic subteran - statia 269. Senzorul a inregistrat 174 cicluri complete de temperatura. Temperatura medie anuala: 295 grade Celsius. Amplitudinea termica maxima: 490 grade. Umiditatea relativa medie: 70 procente. Concentratia de CO2: 249 ppm. Curentul de aer maxim masurat: 334 metri pe secunda. Directia predominanta a curentului: sector 459. Datalogerul a functionat 22 zile fara intrerupere. Am descarcat 35 megabytes de date brute. Presiunea barometrica la intrare: 41 mbar. Evaporarea masurata: 386 milimetri pe luna. Am comparat datele cu 140 statii meteorologice de suprafata. Raportul complet include 291 grafice si tabele. Monitorizarea continua de 405 luni confirma stabilitatea climatica.', 'doc_existing_c9_7.txt', 714, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (349, 9, 'cave', 147, 1775820083);
