INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (148, 'Document PeÈ™tera B3 din Piatra Lupului #8', 'Observatii topografice - tura nr. 379. Am efectuat 436 vizari cu busola si clinometrul. Lungimea poligonalei este de 483 metri. Diferenta de nivel totala: 150 metri. Am folosit statia nr. 228 ca baza. Eroarea de inchidere a poligonalei a fost sub 448 procente. Galeria prezinta un azimut predominant de 305 grade. Panta medie a galeriei este de 263 grade. Latimea variaza intre 459 si aproximativ dublu. Inaltimea maxima a sectiunii este de 130 metri. Am setat 386 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 458. Estimare galerie nemasurata: 52 metri. Am notat 396 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:46. Informam administratia ariei protejate despre descoperirea de la sectorul 304.', 'doc_existing_c9_8.txt', 751, NULL, 'text_document', 1775820083);
