INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (149, 'Document PeÈ™tera B3 din Piatra Lupului #9', 'Inventar echipament - depozit subteran 342. Total corzi disponibile: 442 metri. Dintre acestea, 289 metri necesita inlocuire. Am verificat 23 carabiniere si 441 plachete. Corzi statice diametru 10mm: 360 bucati. Am adaugat 207 saci de transport noi. Lampi de rezerva: 19 bucati cu baterii pline. Stocul de carbid: 325 kilograme. Truse de prim ajutor: 64 complete, verificate. Echipamentul este depozitat la 438 metri de intrare. Urmatoarea verificare programata peste 180 saptamani. Am retras din uz 222 echipamente expirate. Bugetul anual de echipament: 164 lei.', 'doc_existing_c9_9.txt', 563, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (354, 9, 'cave', 149, 1775820083);
