INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (150, 'Document PeÈ™tera B3 din Piatra Lupului #10', 'Fisa tehnica echipare put - verticala nr. 402. Adancimea: 136 metri. Am instalat 73 spituri din otel inoxidabil. Distanta intre spituri: 310 metri. Lungimea corzii principale: 474 metri. Coarda de siguranta: 235 metri. Am montat 272 protectoare de franghie. Fractionarea se face la 65 metri de buza putului. Deviatia este la 10 metri sub fractionare. Am testat echiparea cu 284 coborari. Ultimul control al spiturilor: acum 78 luni.', 'doc_existing_c9_10.txt', 432, NULL, 'text_document', 1775820083);
