INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (163, 'Document PeÈ™tera B4 din Piatra Lupului #1', 'Registru vizitatori - luna 27. Total vizitatori inregistrati: 266. Dintre acestia, 36 au participat la ture ghidate. Am organizat 3 ture pentru grupuri scolare. Media participantilor per tura: 17 persoane. Am distribuit 307 pliante informative. Am colectat 285 chestionare de feedback. Nota medie acordata: 88 din 10. Am inregistrat 306 incidente minore. Veniturile din taxe: 345 lei. Am angajat 4 ghizi suplimentari. Programul de vizitare a fost extins cu 52 ore pe saptamana.', 'doc_existing_c10_1.txt', 477, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (388, 10, 'cave', 163, 1775820083);
