INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (180, 'Document PeÈ™tera B5 din Piatra Lupului #1', 'Jurnal de expeditie subterana - ziua 341. Am intrat in pestera la ora 245. Parcursul pana la tabara subterana a durat 172 ore. Am transportat 413 kilograme de echipament. La tabara temperatura era de 213 grade. Am montat 444 corturi in sala mare. Rezerva de apa potabila este de 318 litri. Am planificat 303 obiective de explorat. Primul obiectiv se afla la 441 metri de tabara. Comunicarea radio functioneaza pe o distanta de 467 metri. Am verificat starea corzilor pe 380 puturi. Am acumulat 486 ore de topografie. Fotodocumentarea a produs 391 imagini RAW. Urmatoarea tura de explorare incepe in 483 ore. Echipa este formata acum din 158 persoane active. Atmosfera din galeria inferioara contine 328 procente CO2. Am stabilit o limita de siguranta la 180 metri distanta. Stocul de baterii este suficient pentru 49 ore de functionare. Moralul echipei este excelent dupa 235 zile sub pamant.', 'doc_existing_c11_1.txt', 892, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (428, 11, 'cave', 180, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (429, 46, 'cave_area', 180, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (430, 501, 'cave_place', 180, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (181, 'Document PeÈ™tera B5 din Piatra Lupului #2', 'Registru vizitatori - luna 318. Total vizitatori inregistrati: 172. Dintre acestia, 50 au participat la ture ghidate. Am organizat 198 ture pentru grupuri scolare. Media participantilor per tura: 127 persoane. Am distribuit 134 pliante informative. Am colectat 85 chestionare de feedback. Nota medie acordata: 54 din 10. Am inregistrat 404 incidente minore. Veniturile din taxe: 45 lei. Am angajat 117 ghizi suplimentari. Programul de vizitare a fost extins cu 102 ore pe saptamana.', 'doc_existing_c11_2.txt', 482, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (431, 11, 'cave', 181, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (432, 47, 'cave_area', 181, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (433, 522, 'cave_place', 181, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (182, 'Document PeÈ™tera B5 din Piatra Lupului #3', 'Fisa tehnica echipare put - verticala nr. 104. Adancimea: 264 metri. Am instalat 141 spituri din otel inoxidabil. Distanta intre spituri: 472 metri. Lungimea corzii principale: 428 metri. Coarda de siguranta: 297 metri. Am montat 424 protectoare de franghie. Fractionarea se face la 402 metri de buza putului. Deviatia este la 337 metri sub fractionare. Am testat echiparea cu 453 coborari. Ultimul control al spiturilor: acum 130 luni.', 'doc_existing_c11_3.txt', 436, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (434, 11, 'cave', 182, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (435, 526, 'cave_place', 182, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (183, 'Document PeÈ™tera B5 din Piatra Lupului #4', 'Jurnal de expeditie subterana - ziua 304. Am intrat in pestera la ora 241. Parcursul pana la tabara subterana a durat 43 ore. Am transportat 346 kilograme de echipament. La tabara temperatura era de 402 grade. Am montat 204 corturi in sala mare. Rezerva de apa potabila este de 411 litri. Am planificat 17 obiective de explorat. Primul obiectiv se afla la 40 metri de tabara. Comunicarea radio functioneaza pe o distanta de 25 metri. Am verificat starea corzilor pe 211 puturi. Am acumulat 225 ore de topografie. Fotodocumentarea a produs 362 imagini RAW. Urmatoarea tura de explorare incepe in 304 ore. Echipa este formata acum din 81 persoane active. Atmosfera din galeria inferioara contine 22 procente CO2. Am stabilit o limita de siguranta la 289 metri distanta. Stocul de baterii este suficient pentru 334 ore de functionare. Moralul echipei este excelent dupa 469 zile sub pamant.', 'doc_existing_c11_4.txt', 887, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (436, 11, 'cave', 183, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (437, 47, 'cave_area', 183, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (184, 'Document PeÈ™tera B5 din Piatra Lupului #5', 'Raport conservare patrimoniu - obiectiv 311. Am evaluat starea a 278 inscriptii istorice. Dintre acestea, 398 necesita interventie urgenta. Am curatat 247 metri patrati de graffiti modern. Am instalat 88 panouri informative la intrare. Bariera de protectie acopera 272 metri liniari. Am documentat 70 urme de vandalism. Raportul a fost transmis autoritatilor locale in 439 exemplare. Am propus clasificarea a 243 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 168 persoane simultan. Am instruit 26 ghizi locali. Costul estimat al lucrarilor: 449 lei. Termenul de finalizare: 208 luni.', 'doc_existing_c11_5.txt', 603, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (438, 11, 'cave', 184, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (439, 482, 'cave_place', 184, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (185, 'Document PeÈ™tera B5 din Piatra Lupului #6', 'Raport climatologic subteran - statia 5. Senzorul a inregistrat 485 cicluri complete de temperatura. Temperatura medie anuala: 103 grade Celsius. Amplitudinea termica maxima: 3 grade. Umiditatea relativa medie: 296 procente. Concentratia de CO2: 384 ppm. Curentul de aer maxim masurat: 474 metri pe secunda. Directia predominanta a curentului: sector 487. Datalogerul a functionat 359 zile fara intrerupere. Am descarcat 405 megabytes de date brute. Presiunea barometrica la intrare: 250 mbar. Evaporarea masurata: 467 milimetri pe luna. Am comparat datele cu 104 statii meteorologice de suprafata. Raportul complet include 312 grafice si tabele. Monitorizarea continua de 210 luni confirma stabilitatea climatica.', 'doc_existing_c11_6.txt', 714, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (440, 11, 'cave', 185, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (441, 47, 'cave_area', 185, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (442, 487, 'cave_place', 185, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (186, 'Document PeÈ™tera B5 din Piatra Lupului #7', 'Fisa tehnica echipare put - verticala nr. 135. Adancimea: 269 metri. Am instalat 416 spituri din otel inoxidabil. Distanta intre spituri: 39 metri. Lungimea corzii principale: 115 metri. Coarda de siguranta: 95 metri. Am montat 381 protectoare de franghie. Fractionarea se face la 112 metri de buza putului. Deviatia este la 150 metri sub fractionare. Am testat echiparea cu 273 coborari. Ultimul control al spiturilor: acum 264 luni.', 'doc_existing_c11_7.txt', 434, NULL, 'text_document', 1775820083);
