INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (188, 'Document PeÈ™tera B5 din Piatra Lupului #9', 'Raport conservare patrimoniu - obiectiv 353. Am evaluat starea a 109 inscriptii istorice. Dintre acestea, 213 necesita interventie urgenta. Am curatat 455 metri patrati de graffiti modern. Am instalat 270 panouri informative la intrare. Bariera de protectie acopera 333 metri liniari. Am documentat 11 urme de vandalism. Raportul a fost transmis autoritatilor locale in 270 exemplare. Am propus clasificarea a 238 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 98 persoane simultan. Am instruit 143 ghizi locali. Costul estimat al lucrarilor: 14 lei. Termenul de finalizare: 398 luni.', 'doc_existing_c11_9.txt', 603, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (447, 11, 'cave', 188, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (448, 46, 'cave_area', 188, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (189, 'Document PeÈ™tera B5 din Piatra Lupului #10', 'Registru vizitatori - luna 13. Total vizitatori inregistrati: 434. Dintre acestia, 332 au participat la ture ghidate. Am organizat 312 ture pentru grupuri scolare. Media participantilor per tura: 83 persoane. Am distribuit 278 pliante informative. Am colectat 489 chestionare de feedback. Nota medie acordata: 347 din 10. Am inregistrat 338 incidente minore. Veniturile din taxe: 498 lei. Am angajat 178 ghizi suplimentari. Programul de vizitare a fost extins cu 315 ore pe saptamana.', 'doc_existing_c11_10.txt', 484, NULL, 'text_document', 1775820083);
