INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (211, 'Document PeÈ™tera C1 din Piatra Lupului #9', 'Fisa tehnica echipare put - verticala nr. 49. Adancimea: 252 metri. Am instalat 455 spituri din otel inoxidabil. Distanta intre spituri: 113 metri. Lungimea corzii principale: 493 metri. Coarda de siguranta: 88 metri. Am montat 467 protectoare de franghie. Fractionarea se face la 404 metri de buza putului. Deviatia este la 19 metri sub fractionare. Am testat echiparea cu 49 coborari. Ultimul control al spiturilor: acum 93 luni.', 'doc_existing_c12_9.txt', 431, NULL, 'text_document', 1775820083);
