INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (232, 'Document PeÈ™tera C2 din Piatra Lupului #1', 'Raport conservare patrimoniu - obiectiv 356. Am evaluat starea a 440 inscriptii istorice. Dintre acestea, 462 necesita interventie urgenta. Am curatat 21 metri patrati de graffiti modern. Am instalat 328 panouri informative la intrare. Bariera de protectie acopera 316 metri liniari. Am documentat 361 urme de vandalism. Raportul a fost transmis autoritatilor locale in 354 exemplare. Am propus clasificarea a 462 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 14 persoane simultan. Am instruit 376 ghizi locali. Costul estimat al lucrarilor: 409 lei. Termenul de finalizare: 440 luni.', 'doc_existing_c13_1.txt', 604, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (547, 13, 'cave', 232, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (548, 56, 'cave_area', 232, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (233, 'Document PeÈ™tera C2 din Piatra Lupului #2', 'Inventar echipament - depozit subteran 211. Total corzi disponibile: 101 metri. Dintre acestea, 439 metri necesita inlocuire. Am verificat 235 carabiniere si 258 plachete. Corzi statice diametru 10mm: 475 bucati. Am adaugat 185 saci de transport noi. Lampi de rezerva: 499 bucati cu baterii pline. Stocul de carbid: 282 kilograme. Truse de prim ajutor: 168 complete, verificate. Echipamentul este depozitat la 351 metri de intrare. Urmatoarea verificare programata peste 467 saptamani. Am retras din uz 300 echipamente expirate. Bugetul anual de echipament: 488 lei.', 'doc_existing_c13_2.txt', 566, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (549, 13, 'cave', 233, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (550, 56, 'cave_area', 233, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (234, 'Document PeÈ™tera C2 din Piatra Lupului #3', 'Jurnal de expeditie subterana - ziua 466. Am intrat in pestera la ora 209. Parcursul pana la tabara subterana a durat 231 ore. Am transportat 145 kilograme de echipament. La tabara temperatura era de 294 grade. Am montat 40 corturi in sala mare. Rezerva de apa potabila este de 110 litri. Am planificat 391 obiective de explorat. Primul obiectiv se afla la 78 metri de tabara. Comunicarea radio functioneaza pe o distanta de 340 metri. Am verificat starea corzilor pe 174 puturi. Am acumulat 146 ore de topografie. Fotodocumentarea a produs 352 imagini RAW. Urmatoarea tura de explorare incepe in 14 ore. Echipa este formata acum din 109 persoane active. Atmosfera din galeria inferioara contine 440 procente CO2. Am stabilit o limita de siguranta la 75 metri distanta. Stocul de baterii este suficient pentru 298 ore de functionare. Moralul echipei este excelent dupa 271 zile sub pamant.', 'doc_existing_c13_3.txt', 889, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (551, 13, 'cave', 234, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (552, 56, 'cave_area', 234, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (235, 'Document PeÈ™tera C2 din Piatra Lupului #4', 'Raport climatologic subteran - statia 334. Senzorul a inregistrat 132 cicluri complete de temperatura. Temperatura medie anuala: 277 grade Celsius. Amplitudinea termica maxima: 492 grade. Umiditatea relativa medie: 32 procente. Concentratia de CO2: 223 ppm. Curentul de aer maxim masurat: 22 metri pe secunda. Directia predominanta a curentului: sector 329. Datalogerul a functionat 312 zile fara intrerupere. Am descarcat 343 megabytes de date brute. Presiunea barometrica la intrare: 7 mbar. Evaporarea masurata: 487 milimetri pe luna. Am comparat datele cu 124 statii meteorologice de suprafata. Raportul complet include 176 grafice si tabele. Monitorizarea continua de 231 luni confirma stabilitatea climatica.', 'doc_existing_c13_4.txt', 714, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (553, 13, 'cave', 235, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (236, 'Document PeÈ™tera C2 din Piatra Lupului #5', 'Raport formare speologica - curs nr. 320. Am instruit 367 cursanti. Durata cursului: 295 zile. Am efectuat 239 sesiuni practice in pestera. Fiecare cursant a parcurs 158 metri de galerie. Am acoperit 169 module teoretice. Examenul final a fost promovat de 64 participanti. Am distribuit 265 seturi de echipament pentru practica. Feedback-ul mediu: 380 din 10. Urmatorul curs incepe in 195 saptamani.', 'doc_existing_c13_5.txt', 399, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (554, 13, 'cave', 236, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (237, 'Document PeÈ™tera C2 din Piatra Lupului #6', 'Fisa tehnica echipare put - verticala nr. 128. Adancimea: 474 metri. Am instalat 34 spituri din otel inoxidabil. Distanta intre spituri: 451 metri. Lungimea corzii principale: 202 metri. Coarda de siguranta: 230 metri. Am montat 438 protectoare de franghie. Fractionarea se face la 317 metri de buza putului. Deviatia este la 145 metri sub fractionare. Am testat echiparea cu 101 coborari. Ultimul control al spiturilor: acum 29 luni.', 'doc_existing_c13_6.txt', 434, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (555, 13, 'cave', 237, 1775820083);
