INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (238, 'Document PeÈ™tera C2 din Piatra Lupului #7', 'Raport formare speologica - curs nr. 437. Am instruit 102 cursanti. Durata cursului: 311 zile. Am efectuat 108 sesiuni practice in pestera. Fiecare cursant a parcurs 109 metri de galerie. Am acoperit 124 module teoretice. Examenul final a fost promovat de 446 participanti. Am distribuit 474 seturi de echipament pentru practica. Feedback-ul mediu: 430 din 10. Urmatorul curs incepe in 427 saptamani.', 'doc_existing_c13_7.txt', 400, NULL, 'text_document', 1775820083);
