INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (239, 'Document PeÈ™tera C2 din Piatra Lupului #8', 'Fisa tehnica echipare put - verticala nr. 456. Adancimea: 486 metri. Am instalat 401 spituri din otel inoxidabil. Distanta intre spituri: 303 metri. Lungimea corzii principale: 301 metri. Coarda de siguranta: 62 metri. Am montat 416 protectoare de franghie. Fractionarea se face la 156 metri de buza putului. Deviatia este la 405 metri sub fractionare. Am testat echiparea cu 272 coborari. Ultimul control al spiturilor: acum 291 luni.', 'doc_existing_c13_8.txt', 435, NULL, 'text_document', 1775820083);
