INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (240, 'Document PeÈ™tera C2 din Piatra Lupului #9', 'Inventar echipament - depozit subteran 409. Total corzi disponibile: 296 metri. Dintre acestea, 104 metri necesita inlocuire. Am verificat 83 carabiniere si 112 plachete. Corzi statice diametru 10mm: 312 bucati. Am adaugat 281 saci de transport noi. Lampi de rezerva: 367 bucati cu baterii pline. Stocul de carbid: 437 kilograme. Truse de prim ajutor: 328 complete, verificate. Echipamentul este depozitat la 155 metri de intrare. Urmatoarea verificare programata peste 430 saptamani. Am retras din uz 233 echipamente expirate. Bugetul anual de echipament: 351 lei.', 'doc_existing_c13_9.txt', 565, NULL, 'text_document', 1775820083);
