INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (243, 'Document PeÈ™tera C2 din Piatra Lupului #12', 'Plan de explorare - obiectiv 80. Am identificat 459 galerii laterale neexplorate. Lungimea estimata: 430 metri pe fiecare. Sunt necesare 483 zile de explorare. Echipa recomandata: 36 persoane. Echipament vertical necesar pentru 416 puturi. Am pregatit 228 kilograme de echipament. Rezerva de carbid: 272 kilograme. Punctul de plecare este statia topografica 30. Comunicarea radio va fi testata la 71 puncte. Am obtinut 398 autorizatii necesare. Data planificata: peste 205 saptamani. Bugetul estimat: 70 lei.', 'doc_existing_c13_12.txt', 508, NULL, 'text_document', 1775820083);
