INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (245, 'Document PeÈ™tera C2 din Piatra Lupului #14', 'Raport formare speologica - curs nr. 279. Am instruit 445 cursanti. Durata cursului: 63 zile. Am efectuat 460 sesiuni practice in pestera. Fiecare cursant a parcurs 237 metri de galerie. Am acoperit 91 module teoretice. Examenul final a fost promovat de 278 participanti. Am distribuit 251 seturi de echipament pentru practica. Feedback-ul mediu: 11 din 10. Urmatorul curs incepe in 345 saptamani.', 'doc_existing_c13_14.txt', 397, NULL, 'text_document', 1775820083);
