INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (246, 'Document PeÈ™tera C2 din Piatra Lupului #15', 'Observatii topografice - tura nr. 367. Am efectuat 483 vizari cu busola si clinometrul. Lungimea poligonalei este de 262 metri. Diferenta de nivel totala: 298 metri. Am folosit statia nr. 104 ca baza. Eroarea de inchidere a poligonalei a fost sub 190 procente. Galeria prezinta un azimut predominant de 70 grade. Panta medie a galeriei este de 141 grade. Latimea variaza intre 76 si aproximativ dublu. Inaltimea maxima a sectiunii este de 303 metri. Am setat 288 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 376. Estimare galerie nemasurata: 57 metri. Am notat 225 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:149. Informam administratia ariei protejate despre descoperirea de la sectorul 199.', 'doc_existing_c13_15.txt', 750, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (574, 13, 'cave', 246, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (575, 56, 'cave_area', 246, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (247, 'Document PeÈ™tera C2 din Piatra Lupului #16', 'Raport conservare patrimoniu - obiectiv 368. Am evaluat starea a 42 inscriptii istorice. Dintre acestea, 471 necesita interventie urgenta. Am curatat 109 metri patrati de graffiti modern. Am instalat 282 panouri informative la intrare. Bariera de protectie acopera 285 metri liniari. Am documentat 55 urme de vandalism. Raportul a fost transmis autoritatilor locale in 228 exemplare. Am propus clasificarea a 146 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 472 persoane simultan. Am instruit 54 ghizi locali. Costul estimat al lucrarilor: 104 lei. Termenul de finalizare: 267 luni.', 'doc_existing_c13_16.txt', 603, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (576, 13, 'cave', 247, 1775820083);
