INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (248, 'Document PeÈ™tera C2 din Piatra Lupului #17', 'Raport climatologic subteran - statia 98. Senzorul a inregistrat 123 cicluri complete de temperatura. Temperatura medie anuala: 326 grade Celsius. Amplitudinea termica maxima: 159 grade. Umiditatea relativa medie: 298 procente. Concentratia de CO2: 312 ppm. Curentul de aer maxim masurat: 129 metri pe secunda. Directia predominanta a curentului: sector 158. Datalogerul a functionat 195 zile fara intrerupere. Am descarcat 476 megabytes de date brute. Presiunea barometrica la intrare: 375 mbar. Evaporarea masurata: 422 milimetri pe luna. Am comparat datele cu 338 statii meteorologice de suprafata. Raportul complet include 226 grafice si tabele. Monitorizarea continua de 312 luni confirma stabilitatea climatica.', 'doc_existing_c13_17.txt', 717, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (579, 13, 'cave', 248, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (580, 629, 'cave_place', 248, 1775820083);
