INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (259, 'Document PeÈ™tera C3 din Piatra Lupului #1', 'Registru vizitatori - luna 2. Total vizitatori inregistrati: 186. Dintre acestia, 136 au participat la ture ghidate. Am organizat 379 ture pentru grupuri scolare. Media participantilor per tura: 435 persoane. Am distribuit 460 pliante informative. Am colectat 399 chestionare de feedback. Nota medie acordata: 34 din 10. Am inregistrat 91 incidente minore. Veniturile din taxe: 453 lei. Am angajat 136 ghizi suplimentari. Programul de vizitare a fost extins cu 162 ore pe saptamana.', 'doc_existing_c14_1.txt', 482, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (608, 14, 'cave', 259, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (260, 'Document PeÈ™tera C3 din Piatra Lupului #2', 'Registru vizitatori - luna 332. Total vizitatori inregistrati: 152. Dintre acestia, 263 au participat la ture ghidate. Am organizat 322 ture pentru grupuri scolare. Media participantilor per tura: 37 persoane. Am distribuit 199 pliante informative. Am colectat 359 chestionare de feedback. Nota medie acordata: 312 din 10. Am inregistrat 299 incidente minore. Veniturile din taxe: 355 lei. Am angajat 282 ghizi suplimentari. Programul de vizitare a fost extins cu 19 ore pe saptamana.', 'doc_existing_c14_2.txt', 484, NULL, 'text_document', 1775820083);
