INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (261, 'Document PeÈ™tera C3 din Piatra Lupului #3', 'Raport conservare patrimoniu - obiectiv 106. Am evaluat starea a 191 inscriptii istorice. Dintre acestea, 180 necesita interventie urgenta. Am curatat 205 metri patrati de graffiti modern. Am instalat 233 panouri informative la intrare. Bariera de protectie acopera 342 metri liniari. Am documentat 314 urme de vandalism. Raportul a fost transmis autoritatilor locale in 462 exemplare. Am propus clasificarea a 468 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 414 persoane simultan. Am instruit 247 ghizi locali. Costul estimat al lucrarilor: 466 lei. Termenul de finalizare: 492 luni.', 'doc_existing_c14_3.txt', 606, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (611, 14, 'cave', 261, 1775820083);
