INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (263, 'Document PeÈ™tera C3 din Piatra Lupului #5', 'Jurnal de expeditie subterana - ziua 232. Am intrat in pestera la ora 129. Parcursul pana la tabara subterana a durat 176 ore. Am transportat 488 kilograme de echipament. La tabara temperatura era de 434 grade. Am montat 72 corturi in sala mare. Rezerva de apa potabila este de 410 litri. Am planificat 475 obiective de explorat. Primul obiectiv se afla la 409 metri de tabara. Comunicarea radio functioneaza pe o distanta de 92 metri. Am verificat starea corzilor pe 8 puturi. Am acumulat 43 ore de topografie. Fotodocumentarea a produs 173 imagini RAW. Urmatoarea tura de explorare incepe in 86 ore. Echipa este formata acum din 302 persoane active. Atmosfera din galeria inferioara contine 433 procente CO2. Am stabilit o limita de siguranta la 302 metri distanta. Stocul de baterii este suficient pentru 235 ore de functionare. Moralul echipei este excelent dupa 418 zile sub pamant.', 'doc_existing_c14_5.txt', 887, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (616, 14, 'cave', 263, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (617, 57, 'cave_area', 263, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (618, 668, 'cave_place', 263, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (264, 'Document PeÈ™tera C3 din Piatra Lupului #6', 'Observatii topografice - tura nr. 375. Am efectuat 327 vizari cu busola si clinometrul. Lungimea poligonalei este de 14 metri. Diferenta de nivel totala: 63 metri. Am folosit statia nr. 319 ca baza. Eroarea de inchidere a poligonalei a fost sub 37 procente. Galeria prezinta un azimut predominant de 117 grade. Panta medie a galeriei este de 255 grade. Latimea variaza intre 55 si aproximativ dublu. Inaltimea maxima a sectiunii este de 374 metri. Am setat 35 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 183. Estimare galerie nemasurata: 475 metri. Am notat 194 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:339. Informam administratia ariei protejate despre descoperirea de la sectorul 494.', 'doc_existing_c14_6.txt', 748, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (619, 14, 'cave', 264, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (620, 675, 'cave_place', 264, 1775820083);
