INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (269, 'Document PeÈ™tera C3 din Piatra Lupului #11', 'Fisa tehnica echipare put - verticala nr. 465. Adancimea: 269 metri. Am instalat 396 spituri din otel inoxidabil. Distanta intre spituri: 470 metri. Lungimea corzii principale: 275 metri. Coarda de siguranta: 115 metri. Am montat 148 protectoare de franghie. Fractionarea se face la 275 metri de buza putului. Deviatia este la 484 metri sub fractionare. Am testat echiparea cu 304 coborari. Ultimul control al spiturilor: acum 497 luni.', 'doc_existing_c14_11.txt', 436, NULL, 'text_document', 1775820083);
