INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (270, 'Document PeÈ™tera C3 din Piatra Lupului #12', 'Inventar echipament - depozit subteran 229. Total corzi disponibile: 89 metri. Dintre acestea, 12 metri necesita inlocuire. Am verificat 251 carabiniere si 499 plachete. Corzi statice diametru 10mm: 445 bucati. Am adaugat 115 saci de transport noi. Lampi de rezerva: 80 bucati cu baterii pline. Stocul de carbid: 184 kilograme. Truse de prim ajutor: 299 complete, verificate. Echipamentul este depozitat la 282 metri de intrare. Urmatoarea verificare programata peste 476 saptamani. Am retras din uz 469 echipamente expirate. Bugetul anual de echipament: 367 lei.', 'doc_existing_c14_12.txt', 563, NULL, 'text_document', 1775820083);
