INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (287, 'Document PeÈ™tera C4 din Piatra Lupului #1', 'Inventar echipament - depozit subteran 170. Total corzi disponibile: 382 metri. Dintre acestea, 298 metri necesita inlocuire. Am verificat 489 carabiniere si 383 plachete. Corzi statice diametru 10mm: 55 bucati. Am adaugat 54 saci de transport noi. Lampi de rezerva: 197 bucati cu baterii pline. Stocul de carbid: 487 kilograme. Truse de prim ajutor: 468 complete, verificate. Echipamentul este depozitat la 143 metri de intrare. Urmatoarea verificare programata peste 239 saptamani. Am retras din uz 170 echipamente expirate. Bugetul anual de echipament: 423 lei.', 'doc_existing_c15_1.txt', 564, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (669, 15, 'cave', 287, 1775820083);
