INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (288, 'Document PeÈ™tera C4 din Piatra Lupului #2', 'Nota de mentenanta balize - traseul 193. Am verificat 396 balize reflectorizante. Dintre acestea, 346 au fost inlocuite. Am adaugat 133 balize noi in zonele nemarcate. Distanta medie intre balize: 367 metri. Am folosit 357 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 6 metri cu lampa frontala. Am eliminat 167 marcaje vechi si confuze. Traseul total balizat: 161 metri. Urmatoarea verificare: peste 266 luni. Materialul consumat: 199 benzi reflectorizante.', 'doc_existing_c15_2.txt', 483, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (671, 15, 'cave', 288, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (672, 59, 'cave_area', 288, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (289, 'Document PeÈ™tera C4 din Piatra Lupului #3', 'Jurnal de expeditie subterana - ziua 180. Am intrat in pestera la ora 21. Parcursul pana la tabara subterana a durat 296 ore. Am transportat 239 kilograme de echipament. La tabara temperatura era de 291 grade. Am montat 222 corturi in sala mare. Rezerva de apa potabila este de 172 litri. Am planificat 31 obiective de explorat. Primul obiectiv se afla la 30 metri de tabara. Comunicarea radio functioneaza pe o distanta de 14 metri. Am verificat starea corzilor pe 67 puturi. Am acumulat 385 ore de topografie. Fotodocumentarea a produs 198 imagini RAW. Urmatoarea tura de explorare incepe in 77 ore. Echipa este formata acum din 305 persoane active. Atmosfera din galeria inferioara contine 194 procente CO2. Am stabilit o limita de siguranta la 452 metri distanta. Stocul de baterii este suficient pentru 25 ore de functionare. Moralul echipei este excelent dupa 272 zile sub pamant.', 'doc_existing_c15_3.txt', 886, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (673, 15, 'cave', 289, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (674, 59, 'cave_area', 289, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (675, 729, 'cave_place', 289, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (290, 'Document PeÈ™tera C4 din Piatra Lupului #4', 'Nota de mentenanta balize - traseul 181. Am verificat 46 balize reflectorizante. Dintre acestea, 417 au fost inlocuite. Am adaugat 364 balize noi in zonele nemarcate. Distanta medie intre balize: 497 metri. Am folosit 126 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 281 metri cu lampa frontala. Am eliminat 154 marcaje vechi si confuze. Traseul total balizat: 459 metri. Urmatoarea verificare: peste 316 luni. Materialul consumat: 66 benzi reflectorizante.', 'doc_existing_c15_4.txt', 483, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (676, 15, 'cave', 290, 1775820083);
