INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (291, 'Document PeÈ™tera C4 din Piatra Lupului #5', 'Raport formare speologica - curs nr. 414. Am instruit 151 cursanti. Durata cursului: 5 zile. Am efectuat 187 sesiuni practice in pestera. Fiecare cursant a parcurs 459 metri de galerie. Am acoperit 76 module teoretice. Examenul final a fost promovat de 431 participanti. Am distribuit 31 seturi de echipament pentru practica. Feedback-ul mediu: 192 din 10. Urmatorul curs incepe in 233 saptamani.', 'doc_existing_c15_5.txt', 396, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (678, 15, 'cave', 291, 1775820083);
