INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (292, 'Document PeÈ™tera C4 din Piatra Lupului #6', 'Raport climatologic subteran - statia 279. Senzorul a inregistrat 28 cicluri complete de temperatura. Temperatura medie anuala: 212 grade Celsius. Amplitudinea termica maxima: 15 grade. Umiditatea relativa medie: 191 procente. Concentratia de CO2: 123 ppm. Curentul de aer maxim masurat: 194 metri pe secunda. Directia predominanta a curentului: sector 292. Datalogerul a functionat 351 zile fara intrerupere. Am descarcat 186 megabytes de date brute. Presiunea barometrica la intrare: 174 mbar. Evaporarea masurata: 370 milimetri pe luna. Am comparat datele cu 482 statii meteorologice de suprafata. Raportul complet include 470 grafice si tabele. Monitorizarea continua de 475 luni confirma stabilitatea climatica.', 'doc_existing_c15_6.txt', 716, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (680, 15, 'cave', 292, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (681, 59, 'cave_area', 292, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (293, 'Document PeÈ™tera C4 din Piatra Lupului #7', 'Registru vizitatori - luna 166. Total vizitatori inregistrati: 8. Dintre acestia, 104 au participat la ture ghidate. Am organizat 493 ture pentru grupuri scolare. Media participantilor per tura: 216 persoane. Am distribuit 419 pliante informative. Am colectat 460 chestionare de feedback. Nota medie acordata: 317 din 10. Am inregistrat 356 incidente minore. Veniturile din taxe: 98 lei. Am angajat 325 ghizi suplimentari. Programul de vizitare a fost extins cu 162 ore pe saptamana.', 'doc_existing_c15_7.txt', 483, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (682, 15, 'cave', 293, 1775820083);
