INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (295, 'Document PeÈ™tera C4 din Piatra Lupului #9', 'Raport conservare patrimoniu - obiectiv 348. Am evaluat starea a 207 inscriptii istorice. Dintre acestea, 136 necesita interventie urgenta. Am curatat 280 metri patrati de graffiti modern. Am instalat 346 panouri informative la intrare. Bariera de protectie acopera 197 metri liniari. Am documentat 158 urme de vandalism. Raportul a fost transmis autoritatilor locale in 159 exemplare. Am propus clasificarea a 464 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 14 persoane simultan. Am instruit 168 ghizi locali. Costul estimat al lucrarilor: 7 lei. Termenul de finalizare: 250 luni.', 'doc_existing_c15_9.txt', 603, NULL, 'text_document', 1775820083);
