INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (306, 'Document PeÈ™tera C5 din Piatra Lupului #1', 'Nota de mentenanta balize - traseul 4. Am verificat 208 balize reflectorizante. Dintre acestea, 376 au fost inlocuite. Am adaugat 499 balize noi in zonele nemarcate. Distanta medie intre balize: 437 metri. Am folosit 90 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 134 metri cu lampa frontala. Am eliminat 66 marcaje vechi si confuze. Traseul total balizat: 6 metri. Urmatoarea verificare: peste 36 luni. Materialul consumat: 291 benzi reflectorizante.', 'doc_existing_c16_1.txt', 478, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (713, 16, 'cave', 306, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (307, 'Document PeÈ™tera C5 din Piatra Lupului #2', 'Raport formare speologica - curs nr. 185. Am instruit 295 cursanti. Durata cursului: 217 zile. Am efectuat 294 sesiuni practice in pestera. Fiecare cursant a parcurs 149 metri de galerie. Am acoperit 440 module teoretice. Examenul final a fost promovat de 201 participanti. Am distribuit 82 seturi de echipament pentru practica. Feedback-ul mediu: 11 din 10. Urmatorul curs incepe in 498 saptamani.', 'doc_existing_c16_2.txt', 398, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (714, 16, 'cave', 307, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (715, 61, 'cave_area', 307, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (716, 793, 'cave_place', 307, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (308, 'Document PeÈ™tera C5 din Piatra Lupului #3', 'Registru vizitatori - luna 212. Total vizitatori inregistrati: 91. Dintre acestia, 382 au participat la ture ghidate. Am organizat 411 ture pentru grupuri scolare. Media participantilor per tura: 363 persoane. Am distribuit 492 pliante informative. Am colectat 434 chestionare de feedback. Nota medie acordata: 437 din 10. Am inregistrat 337 incidente minore. Veniturile din taxe: 216 lei. Am angajat 119 ghizi suplimentari. Programul de vizitare a fost extins cu 385 ore pe saptamana.', 'doc_existing_c16_3.txt', 485, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (717, 16, 'cave', 308, 1775820083);
