INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (309, 'Document PeÈ™tera C5 din Piatra Lupului #4', 'Nota de mentenanta balize - traseul 361. Am verificat 225 balize reflectorizante. Dintre acestea, 112 au fost inlocuite. Am adaugat 302 balize noi in zonele nemarcate. Distanta medie intre balize: 418 metri. Am folosit 362 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 251 metri cu lampa frontala. Am eliminat 315 marcaje vechi si confuze. Traseul total balizat: 264 metri. Urmatoarea verificare: peste 67 luni. Materialul consumat: 60 benzi reflectorizante.', 'doc_existing_c16_4.txt', 483, NULL, 'text_document', 1775820083);
