INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (318, 'Document PeÈ™tera C6 din Piatra Lupului #1', 'Nota de mentenanta balize - traseul 242. Am verificat 166 balize reflectorizante. Dintre acestea, 316 au fost inlocuite. Am adaugat 393 balize noi in zonele nemarcate. Distanta medie intre balize: 266 metri. Am folosit 162 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 229 metri cu lampa frontala. Am eliminat 127 marcaje vechi si confuze. Traseul total balizat: 252 metri. Urmatoarea verificare: peste 434 luni. Materialul consumat: 316 benzi reflectorizante.', 'doc_existing_c17_1.txt', 485, NULL, 'text_document', 1775820083);
