INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (335, 'Document PeÈ™tera C7 din Piatra Lupului #1', 'Raport conservare patrimoniu - obiectiv 315. Am evaluat starea a 109 inscriptii istorice. Dintre acestea, 479 necesita interventie urgenta. Am curatat 7 metri patrati de graffiti modern. Am instalat 125 panouri informative la intrare. Bariera de protectie acopera 34 metri liniari. Am documentat 129 urme de vandalism. Raportul a fost transmis autoritatilor locale in 416 exemplare. Am propus clasificarea a 58 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 494 persoane simultan. Am instruit 106 ghizi locali. Costul estimat al lucrarilor: 176 lei. Termenul de finalizare: 105 luni.', 'doc_existing_c18_1.txt', 602, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (782, 18, 'cave', 335, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (783, 67, 'cave_area', 335, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (336, 'Document PeÈ™tera C7 din Piatra Lupului #2', 'Jurnal de expeditie subterana - ziua 351. Am intrat in pestera la ora 10. Parcursul pana la tabara subterana a durat 439 ore. Am transportat 267 kilograme de echipament. La tabara temperatura era de 23 grade. Am montat 168 corturi in sala mare. Rezerva de apa potabila este de 256 litri. Am planificat 37 obiective de explorat. Primul obiectiv se afla la 253 metri de tabara. Comunicarea radio functioneaza pe o distanta de 335 metri. Am verificat starea corzilor pe 191 puturi. Am acumulat 92 ore de topografie. Fotodocumentarea a produs 441 imagini RAW. Urmatoarea tura de explorare incepe in 184 ore. Echipa este formata acum din 101 persoane active. Atmosfera din galeria inferioara contine 225 procente CO2. Am stabilit o limita de siguranta la 427 metri distanta. Stocul de baterii este suficient pentru 476 ore de functionare. Moralul echipei este excelent dupa 201 zile sub pamant.', 'doc_existing_c18_2.txt', 889, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (784, 18, 'cave', 336, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (785, 64, 'cave_area', 336, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (786, 951, 'cave_place', 336, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (337, 'Document PeÈ™tera C7 din Piatra Lupului #3', 'Inventar echipament - depozit subteran 165. Total corzi disponibile: 336 metri. Dintre acestea, 433 metri necesita inlocuire. Am verificat 227 carabiniere si 485 plachete. Corzi statice diametru 10mm: 338 bucati. Am adaugat 321 saci de transport noi. Lampi de rezerva: 10 bucati cu baterii pline. Stocul de carbid: 159 kilograme. Truse de prim ajutor: 344 complete, verificate. Echipamentul este depozitat la 135 metri de intrare. Urmatoarea verificare programata peste 44 saptamani. Am retras din uz 483 echipamente expirate. Bugetul anual de echipament: 357 lei.', 'doc_existing_c18_3.txt', 564, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (787, 18, 'cave', 337, 1775820083);
