INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (338, 'Document PeÈ™tera C7 din Piatra Lupului #4', 'Raport climatologic subteran - statia 390. Senzorul a inregistrat 80 cicluri complete de temperatura. Temperatura medie anuala: 93 grade Celsius. Amplitudinea termica maxima: 30 grade. Umiditatea relativa medie: 317 procente. Concentratia de CO2: 375 ppm. Curentul de aer maxim masurat: 246 metri pe secunda. Directia predominanta a curentului: sector 117. Datalogerul a functionat 50 zile fara intrerupere. Am descarcat 395 megabytes de date brute. Presiunea barometrica la intrare: 484 mbar. Evaporarea masurata: 101 milimetri pe luna. Am comparat datele cu 99 statii meteorologice de suprafata. Raportul complet include 193 grafice si tabele. Monitorizarea continua de 173 luni confirma stabilitatea climatica.', 'doc_existing_c18_4.txt', 713, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (789, 18, 'cave', 338, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (790, 66, 'cave_area', 338, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (339, 'Document PeÈ™tera C7 din Piatra Lupului #5', 'Jurnal de expeditie subterana - ziua 464. Am intrat in pestera la ora 248. Parcursul pana la tabara subterana a durat 35 ore. Am transportat 247 kilograme de echipament. La tabara temperatura era de 186 grade. Am montat 305 corturi in sala mare. Rezerva de apa potabila este de 192 litri. Am planificat 409 obiective de explorat. Primul obiectiv se afla la 292 metri de tabara. Comunicarea radio functioneaza pe o distanta de 229 metri. Am verificat starea corzilor pe 371 puturi. Am acumulat 41 ore de topografie. Fotodocumentarea a produs 465 imagini RAW. Urmatoarea tura de explorare incepe in 111 ore. Echipa este formata acum din 372 persoane active. Atmosfera din galeria inferioara contine 418 procente CO2. Am stabilit o limita de siguranta la 139 metri distanta. Stocul de baterii este suficient pentru 178 ore de functionare. Moralul echipei este excelent dupa 399 zile sub pamant.', 'doc_existing_c18_5.txt', 891, NULL, 'text_document', 1775820083);
