INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (340, 'Document PeÈ™tera C7 din Piatra Lupului #6', 'Fisa tehnica echipare put - verticala nr. 472. Adancimea: 61 metri. Am instalat 448 spituri din otel inoxidabil. Distanta intre spituri: 397 metri. Lungimea corzii principale: 304 metri. Coarda de siguranta: 417 metri. Am montat 53 protectoare de franghie. Fractionarea se face la 388 metri de buza putului. Deviatia este la 118 metri sub fractionare. Am testat echiparea cu 360 coborari. Ultimul control al spiturilor: acum 243 luni.', 'doc_existing_c18_6.txt', 434, NULL, 'text_document', 1775820083);
