INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (341, 'Document PeÈ™tera C7 din Piatra Lupului #7', 'Raport formare speologica - curs nr. 400. Am instruit 283 cursanti. Durata cursului: 90 zile. Am efectuat 104 sesiuni practice in pestera. Fiecare cursant a parcurs 151 metri de galerie. Am acoperit 153 module teoretice. Examenul final a fost promovat de 416 participanti. Am distribuit 181 seturi de echipament pentru practica. Feedback-ul mediu: 19 din 10. Urmatorul curs incepe in 106 saptamani.', 'doc_existing_c18_7.txt', 398, NULL, 'text_document', 1775820083);
