INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (342, 'Document PeÈ™tera C7 din Piatra Lupului #8', 'Plan de explorare - obiectiv 368. Am identificat 489 galerii laterale neexplorate. Lungimea estimata: 291 metri pe fiecare. Sunt necesare 28 zile de explorare. Echipa recomandata: 384 persoane. Echipament vertical necesar pentru 161 puturi. Am pregatit 320 kilograme de echipament. Rezerva de carbid: 285 kilograme. Punctul de plecare este statia topografica 297. Comunicarea radio va fi testata la 431 puncte. Am obtinut 21 autorizatii necesare. Data planificata: peste 206 saptamani. Bugetul estimat: 363 lei.', 'doc_existing_c18_8.txt', 511, NULL, 'text_document', 1775820083);
