INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (364, 'Document PeÈ™tera C8 din Piatra Lupului #1', 'Raport formare speologica - curs nr. 149. Am instruit 10 cursanti. Durata cursului: 213 zile. Am efectuat 57 sesiuni practice in pestera. Fiecare cursant a parcurs 494 metri de galerie. Am acoperit 57 module teoretice. Examenul final a fost promovat de 482 participanti. Am distribuit 429 seturi de echipament pentru practica. Feedback-ul mediu: 8 din 10. Urmatorul curs incepe in 240 saptamani.', 'doc_existing_c19_1.txt', 395, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (848, 19, 'cave', 364, 1775820083);
