INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (365, 'Document PeÈ™tera C8 din Piatra Lupului #2', 'Raport conservare patrimoniu - obiectiv 362. Am evaluat starea a 222 inscriptii istorice. Dintre acestea, 126 necesita interventie urgenta. Am curatat 296 metri patrati de graffiti modern. Am instalat 244 panouri informative la intrare. Bariera de protectie acopera 159 metri liniari. Am documentat 112 urme de vandalism. Raportul a fost transmis autoritatilor locale in 341 exemplare. Am propus clasificarea a 234 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 74 persoane simultan. Am instruit 96 ghizi locali. Costul estimat al lucrarilor: 332 lei. Termenul de finalizare: 464 luni.', 'doc_existing_c19_2.txt', 604, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (850, 19, 'cave', 365, 1775820083);
