INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (366, 'Document PeÈ™tera C8 din Piatra Lupului #3', 'Fisa tehnica echipare put - verticala nr. 198. Adancimea: 144 metri. Am instalat 250 spituri din otel inoxidabil. Distanta intre spituri: 406 metri. Lungimea corzii principale: 365 metri. Coarda de siguranta: 397 metri. Am montat 294 protectoare de franghie. Fractionarea se face la 81 metri de buza putului. Deviatia este la 291 metri sub fractionare. Am testat echiparea cu 201 coborari. Ultimul control al spiturilor: acum 377 luni.', 'doc_existing_c19_3.txt', 435, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (853, 19, 'cave', 366, 1775820083);
