INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (367, 'Document PeÈ™tera C8 din Piatra Lupului #4', 'Raport conservare patrimoniu - obiectiv 127. Am evaluat starea a 117 inscriptii istorice. Dintre acestea, 283 necesita interventie urgenta. Am curatat 252 metri patrati de graffiti modern. Am instalat 482 panouri informative la intrare. Bariera de protectie acopera 91 metri liniari. Am documentat 296 urme de vandalism. Raportul a fost transmis autoritatilor locale in 37 exemplare. Am propus clasificarea a 215 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 363 persoane simultan. Am instruit 478 ghizi locali. Costul estimat al lucrarilor: 476 lei. Termenul de finalizare: 358 luni.', 'doc_existing_c19_4.txt', 604, NULL, 'text_document', 1775820083);
