INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (370, 'Document PeÈ™tera C8 din Piatra Lupului #7', 'Observatii topografice - tura nr. 290. Am efectuat 41 vizari cu busola si clinometrul. Lungimea poligonalei este de 238 metri. Diferenta de nivel totala: 98 metri. Am folosit statia nr. 311 ca baza. Eroarea de inchidere a poligonalei a fost sub 118 procente. Galeria prezinta un azimut predominant de 431 grade. Panta medie a galeriei este de 159 grade. Latimea variaza intre 113 si aproximativ dublu. Inaltimea maxima a sectiunii este de 371 metri. Am setat 133 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 156. Estimare galerie nemasurata: 409 metri. Am notat 210 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:332. Informam administratia ariei protejate despre descoperirea de la sectorul 208.', 'doc_existing_c19_7.txt', 751, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (863, 19, 'cave', 370, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (864, 986, 'cave_place', 370, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (371, 'Document PeÈ™tera C8 din Piatra Lupului #8', 'Observatii topografice - tura nr. 215. Am efectuat 468 vizari cu busola si clinometrul. Lungimea poligonalei este de 10 metri. Diferenta de nivel totala: 412 metri. Am folosit statia nr. 19 ca baza. Eroarea de inchidere a poligonalei a fost sub 195 procente. Galeria prezinta un azimut predominant de 396 grade. Panta medie a galeriei este de 174 grade. Latimea variaza intre 32 si aproximativ dublu. Inaltimea maxima a sectiunii este de 429 metri. Am setat 28 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 275. Estimare galerie nemasurata: 414 metri. Am notat 491 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:153. Informam administratia ariei protejate despre descoperirea de la sectorul 346.', 'doc_existing_c19_8.txt', 749, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (865, 19, 'cave', 371, 1775820083);
