INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (372, 'Document PeÈ™tera C8 din Piatra Lupului #9', 'Nota de mentenanta balize - traseul 197. Am verificat 464 balize reflectorizante. Dintre acestea, 116 au fost inlocuite. Am adaugat 171 balize noi in zonele nemarcate. Distanta medie intre balize: 127 metri. Am folosit 60 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 230 metri cu lampa frontala. Am eliminat 117 marcaje vechi si confuze. Traseul total balizat: 464 metri. Urmatoarea verificare: peste 33 luni. Materialul consumat: 303 benzi reflectorizante.', 'doc_existing_c19_9.txt', 483, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (867, 19, 'cave', 372, 1775820083);
