INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (373, 'Document PeÈ™tera C8 din Piatra Lupului #10', 'Registru vizitatori - luna 58. Total vizitatori inregistrati: 204. Dintre acestia, 392 au participat la ture ghidate. Am organizat 310 ture pentru grupuri scolare. Media participantilor per tura: 361 persoane. Am distribuit 171 pliante informative. Am colectat 169 chestionare de feedback. Nota medie acordata: 258 din 10. Am inregistrat 339 incidente minore. Veniturile din taxe: 270 lei. Am angajat 196 ghizi suplimentari. Programul de vizitare a fost extins cu 401 ore pe saptamana.', 'doc_existing_c19_10.txt', 485, NULL, 'text_document', 1775820083);
