INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (374, 'Document PeÈ™tera C8 din Piatra Lupului #11', 'Jurnal de expeditie subterana - ziua 89. Am intrat in pestera la ora 335. Parcursul pana la tabara subterana a durat 395 ore. Am transportat 436 kilograme de echipament. La tabara temperatura era de 140 grade. Am montat 389 corturi in sala mare. Rezerva de apa potabila este de 278 litri. Am planificat 90 obiective de explorat. Primul obiectiv se afla la 200 metri de tabara. Comunicarea radio functioneaza pe o distanta de 135 metri. Am verificat starea corzilor pe 217 puturi. Am acumulat 157 ore de topografie. Fotodocumentarea a produs 69 imagini RAW. Urmatoarea tura de explorare incepe in 294 ore. Echipa este formata acum din 13 persoane active. Atmosfera din galeria inferioara contine 336 procente CO2. Am stabilit o limita de siguranta la 224 metri distanta. Stocul de baterii este suficient pentru 118 ore de functionare. Moralul echipei este excelent dupa 78 zile sub pamant.', 'doc_existing_c19_11.txt', 888, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (872, 19, 'cave', 374, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (873, 990, 'cave_place', 374, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (375, 'Document PeÈ™tera C8 din Piatra Lupului #12', 'Jurnal de expeditie subterana - ziua 326. Am intrat in pestera la ora 258. Parcursul pana la tabara subterana a durat 81 ore. Am transportat 48 kilograme de echipament. La tabara temperatura era de 76 grade. Am montat 454 corturi in sala mare. Rezerva de apa potabila este de 304 litri. Am planificat 159 obiective de explorat. Primul obiectiv se afla la 276 metri de tabara. Comunicarea radio functioneaza pe o distanta de 17 metri. Am verificat starea corzilor pe 326 puturi. Am acumulat 50 ore de topografie. Fotodocumentarea a produs 259 imagini RAW. Urmatoarea tura de explorare incepe in 76 ore. Echipa este formata acum din 374 persoane active. Atmosfera din galeria inferioara contine 415 procente CO2. Am stabilit o limita de siguranta la 408 metri distanta. Stocul de baterii este suficient pentru 93 ore de functionare. Moralul echipei este excelent dupa 262 zile sub pamant.', 'doc_existing_c19_12.txt', 886, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (874, 19, 'cave', 375, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (376, 'Document PeÈ™tera C8 din Piatra Lupului #13', 'Plan de explorare - obiectiv 336. Am identificat 476 galerii laterale neexplorate. Lungimea estimata: 17 metri pe fiecare. Sunt necesare 141 zile de explorare. Echipa recomandata: 450 persoane. Echipament vertical necesar pentru 409 puturi. Am pregatit 119 kilograme de echipament. Rezerva de carbid: 187 kilograme. Punctul de plecare este statia topografica 426. Comunicarea radio va fi testata la 288 puncte. Am obtinut 55 autorizatii necesare. Data planificata: peste 214 saptamani. Bugetul estimat: 320 lei.', 'doc_existing_c19_13.txt', 511, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (875, 19, 'cave', 376, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (876, 1002, 'cave_place', 376, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (377, 'Document PeÈ™tera C8 din Piatra Lupului #14', 'Observatii topografice - tura nr. 239. Am efectuat 356 vizari cu busola si clinometrul. Lungimea poligonalei este de 20 metri. Diferenta de nivel totala: 448 metri. Am folosit statia nr. 453 ca baza. Eroarea de inchidere a poligonalei a fost sub 377 procente. Galeria prezinta un azimut predominant de 195 grade. Panta medie a galeriei este de 269 grade. Latimea variaza intre 93 si aproximativ dublu. Inaltimea maxima a sectiunii este de 182 metri. Am setat 6 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 457. Estimare galerie nemasurata: 417 metri. Am notat 342 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:472. Informam administratia ariei protejate despre descoperirea de la sectorul 122.', 'doc_existing_c19_14.txt', 749, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (877, 19, 'cave', 377, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (878, 76, 'cave_area', 377, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (879, 989, 'cave_place', 377, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (378, 'Document PeÈ™tera C8 din Piatra Lupului #15', 'Raport conservare patrimoniu - obiectiv 400. Am evaluat starea a 125 inscriptii istorice. Dintre acestea, 330 necesita interventie urgenta. Am curatat 286 metri patrati de graffiti modern. Am instalat 169 panouri informative la intrare. Bariera de protectie acopera 357 metri liniari. Am documentat 113 urme de vandalism. Raportul a fost transmis autoritatilor locale in 490 exemplare. Am propus clasificarea a 74 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 253 persoane simultan. Am instruit 206 ghizi locali. Costul estimat al lucrarilor: 404 lei. Termenul de finalizare: 368 luni.', 'doc_existing_c19_15.txt', 605, NULL, 'text_document', 1775820083);
