INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (386, 'Document PeÈ™tera C9 din Piatra Lupului #1', 'Plan de explorare - obiectiv 54. Am identificat 277 galerii laterale neexplorate. Lungimea estimata: 313 metri pe fiecare. Sunt necesare 348 zile de explorare. Echipa recomandata: 234 persoane. Echipament vertical necesar pentru 93 puturi. Am pregatit 246 kilograme de echipament. Rezerva de carbid: 286 kilograme. Punctul de plecare este statia topografica 243. Comunicarea radio va fi testata la 344 puncte. Am obtinut 97 autorizatii necesare. Data planificata: peste 85 saptamani. Bugetul estimat: 129 lei.', 'doc_existing_c20_1.txt', 509, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (895, 20, 'cave', 386, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (896, 1037, 'cave_place', 386, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (387, 'Document PeÈ™tera C9 din Piatra Lupului #2', 'Raport climatologic subteran - statia 27. Senzorul a inregistrat 249 cicluri complete de temperatura. Temperatura medie anuala: 65 grade Celsius. Amplitudinea termica maxima: 386 grade. Umiditatea relativa medie: 268 procente. Concentratia de CO2: 301 ppm. Curentul de aer maxim masurat: 66 metri pe secunda. Directia predominanta a curentului: sector 274. Datalogerul a functionat 121 zile fara intrerupere. Am descarcat 53 megabytes de date brute. Presiunea barometrica la intrare: 314 mbar. Evaporarea masurata: 477 milimetri pe luna. Am comparat datele cu 170 statii meteorologice de suprafata. Raportul complet include 52 grafice si tabele. Monitorizarea continua de 218 luni confirma stabilitatea climatica.', 'doc_existing_c20_2.txt', 713, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (897, 20, 'cave', 387, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (898, 79, 'cave_area', 387, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (388, 'Document PeÈ™tera C9 din Piatra Lupului #3', 'Fisa tehnica echipare put - verticala nr. 135. Adancimea: 131 metri. Am instalat 323 spituri din otel inoxidabil. Distanta intre spituri: 51 metri. Lungimea corzii principale: 3 metri. Coarda de siguranta: 154 metri. Am montat 487 protectoare de franghie. Fractionarea se face la 421 metri de buza putului. Deviatia este la 280 metri sub fractionare. Am testat echiparea cu 415 coborari. Ultimul control al spiturilor: acum 498 luni.', 'doc_existing_c20_3.txt', 433, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (899, 20, 'cave', 388, 1775820083);
