INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (901, 1024, 'cave_place', 388, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (389, 'Document PeÈ™tera C9 din Piatra Lupului #4', 'Plan de explorare - obiectiv 54. Am identificat 378 galerii laterale neexplorate. Lungimea estimata: 388 metri pe fiecare. Sunt necesare 386 zile de explorare. Echipa recomandata: 353 persoane. Echipament vertical necesar pentru 490 puturi. Am pregatit 76 kilograme de echipament. Rezerva de carbid: 494 kilograme. Punctul de plecare este statia topografica 426. Comunicarea radio va fi testata la 421 puncte. Am obtinut 439 autorizatii necesare. Data planificata: peste 366 saptamani. Bugetul estimat: 242 lei.', 'doc_existing_c20_4.txt', 511, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (902, 20, 'cave', 389, 1775820083);
