INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (390, 'Document PeÈ™tera C9 din Piatra Lupului #5', 'Nota de mentenanta balize - traseul 448. Am verificat 327 balize reflectorizante. Dintre acestea, 248 au fost inlocuite. Am adaugat 397 balize noi in zonele nemarcate. Distanta medie intre balize: 107 metri. Am folosit 2 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 301 metri cu lampa frontala. Am eliminat 273 marcaje vechi si confuze. Traseul total balizat: 442 metri. Urmatoarea verificare: peste 299 luni. Materialul consumat: 449 benzi reflectorizante.', 'doc_existing_c20_5.txt', 483, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (904, 20, 'cave', 390, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (391, 'Document PeÈ™tera C9 din Piatra Lupului #6', 'Observatii topografice - tura nr. 120. Am efectuat 91 vizari cu busola si clinometrul. Lungimea poligonalei este de 186 metri. Diferenta de nivel totala: 66 metri. Am folosit statia nr. 499 ca baza. Eroarea de inchidere a poligonalei a fost sub 289 procente. Galeria prezinta un azimut predominant de 322 grade. Panta medie a galeriei este de 10 grade. Latimea variaza intre 178 si aproximativ dublu. Inaltimea maxima a sectiunii este de 455 metri. Am setat 163 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 449. Estimare galerie nemasurata: 305 metri. Am notat 346 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:191. Informam administratia ariei protejate despre descoperirea de la sectorul 412.', 'doc_existing_c20_6.txt', 750, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (905, 20, 'cave', 391, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (906, 84, 'cave_area', 391, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (907, 1068, 'cave_place', 391, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (392, 'Document PeÈ™tera C9 din Piatra Lupului #7', 'Inventar echipament - depozit subteran 361. Total corzi disponibile: 127 metri. Dintre acestea, 247 metri necesita inlocuire. Am verificat 13 carabiniere si 34 plachete. Corzi statice diametru 10mm: 153 bucati. Am adaugat 393 saci de transport noi. Lampi de rezerva: 139 bucati cu baterii pline. Stocul de carbid: 123 kilograme. Truse de prim ajutor: 473 complete, verificate. Echipamentul este depozitat la 64 metri de intrare. Urmatoarea verificare programata peste 200 saptamani. Am retras din uz 243 echipamente expirate. Bugetul anual de echipament: 213 lei.', 'doc_existing_c20_7.txt', 563, NULL, 'text_document', 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (908, 20, 'cave', 392, 1775820083);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (909, 83, 'cave_area', 392, 1775820083);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (393, 'Document PeÈ™tera C9 din Piatra Lupului #8', 'Raport climatologic subteran - statia 2. Senzorul a inregistrat 65 cicluri complete de temperatura. Temperatura medie anuala: 101 grade Celsius. Amplitudinea termica maxima: 346 grade. Umiditatea relativa medie: 435 procente. Concentratia de CO2: 464 ppm. Curentul de aer maxim masurat: 360 metri pe secunda. Directia predominanta a curentului: sector 240. Datalogerul a functionat 392 zile fara intrerupere. Am descarcat 464 megabytes de date brute. Presiunea barometrica la intrare: 125 mbar. Evaporarea masurata: 308 milimetri pe luna. Am comparat datele cu 341 statii meteorologice de suprafata. Raportul complet include 386 grafice si tabele. Monitorizarea continua de 305 luni confirma stabilitatea climatica.', 'doc_existing_c20_8.txt', 715, NULL, 'text_document', 1775820083);
