INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (403, 'Document PeÈ™tera C9 din Piatra Lupului (Gaura cu VÃ¢jagÄƒu) #1', 'Registru vizitatori - luna 369. Total vizitatori inregistrati: 353. Dintre acestia, 382 au participat la ture ghidate. Am organizat 19 ture pentru grupuri scolare. Media participantilor per tura: 74 persoane. Am distribuit 22 pliante informative. Am colectat 265 chestionare de feedback. Nota medie acordata: 192 din 10. Am inregistrat 164 incidente minore. Veniturile din taxe: 94 lei. Am angajat 390 ghizi suplimentari. Programul de vizitare a fost extins cu 216 ore pe saptamana.', 'doc_existing_c21_1.txt', 482, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (933, 21, 'cave', 403, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (934, 85, 'cave_area', 403, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (935, 1146, 'cave_place', 403, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (404, 'Document PeÈ™tera C9 din Piatra Lupului (Gaura cu VÃ¢jagÄƒu) #2', 'Raport formare speologica - curs nr. 445. Am instruit 239 cursanti. Durata cursului: 138 zile. Am efectuat 104 sesiuni practice in pestera. Fiecare cursant a parcurs 72 metri de galerie. Am acoperit 330 module teoretice. Examenul final a fost promovat de 193 participanti. Am distribuit 41 seturi de echipament pentru practica. Feedback-ul mediu: 491 din 10. Urmatorul curs incepe in 34 saptamani.', 'doc_existing_c21_2.txt', 397, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (936, 21, 'cave', 404, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (937, 1108, 'cave_place', 404, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (405, 'Document PeÈ™tera C9 din Piatra Lupului (Gaura cu VÃ¢jagÄƒu) #3', 'Raport formare speologica - curs nr. 13. Am instruit 16 cursanti. Durata cursului: 247 zile. Am efectuat 268 sesiuni practice in pestera. Fiecare cursant a parcurs 178 metri de galerie. Am acoperit 255 module teoretice. Examenul final a fost promovat de 57 participanti. Am distribuit 257 seturi de echipament pentru practica. Feedback-ul mediu: 302 din 10. Urmatorul curs incepe in 167 saptamani.', 'doc_existing_c21_3.txt', 397, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (938, 21, 'cave', 405, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (406, 'Document PeÈ™tera C9 din Piatra Lupului (Gaura cu VÃ¢jagÄƒu) #4', 'Plan de explorare - obiectiv 448. Am identificat 220 galerii laterale neexplorate. Lungimea estimata: 225 metri pe fiecare. Sunt necesare 104 zile de explorare. Echipa recomandata: 100 persoane. Echipament vertical necesar pentru 91 puturi. Am pregatit 287 kilograme de echipament. Rezerva de carbid: 213 kilograme. Punctul de plecare este statia topografica 132. Comunicarea radio va fi testata la 111 puncte. Am obtinut 179 autorizatii necesare. Data planificata: peste 488 saptamani. Bugetul estimat: 228 lei.', 'doc_existing_c21_4.txt', 512, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (939, 21, 'cave', 406, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (940, 1143, 'cave_place', 406, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (407, 'Document PeÈ™tera C9 din Piatra Lupului (Gaura cu VÃ¢jagÄƒu) #5', 'Raport conservare patrimoniu - obiectiv 120. Am evaluat starea a 107 inscriptii istorice. Dintre acestea, 375 necesita interventie urgenta. Am curatat 55 metri patrati de graffiti modern. Am instalat 445 panouri informative la intrare. Bariera de protectie acopera 12 metri liniari. Am documentat 129 urme de vandalism. Raportul a fost transmis autoritatilor locale in 80 exemplare. Am propus clasificarea a 288 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 105 persoane simultan. Am instruit 418 ghizi locali. Costul estimat al lucrarilor: 78 lei. Termenul de finalizare: 6 luni.', 'doc_existing_c21_5.txt', 600, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (941, 21, 'cave', 407, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (942, 88, 'cave_area', 407, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (408, 'Document PeÈ™tera C9 din Piatra Lupului (Gaura cu VÃ¢jagÄƒu) #6', 'Raport climatologic subteran - statia 91. Senzorul a inregistrat 386 cicluri complete de temperatura. Temperatura medie anuala: 395 grade Celsius. Amplitudinea termica maxima: 281 grade. Umiditatea relativa medie: 292 procente. Concentratia de CO2: 122 ppm. Curentul de aer maxim masurat: 87 metri pe secunda. Directia predominanta a curentului: sector 231. Datalogerul a functionat 232 zile fara intrerupere. Am descarcat 142 megabytes de date brute. Presiunea barometrica la intrare: 271 mbar. Evaporarea masurata: 97 milimetri pe luna. Am comparat datele cu 60 statii meteorologice de suprafata. Raportul complet include 93 grafice si tabele. Monitorizarea continua de 317 luni confirma stabilitatea climatica.', 'doc_existing_c21_6.txt', 713, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (943, 21, 'cave', 408, 1775820084);
