INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (945, 1129, 'cave_place', 408, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (409, 'Document PeÈ™tera C9 din Piatra Lupului (Gaura cu VÃ¢jagÄƒu) #7', 'Registru vizitatori - luna 370. Total vizitatori inregistrati: 400. Dintre acestia, 22 au participat la ture ghidate. Am organizat 95 ture pentru grupuri scolare. Media participantilor per tura: 365 persoane. Am distribuit 34 pliante informative. Am colectat 73 chestionare de feedback. Nota medie acordata: 487 din 10. Am inregistrat 300 incidente minore. Veniturile din taxe: 5 lei. Am angajat 166 ghizi suplimentari. Programul de vizitare a fost extins cu 50 ore pe saptamana.', 'doc_existing_c21_7.txt', 479, NULL, 'text_document', 1775820084);
