INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (415, 'Document PeÈ™tera D1 din Piatra Lupului #1', 'Registru vizitatori - luna 490. Total vizitatori inregistrati: 453. Dintre acestia, 90 au participat la ture ghidate. Am organizat 5 ture pentru grupuri scolare. Media participantilor per tura: 416 persoane. Am distribuit 367 pliante informative. Am colectat 362 chestionare de feedback. Nota medie acordata: 162 din 10. Am inregistrat 352 incidente minore. Veniturile din taxe: 390 lei. Am angajat 298 ghizi suplimentari. Programul de vizitare a fost extins cu 113 ore pe saptamana.', 'doc_existing_c22_1.txt', 483, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (961, 22, 'cave', 415, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (962, 91, 'cave_area', 415, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (963, 1169, 'cave_place', 415, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (416, 'Document PeÈ™tera D1 din Piatra Lupului #2', 'Nota de mentenanta balize - traseul 298. Am verificat 491 balize reflectorizante. Dintre acestea, 178 au fost inlocuite. Am adaugat 378 balize noi in zonele nemarcate. Distanta medie intre balize: 81 metri. Am folosit 297 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 221 metri cu lampa frontala. Am eliminat 327 marcaje vechi si confuze. Traseul total balizat: 188 metri. Urmatoarea verificare: peste 214 luni. Materialul consumat: 205 benzi reflectorizante.', 'doc_existing_c22_2.txt', 484, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (964, 22, 'cave', 416, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (965, 1225, 'cave_place', 416, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (417, 'Document PeÈ™tera D1 din Piatra Lupului #3', 'Observatii topografice - tura nr. 42. Am efectuat 164 vizari cu busola si clinometrul. Lungimea poligonalei este de 373 metri. Diferenta de nivel totala: 369 metri. Am folosit statia nr. 309 ca baza. Eroarea de inchidere a poligonalei a fost sub 222 procente. Galeria prezinta un azimut predominant de 188 grade. Panta medie a galeriei este de 129 grade. Latimea variaza intre 65 si aproximativ dublu. Inaltimea maxima a sectiunii este de 471 metri. Am setat 118 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 154. Estimare galerie nemasurata: 48 metri. Am notat 123 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:499. Informam administratia ariei protejate despre descoperirea de la sectorul 6.', 'doc_existing_c22_3.txt', 748, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (966, 22, 'cave', 417, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (967, 1179, 'cave_place', 417, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (418, 'Document PeÈ™tera D1 din Piatra Lupului #4', 'Plan de explorare - obiectiv 415. Am identificat 264 galerii laterale neexplorate. Lungimea estimata: 434 metri pe fiecare. Sunt necesare 487 zile de explorare. Echipa recomandata: 351 persoane. Echipament vertical necesar pentru 459 puturi. Am pregatit 124 kilograme de echipament. Rezerva de carbid: 494 kilograme. Punctul de plecare este statia topografica 482. Comunicarea radio va fi testata la 353 puncte. Am obtinut 276 autorizatii necesare. Data planificata: peste 104 saptamani. Bugetul estimat: 45 lei.', 'doc_existing_c22_4.txt', 512, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (968, 22, 'cave', 418, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (969, 91, 'cave_area', 418, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (970, 1223, 'cave_place', 418, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (419, 'Document PeÈ™tera D1 din Piatra Lupului #5', 'Raport conservare patrimoniu - obiectiv 170. Am evaluat starea a 310 inscriptii istorice. Dintre acestea, 414 necesita interventie urgenta. Am curatat 306 metri patrati de graffiti modern. Am instalat 1 panouri informative la intrare. Bariera de protectie acopera 402 metri liniari. Am documentat 437 urme de vandalism. Raportul a fost transmis autoritatilor locale in 93 exemplare. Am propus clasificarea a 434 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 96 persoane simultan. Am instruit 179 ghizi locali. Costul estimat al lucrarilor: 129 lei. Termenul de finalizare: 132 luni.', 'doc_existing_c22_5.txt', 602, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (971, 22, 'cave', 419, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (972, 91, 'cave_area', 419, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (973, 1161, 'cave_place', 419, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (420, 'Document PeÈ™tera D1 din Piatra Lupului #6', 'Inventar echipament - depozit subteran 360. Total corzi disponibile: 400 metri. Dintre acestea, 141 metri necesita inlocuire. Am verificat 452 carabiniere si 422 plachete. Corzi statice diametru 10mm: 378 bucati. Am adaugat 59 saci de transport noi. Lampi de rezerva: 15 bucati cu baterii pline. Stocul de carbid: 332 kilograme. Truse de prim ajutor: 199 complete, verificate. Echipamentul este depozitat la 270 metri de intrare. Urmatoarea verificare programata peste 121 saptamani. Am retras din uz 181 echipamente expirate. Bugetul anual de echipament: 108 lei.', 'doc_existing_c22_6.txt', 564, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (974, 22, 'cave', 420, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (975, 91, 'cave_area', 420, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (421, 'Document PeÈ™tera D1 din Piatra Lupului #7', 'Raport formare speologica - curs nr. 349. Am instruit 143 cursanti. Durata cursului: 68 zile. Am efectuat 180 sesiuni practice in pestera. Fiecare cursant a parcurs 159 metri de galerie. Am acoperit 31 module teoretice. Examenul final a fost promovat de 85 participanti. Am distribuit 182 seturi de echipament pentru practica. Feedback-ul mediu: 264 din 10. Urmatorul curs incepe in 310 saptamani.', 'doc_existing_c22_7.txt', 397, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (976, 22, 'cave', 421, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (977, 1186, 'cave_place', 421, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (422, 'Document PeÈ™tera D1 din Piatra Lupului #8', 'Jurnal de expeditie subterana - ziua 15. Am intrat in pestera la ora 78. Parcursul pana la tabara subterana a durat 360 ore. Am transportat 247 kilograme de echipament. La tabara temperatura era de 260 grade. Am montat 259 corturi in sala mare. Rezerva de apa potabila este de 277 litri. Am planificat 270 obiective de explorat. Primul obiectiv se afla la 331 metri de tabara. Comunicarea radio functioneaza pe o distanta de 415 metri. Am verificat starea corzilor pe 57 puturi. Am acumulat 176 ore de topografie. Fotodocumentarea a produs 338 imagini RAW. Urmatoarea tura de explorare incepe in 272 ore. Echipa este formata acum din 45 persoane active. Atmosfera din galeria inferioara contine 349 procente CO2. Am stabilit o limita de siguranta la 373 metri distanta. Stocul de baterii este suficient pentru 102 ore de functionare. Moralul echipei este excelent dupa 483 zile sub pamant.', 'doc_existing_c22_8.txt', 889, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (978, 22, 'cave', 422, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (979, 91, 'cave_area', 422, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (980, 1202, 'cave_place', 422, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (423, 'Document PeÈ™tera D1 din Piatra Lupului #9', 'Nota de mentenanta balize - traseul 162. Am verificat 455 balize reflectorizante. Dintre acestea, 42 au fost inlocuite. Am adaugat 494 balize noi in zonele nemarcate. Distanta medie intre balize: 295 metri. Am folosit 64 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 29 metri cu lampa frontala. Am eliminat 498 marcaje vechi si confuze. Traseul total balizat: 321 metri. Urmatoarea verificare: peste 312 luni. Materialul consumat: 229 benzi reflectorizante.', 'doc_existing_c22_9.txt', 482, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (981, 22, 'cave', 423, 1775820084);
