INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (429, 'Document PeÈ™tera D2 din Piatra Lupului #1', 'Plan de explorare - obiectiv 368. Am identificat 117 galerii laterale neexplorate. Lungimea estimata: 338 metri pe fiecare. Sunt necesare 111 zile de explorare. Echipa recomandata: 329 persoane. Echipament vertical necesar pentru 152 puturi. Am pregatit 238 kilograme de echipament. Rezerva de carbid: 21 kilograme. Punctul de plecare este statia topografica 177. Comunicarea radio va fi testata la 94 puncte. Am obtinut 219 autorizatii necesare. Data planificata: peste 155 saptamani. Bugetul estimat: 437 lei.', 'doc_existing_c23_1.txt', 511, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (995, 23, 'cave', 429, 1775820084);
