INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (430, 'Document PeÈ™tera D2 din Piatra Lupului #2', 'Observatii topografice - tura nr. 262. Am efectuat 118 vizari cu busola si clinometrul. Lungimea poligonalei este de 322 metri. Diferenta de nivel totala: 183 metri. Am folosit statia nr. 107 ca baza. Eroarea de inchidere a poligonalei a fost sub 227 procente. Galeria prezinta un azimut predominant de 481 grade. Panta medie a galeriei este de 363 grade. Latimea variaza intre 386 si aproximativ dublu. Inaltimea maxima a sectiunii este de 87 metri. Am setat 278 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 18. Estimare galerie nemasurata: 265 metri. Am notat 373 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:461. Informam administratia ariei protejate despre descoperirea de la sectorul 494.', 'doc_existing_c23_2.txt', 751, NULL, 'text_document', 1775820084);
