INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (431, 'Document PeÈ™tera D2 din Piatra Lupului #3', 'Observatii topografice - tura nr. 172. Am efectuat 101 vizari cu busola si clinometrul. Lungimea poligonalei este de 408 metri. Diferenta de nivel totala: 408 metri. Am folosit statia nr. 463 ca baza. Eroarea de inchidere a poligonalei a fost sub 172 procente. Galeria prezinta un azimut predominant de 344 grade. Panta medie a galeriei este de 60 grade. Latimea variaza intre 290 si aproximativ dublu. Inaltimea maxima a sectiunii este de 486 metri. Am setat 204 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 163. Estimare galerie nemasurata: 297 metri. Am notat 85 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:54. Informam administratia ariei protejate despre descoperirea de la sectorul 416.', 'doc_existing_c23_3.txt', 750, NULL, 'text_document', 1775820084);
