INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (432, 'Document PeÈ™tera D2 din Piatra Lupului #4', 'Jurnal de expeditie subterana - ziua 426. Am intrat in pestera la ora 101. Parcursul pana la tabara subterana a durat 91 ore. Am transportat 410 kilograme de echipament. La tabara temperatura era de 120 grade. Am montat 370 corturi in sala mare. Rezerva de apa potabila este de 181 litri. Am planificat 496 obiective de explorat. Primul obiectiv se afla la 473 metri de tabara. Comunicarea radio functioneaza pe o distanta de 80 metri. Am verificat starea corzilor pe 143 puturi. Am acumulat 321 ore de topografie. Fotodocumentarea a produs 95 imagini RAW. Urmatoarea tura de explorare incepe in 353 ore. Echipa este formata acum din 196 persoane active. Atmosfera din galeria inferioara contine 204 procente CO2. Am stabilit o limita de siguranta la 456 metri distanta. Stocul de baterii este suficient pentru 354 ore de functionare. Moralul echipei este excelent dupa 408 zile sub pamant.', 'doc_existing_c23_4.txt', 890, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1002, 23, 'cave', 432, 1775820084);
