INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (433, 'Document PeÈ™tera D2 din Piatra Lupului #5', 'Observatii topografice - tura nr. 231. Am efectuat 91 vizari cu busola si clinometrul. Lungimea poligonalei este de 133 metri. Diferenta de nivel totala: 259 metri. Am folosit statia nr. 314 ca baza. Eroarea de inchidere a poligonalei a fost sub 286 procente. Galeria prezinta un azimut predominant de 372 grade. Panta medie a galeriei este de 118 grade. Latimea variaza intre 40 si aproximativ dublu. Inaltimea maxima a sectiunii este de 130 metri. Am setat 472 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 309. Estimare galerie nemasurata: 472 metri. Am notat 362 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:255. Informam administratia ariei protejate despre descoperirea de la sectorul 116.', 'doc_existing_c23_5.txt', 751, NULL, 'text_document', 1775820084);
