INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (434, 'Document PeÈ™tera D2 din Piatra Lupului #6', 'Raport climatologic subteran - statia 129. Senzorul a inregistrat 260 cicluri complete de temperatura. Temperatura medie anuala: 285 grade Celsius. Amplitudinea termica maxima: 170 grade. Umiditatea relativa medie: 426 procente. Concentratia de CO2: 53 ppm. Curentul de aer maxim masurat: 140 metri pe secunda. Directia predominanta a curentului: sector 353. Datalogerul a functionat 431 zile fara intrerupere. Am descarcat 316 megabytes de date brute. Presiunea barometrica la intrare: 450 mbar. Evaporarea masurata: 449 milimetri pe luna. Am comparat datele cu 301 statii meteorologice de suprafata. Raportul complet include 229 grafice si tabele. Monitorizarea continua de 1 luni confirma stabilitatea climatica.', 'doc_existing_c23_6.txt', 715, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1006, 23, 'cave', 434, 1775820084);
