INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (435, 'Document PeÈ™tera D2 din Piatra Lupului #7', 'Inventar echipament - depozit subteran 398. Total corzi disponibile: 35 metri. Dintre acestea, 125 metri necesita inlocuire. Am verificat 302 carabiniere si 499 plachete. Corzi statice diametru 10mm: 300 bucati. Am adaugat 104 saci de transport noi. Lampi de rezerva: 295 bucati cu baterii pline. Stocul de carbid: 411 kilograme. Truse de prim ajutor: 197 complete, verificate. Echipamentul este depozitat la 186 metri de intrare. Urmatoarea verificare programata peste 84 saptamani. Am retras din uz 153 echipamente expirate. Bugetul anual de echipament: 366 lei.', 'doc_existing_c23_7.txt', 564, NULL, 'text_document', 1775820084);
