INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (439, 'Document PeÈ™tera D2 din Piatra Lupului #11', 'Registru vizitatori - luna 500. Total vizitatori inregistrati: 81. Dintre acestia, 260 au participat la ture ghidate. Am organizat 350 ture pentru grupuri scolare. Media participantilor per tura: 388 persoane. Am distribuit 238 pliante informative. Am colectat 304 chestionare de feedback. Nota medie acordata: 246 din 10. Am inregistrat 414 incidente minore. Veniturile din taxe: 411 lei. Am angajat 397 ghizi suplimentari. Programul de vizitare a fost extins cu 1 ore pe saptamana.', 'doc_existing_c23_11.txt', 483, NULL, 'text_document', 1775820084);
