INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (440, 'Document PeÈ™tera D2 din Piatra Lupului #12', 'Fisa tehnica echipare put - verticala nr. 455. Adancimea: 52 metri. Am instalat 11 spituri din otel inoxidabil. Distanta intre spituri: 116 metri. Lungimea corzii principale: 496 metri. Coarda de siguranta: 301 metri. Am montat 475 protectoare de franghie. Fractionarea se face la 190 metri de buza putului. Deviatia este la 299 metri sub fractionare. Am testat echiparea cu 41 coborari. Ultimul control al spiturilor: acum 482 luni.', 'doc_existing_c23_12.txt', 433, NULL, 'text_document', 1775820084);
