INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (447, 'Document PeÈ™tera D3 din Piatra Lupului #1', 'Raport formare speologica - curs nr. 482. Am instruit 254 cursanti. Durata cursului: 306 zile. Am efectuat 56 sesiuni practice in pestera. Fiecare cursant a parcurs 44 metri de galerie. Am acoperit 195 module teoretice. Examenul final a fost promovat de 208 participanti. Am distribuit 429 seturi de echipament pentru practica. Feedback-ul mediu: 211 din 10. Urmatorul curs incepe in 111 saptamani.', 'doc_existing_c24_1.txt', 398, NULL, 'text_document', 1775820084);
