INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (456, 'Document PeÈ™tera M1 din Piatra Lupului #1', 'Raport conservare patrimoniu - obiectiv 234. Am evaluat starea a 178 inscriptii istorice. Dintre acestea, 242 necesita interventie urgenta. Am curatat 489 metri patrati de graffiti modern. Am instalat 497 panouri informative la intrare. Bariera de protectie acopera 452 metri liniari. Am documentat 55 urme de vandalism. Raportul a fost transmis autoritatilor locale in 210 exemplare. Am propus clasificarea a 396 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 253 persoane simultan. Am instruit 113 ghizi locali. Costul estimat al lucrarilor: 243 lei. Termenul de finalizare: 246 luni.', 'doc_existing_c25_1.txt', 605, NULL, 'text_document', 1775820084);
