INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (459, 'Document PeÈ™tera M2 din Piatra Lupului #1', 'Plan de explorare - obiectiv 146. Am identificat 249 galerii laterale neexplorate. Lungimea estimata: 111 metri pe fiecare. Sunt necesare 36 zile de explorare. Echipa recomandata: 460 persoane. Echipament vertical necesar pentru 94 puturi. Am pregatit 237 kilograme de echipament. Rezerva de carbid: 201 kilograme. Punctul de plecare este statia topografica 95. Comunicarea radio va fi testata la 56 puncte. Am obtinut 298 autorizatii necesare. Data planificata: peste 416 saptamani. Bugetul estimat: 453 lei.', 'doc_existing_c26_1.txt', 509, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1069, 26, 'cave', 459, 1775820084);
