INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (460, 'Document PeÈ™tera M2 din Piatra Lupului #2', 'Plan de explorare - obiectiv 354. Am identificat 116 galerii laterale neexplorate. Lungimea estimata: 73 metri pe fiecare. Sunt necesare 6 zile de explorare. Echipa recomandata: 264 persoane. Echipament vertical necesar pentru 383 puturi. Am pregatit 178 kilograme de echipament. Rezerva de carbid: 135 kilograme. Punctul de plecare este statia topografica 425. Comunicarea radio va fi testata la 219 puncte. Am obtinut 364 autorizatii necesare. Data planificata: peste 428 saptamani. Bugetul estimat: 439 lei.', 'doc_existing_c26_2.txt', 510, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1072, 26, 'cave', 460, 1775820084);
