INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (461, 'Document PeÈ™tera M2 din Piatra Lupului #3', 'Raport formare speologica - curs nr. 154. Am instruit 199 cursanti. Durata cursului: 397 zile. Am efectuat 330 sesiuni practice in pestera. Fiecare cursant a parcurs 218 metri de galerie. Am acoperit 133 module teoretice. Examenul final a fost promovat de 342 participanti. Am distribuit 430 seturi de echipament pentru practica. Feedback-ul mediu: 491 din 10. Urmatorul curs incepe in 282 saptamani.', 'doc_existing_c26_3.txt', 400, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1075, 26, 'cave', 461, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1076, 112, 'cave_area', 461, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (462, 'Document PeÈ™tera M2 din Piatra Lupului #4', 'Inventar echipament - depozit subteran 460. Total corzi disponibile: 30 metri. Dintre acestea, 442 metri necesita inlocuire. Am verificat 338 carabiniere si 92 plachete. Corzi statice diametru 10mm: 129 bucati. Am adaugat 428 saci de transport noi. Lampi de rezerva: 324 bucati cu baterii pline. Stocul de carbid: 215 kilograme. Truse de prim ajutor: 65 complete, verificate. Echipamentul este depozitat la 470 metri de intrare. Urmatoarea verificare programata peste 477 saptamani. Am retras din uz 72 echipamente expirate. Bugetul anual de echipament: 91 lei.', 'doc_existing_c26_4.txt', 561, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1077, 26, 'cave', 462, 1775820084);
