INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (463, 'Document PeÈ™tera M2 din Piatra Lupului #5', 'Inventar echipament - depozit subteran 139. Total corzi disponibile: 473 metri. Dintre acestea, 112 metri necesita inlocuire. Am verificat 358 carabiniere si 231 plachete. Corzi statice diametru 10mm: 59 bucati. Am adaugat 105 saci de transport noi. Lampi de rezerva: 246 bucati cu baterii pline. Stocul de carbid: 428 kilograme. Truse de prim ajutor: 103 complete, verificate. Echipamentul este depozitat la 477 metri de intrare. Urmatoarea verificare programata peste 379 saptamani. Am retras din uz 96 echipamente expirate. Bugetul anual de echipament: 451 lei.', 'doc_existing_c26_5.txt', 564, NULL, 'text_document', 1775820084);
