INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (480, 'Document PeÈ™tera M3 din Piatra Lupului #1', 'Raport conservare patrimoniu - obiectiv 465. Am evaluat starea a 103 inscriptii istorice. Dintre acestea, 254 necesita interventie urgenta. Am curatat 177 metri patrati de graffiti modern. Am instalat 354 panouri informative la intrare. Bariera de protectie acopera 3 metri liniari. Am documentat 247 urme de vandalism. Raportul a fost transmis autoritatilor locale in 209 exemplare. Am propus clasificarea a 91 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 289 persoane simultan. Am instruit 275 ghizi locali. Costul estimat al lucrarilor: 328 lei. Termenul de finalizare: 179 luni.', 'doc_existing_c27_1.txt', 603, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1120, 27, 'cave', 480, 1775820084);
