INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (481, 'Document PeÈ™tera M3 din Piatra Lupului #2', 'Plan de explorare - obiectiv 334. Am identificat 66 galerii laterale neexplorate. Lungimea estimata: 374 metri pe fiecare. Sunt necesare 172 zile de explorare. Echipa recomandata: 150 persoane. Echipament vertical necesar pentru 58 puturi. Am pregatit 360 kilograme de echipament. Rezerva de carbid: 237 kilograme. Punctul de plecare este statia topografica 371. Comunicarea radio va fi testata la 316 puncte. Am obtinut 129 autorizatii necesare. Data planificata: peste 79 saptamani. Bugetul estimat: 470 lei.', 'doc_existing_c27_2.txt', 510, NULL, 'text_document', 1775820084);
