INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (482, 'Document PeÈ™tera M3 din Piatra Lupului #3', 'Inventar echipament - depozit subteran 209. Total corzi disponibile: 477 metri. Dintre acestea, 411 metri necesita inlocuire. Am verificat 322 carabiniere si 395 plachete. Corzi statice diametru 10mm: 372 bucati. Am adaugat 386 saci de transport noi. Lampi de rezerva: 103 bucati cu baterii pline. Stocul de carbid: 151 kilograme. Truse de prim ajutor: 244 complete, verificate. Echipamentul este depozitat la 414 metri de intrare. Urmatoarea verificare programata peste 430 saptamani. Am retras din uz 118 echipamente expirate. Bugetul anual de echipament: 141 lei.', 'doc_existing_c27_3.txt', 566, NULL, 'text_document', 1775820084);
