INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (483, 'Document PeÈ™tera M3 din Piatra Lupului #4', 'Registru vizitatori - luna 180. Total vizitatori inregistrati: 349. Dintre acestia, 111 au participat la ture ghidate. Am organizat 362 ture pentru grupuri scolare. Media participantilor per tura: 88 persoane. Am distribuit 286 pliante informative. Am colectat 67 chestionare de feedback. Nota medie acordata: 304 din 10. Am inregistrat 208 incidente minore. Veniturile din taxe: 40 lei. Am angajat 116 ghizi suplimentari. Programul de vizitare a fost extins cu 428 ore pe saptamana.', 'doc_existing_c27_4.txt', 483, NULL, 'text_document', 1775820084);
