INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (484, 'Document PeÈ™tera M3 din Piatra Lupului #5', 'Fisa tehnica echipare put - verticala nr. 411. Adancimea: 266 metri. Am instalat 436 spituri din otel inoxidabil. Distanta intre spituri: 204 metri. Lungimea corzii principale: 341 metri. Coarda de siguranta: 304 metri. Am montat 255 protectoare de franghie. Fractionarea se face la 197 metri de buza putului. Deviatia este la 169 metri sub fractionare. Am testat echiparea cu 124 coborari. Ultimul control al spiturilor: acum 42 luni.', 'doc_existing_c27_5.txt', 435, NULL, 'text_document', 1775820084);
