INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (487, 'Document PeÈ™tera M3 din Piatra Lupului #8', 'Nota de mentenanta balize - traseul 23. Am verificat 326 balize reflectorizante. Dintre acestea, 176 au fost inlocuite. Am adaugat 205 balize noi in zonele nemarcate. Distanta medie intre balize: 479 metri. Am folosit 137 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 177 metri cu lampa frontala. Am eliminat 303 marcaje vechi si confuze. Traseul total balizat: 69 metri. Urmatoarea verificare: peste 151 luni. Materialul consumat: 256 benzi reflectorizante.', 'doc_existing_c27_8.txt', 483, NULL, 'text_document', 1775820084);
