INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (489, 'Document PeÈ™tera M3 din Piatra Lupului #10', 'Jurnal de expeditie subterana - ziua 401. Am intrat in pestera la ora 413. Parcursul pana la tabara subterana a durat 325 ore. Am transportat 125 kilograme de echipament. La tabara temperatura era de 500 grade. Am montat 166 corturi in sala mare. Rezerva de apa potabila este de 448 litri. Am planificat 39 obiective de explorat. Primul obiectiv se afla la 76 metri de tabara. Comunicarea radio functioneaza pe o distanta de 286 metri. Am verificat starea corzilor pe 474 puturi. Am acumulat 380 ore de topografie. Fotodocumentarea a produs 340 imagini RAW. Urmatoarea tura de explorare incepe in 36 ore. Echipa este formata acum din 404 persoane active. Atmosfera din galeria inferioara contine 210 procente CO2. Am stabilit o limita de siguranta la 208 metri distanta. Stocul de baterii este suficient pentru 122 ore de functionare. Moralul echipei este excelent dupa 257 zile sub pamant.', 'doc_existing_c27_10.txt', 890, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1144, 27, 'cave', 489, 1775820084);
