INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (493, 'Document PeÈ™tera M4 din Piatra Lupului #1', 'Raport formare speologica - curs nr. 291. Am instruit 52 cursanti. Durata cursului: 377 zile. Am efectuat 104 sesiuni practice in pestera. Fiecare cursant a parcurs 404 metri de galerie. Am acoperit 344 module teoretice. Examenul final a fost promovat de 56 participanti. Am distribuit 430 seturi de echipament pentru practica. Feedback-ul mediu: 6 din 10. Urmatorul curs incepe in 40 saptamani.', 'doc_existing_c28_1.txt', 395, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1154, 28, 'cave', 493, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (494, 'Document PeÈ™tera M4 din Piatra Lupului #2', 'Nota de mentenanta balize - traseul 103. Am verificat 239 balize reflectorizante. Dintre acestea, 277 au fost inlocuite. Am adaugat 142 balize noi in zonele nemarcate. Distanta medie intre balize: 250 metri. Am folosit 216 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 364 metri cu lampa frontala. Am eliminat 465 marcaje vechi si confuze. Traseul total balizat: 108 metri. Urmatoarea verificare: peste 31 luni. Materialul consumat: 432 benzi reflectorizante.', 'doc_existing_c28_2.txt', 484, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1155, 28, 'cave', 494, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1156, 1584, 'cave_place', 494, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (495, 'Document PeÈ™tera M4 din Piatra Lupului #3', 'Raport conservare patrimoniu - obiectiv 465. Am evaluat starea a 229 inscriptii istorice. Dintre acestea, 34 necesita interventie urgenta. Am curatat 235 metri patrati de graffiti modern. Am instalat 403 panouri informative la intrare. Bariera de protectie acopera 193 metri liniari. Am documentat 13 urme de vandalism. Raportul a fost transmis autoritatilor locale in 364 exemplare. Am propus clasificarea a 217 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 222 persoane simultan. Am instruit 257 ghizi locali. Costul estimat al lucrarilor: 445 lei. Termenul de finalizare: 463 luni.', 'doc_existing_c28_3.txt', 604, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1157, 28, 'cave', 495, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (496, 'Document PeÈ™tera M4 din Piatra Lupului #4', 'Observatii topografice - tura nr. 373. Am efectuat 303 vizari cu busola si clinometrul. Lungimea poligonalei este de 108 metri. Diferenta de nivel totala: 460 metri. Am folosit statia nr. 404 ca baza. Eroarea de inchidere a poligonalei a fost sub 226 procente. Galeria prezinta un azimut predominant de 349 grade. Panta medie a galeriei este de 317 grade. Latimea variaza intre 277 si aproximativ dublu. Inaltimea maxima a sectiunii este de 422 metri. Am setat 172 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 86. Estimare galerie nemasurata: 241 metri. Am notat 177 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:186. Informam administratia ariei protejate despre descoperirea de la sectorul 490.', 'doc_existing_c28_4.txt', 752, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1158, 28, 'cave', 496, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1159, 120, 'cave_area', 496, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1160, 1621, 'cave_place', 496, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (497, 'Document PeÈ™tera M4 din Piatra Lupului #5', 'Registru vizitatori - luna 179. Total vizitatori inregistrati: 388. Dintre acestia, 310 au participat la ture ghidate. Am organizat 92 ture pentru grupuri scolare. Media participantilor per tura: 10 persoane. Am distribuit 495 pliante informative. Am colectat 85 chestionare de feedback. Nota medie acordata: 75 din 10. Am inregistrat 292 incidente minore. Veniturile din taxe: 149 lei. Am angajat 200 ghizi suplimentari. Programul de vizitare a fost extins cu 168 ore pe saptamana.', 'doc_existing_c28_5.txt', 482, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1161, 28, 'cave', 497, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1162, 120, 'cave_area', 497, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (498, 'Document PeÈ™tera M4 din Piatra Lupului #6', 'Registru vizitatori - luna 396. Total vizitatori inregistrati: 229. Dintre acestia, 416 au participat la ture ghidate. Am organizat 138 ture pentru grupuri scolare. Media participantilor per tura: 388 persoane. Am distribuit 448 pliante informative. Am colectat 465 chestionare de feedback. Nota medie acordata: 59 din 10. Am inregistrat 391 incidente minore. Veniturile din taxe: 26 lei. Am angajat 377 ghizi suplimentari. Programul de vizitare a fost extins cu 205 ore pe saptamana.', 'doc_existing_c28_6.txt', 484, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1163, 28, 'cave', 498, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (499, 'Document PeÈ™tera M4 din Piatra Lupului #7', 'Raport climatologic subteran - statia 420. Senzorul a inregistrat 148 cicluri complete de temperatura. Temperatura medie anuala: 99 grade Celsius. Amplitudinea termica maxima: 265 grade. Umiditatea relativa medie: 470 procente. Concentratia de CO2: 246 ppm. Curentul de aer maxim masurat: 217 metri pe secunda. Directia predominanta a curentului: sector 88. Datalogerul a functionat 203 zile fara intrerupere. Am descarcat 246 megabytes de date brute. Presiunea barometrica la intrare: 42 mbar. Evaporarea masurata: 342 milimetri pe luna. Am comparat datele cu 328 statii meteorologice de suprafata. Raportul complet include 350 grafice si tabele. Monitorizarea continua de 430 luni confirma stabilitatea climatica.', 'doc_existing_c28_7.txt', 715, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1164, 28, 'cave', 499, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1165, 119, 'cave_area', 499, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1166, 1616, 'cave_place', 499, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (500, 'Document PeÈ™tera M4 din Piatra Lupului #8', 'Fisa tehnica echipare put - verticala nr. 231. Adancimea: 197 metri. Am instalat 124 spituri din otel inoxidabil. Distanta intre spituri: 54 metri. Lungimea corzii principale: 217 metri. Coarda de siguranta: 274 metri. Am montat 382 protectoare de franghie. Fractionarea se face la 245 metri de buza putului. Deviatia este la 104 metri sub fractionare. Am testat echiparea cu 450 coborari. Ultimul control al spiturilor: acum 302 luni.', 'doc_existing_c28_8.txt', 435, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1167, 28, 'cave', 500, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1168, 118, 'cave_area', 500, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1169, 1571, 'cave_place', 500, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (501, 'Document PeÈ™tera M4 din Piatra Lupului #9', 'Plan de explorare - obiectiv 191. Am identificat 272 galerii laterale neexplorate. Lungimea estimata: 146 metri pe fiecare. Sunt necesare 307 zile de explorare. Echipa recomandata: 183 persoane. Echipament vertical necesar pentru 375 puturi. Am pregatit 111 kilograme de echipament. Rezerva de carbid: 226 kilograme. Punctul de plecare este statia topografica 105. Comunicarea radio va fi testata la 402 puncte. Am obtinut 330 autorizatii necesare. Data planificata: peste 180 saptamani. Bugetul estimat: 282 lei.', 'doc_existing_c28_9.txt', 513, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1170, 28, 'cave', 501, 1775820084);
