INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (502, 'Document PeÈ™tera M4 din Piatra Lupului #10', 'Nota de mentenanta balize - traseul 166. Am verificat 413 balize reflectorizante. Dintre acestea, 489 au fost inlocuite. Am adaugat 279 balize noi in zonele nemarcate. Distanta medie intre balize: 57 metri. Am folosit 350 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 360 metri cu lampa frontala. Am eliminat 404 marcaje vechi si confuze. Traseul total balizat: 166 metri. Urmatoarea verificare: peste 375 luni. Materialul consumat: 94 benzi reflectorizante.', 'doc_existing_c28_10.txt', 483, NULL, 'text_document', 1775820084);
