INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (518, 'Document Avenul M5 din Piatra Lupului #1', 'Inventar echipament - depozit subteran 87. Total corzi disponibile: 435 metri. Dintre acestea, 196 metri necesita inlocuire. Am verificat 253 carabiniere si 335 plachete. Corzi statice diametru 10mm: 459 bucati. Am adaugat 131 saci de transport noi. Lampi de rezerva: 241 bucati cu baterii pline. Stocul de carbid: 74 kilograme. Truse de prim ajutor: 388 complete, verificate. Echipamentul este depozitat la 16 metri de intrare. Urmatoarea verificare programata peste 184 saptamani. Am retras din uz 291 echipamente expirate. Bugetul anual de echipament: 373 lei.', 'doc_existing_c29_1.txt', 563, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1210, 29, 'cave', 518, 1775820084);
