INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (519, 'Document Avenul M5 din Piatra Lupului #2', 'Raport formare speologica - curs nr. 56. Am instruit 283 cursanti. Durata cursului: 226 zile. Am efectuat 121 sesiuni practice in pestera. Fiecare cursant a parcurs 164 metri de galerie. Am acoperit 370 module teoretice. Examenul final a fost promovat de 485 participanti. Am distribuit 49 seturi de echipament pentru practica. Feedback-ul mediu: 418 din 10. Urmatorul curs incepe in 265 saptamani.', 'doc_existing_c29_2.txt', 398, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1213, 29, 'cave', 519, 1775820084);
