INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (520, 'Document Avenul M5 din Piatra Lupului #3', 'Nota de mentenanta balize - traseul 181. Am verificat 409 balize reflectorizante. Dintre acestea, 82 au fost inlocuite. Am adaugat 494 balize noi in zonele nemarcate. Distanta medie intre balize: 311 metri. Am folosit 323 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 496 metri cu lampa frontala. Am eliminat 38 marcaje vechi si confuze. Traseul total balizat: 377 metri. Urmatoarea verificare: peste 151 luni. Materialul consumat: 416 benzi reflectorizante.', 'doc_existing_c29_3.txt', 483, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1215, 29, 'cave', 520, 1775820084);
