INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (521, 'Document Avenul M5 din Piatra Lupului #4', 'Jurnal de expeditie subterana - ziua 441. Am intrat in pestera la ora 322. Parcursul pana la tabara subterana a durat 289 ore. Am transportat 421 kilograme de echipament. La tabara temperatura era de 292 grade. Am montat 451 corturi in sala mare. Rezerva de apa potabila este de 38 litri. Am planificat 15 obiective de explorat. Primul obiectiv se afla la 245 metri de tabara. Comunicarea radio functioneaza pe o distanta de 361 metri. Am verificat starea corzilor pe 488 puturi. Am acumulat 38 ore de topografie. Fotodocumentarea a produs 60 imagini RAW. Urmatoarea tura de explorare incepe in 194 ore. Echipa este formata acum din 299 persoane active. Atmosfera din galeria inferioara contine 120 procente CO2. Am stabilit o limita de siguranta la 106 metri distanta. Stocul de baterii este suficient pentru 17 ore de functionare. Moralul echipei este excelent dupa 165 zile sub pamant.', 'doc_existing_c29_4.txt', 888, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1218, 29, 'cave', 521, 1775820084);
