INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (524, 'Document Avenul M5 din Piatra Lupului #7', 'Fisa tehnica echipare put - verticala nr. 24. Adancimea: 383 metri. Am instalat 50 spituri din otel inoxidabil. Distanta intre spituri: 317 metri. Lungimea corzii principale: 432 metri. Coarda de siguranta: 202 metri. Am montat 8 protectoare de franghie. Fractionarea se face la 422 metri de buza putului. Deviatia este la 374 metri sub fractionare. Am testat echiparea cu 206 coborari. Ultimul control al spiturilor: acum 47 luni.', 'doc_existing_c29_7.txt', 431, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1226, 29, 'cave', 524, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (525, 'Document Avenul M5 din Piatra Lupului #8', 'Fisa tehnica echipare put - verticala nr. 398. Adancimea: 268 metri. Am instalat 480 spituri din otel inoxidabil. Distanta intre spituri: 93 metri. Lungimea corzii principale: 167 metri. Coarda de siguranta: 389 metri. Am montat 421 protectoare de franghie. Fractionarea se face la 486 metri de buza putului. Deviatia este la 136 metri sub fractionare. Am testat echiparea cu 404 coborari. Ultimul control al spiturilor: acum 72 luni.', 'doc_existing_c29_8.txt', 434, NULL, 'text_document', 1775820084);
