INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (526, 'Document Avenul M5 din Piatra Lupului #9', 'Raport conservare patrimoniu - obiectiv 77. Am evaluat starea a 238 inscriptii istorice. Dintre acestea, 257 necesita interventie urgenta. Am curatat 230 metri patrati de graffiti modern. Am instalat 153 panouri informative la intrare. Bariera de protectie acopera 155 metri liniari. Am documentat 406 urme de vandalism. Raportul a fost transmis autoritatilor locale in 137 exemplare. Am propus clasificarea a 333 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 172 persoane simultan. Am instruit 254 ghizi locali. Costul estimat al lucrarilor: 219 lei. Termenul de finalizare: 227 luni.', 'doc_existing_c29_9.txt', 605, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1229, 29, 'cave', 526, 1775820084);
