INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1231, 1649, 'cave_place', 526, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (527, 'Document Avenul M5 din Piatra Lupului #10', 'Raport climatologic subteran - statia 33. Senzorul a inregistrat 219 cicluri complete de temperatura. Temperatura medie anuala: 70 grade Celsius. Amplitudinea termica maxima: 289 grade. Umiditatea relativa medie: 114 procente. Concentratia de CO2: 352 ppm. Curentul de aer maxim masurat: 421 metri pe secunda. Directia predominanta a curentului: sector 456. Datalogerul a functionat 398 zile fara intrerupere. Am descarcat 145 megabytes de date brute. Presiunea barometrica la intrare: 409 mbar. Evaporarea masurata: 416 milimetri pe luna. Am comparat datele cu 19 statii meteorologice de suprafata. Raportul complet include 39 grafice si tabele. Monitorizarea continua de 301 luni confirma stabilitatea climatica.', 'doc_existing_c29_10.txt', 714, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1232, 29, 'cave', 527, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1233, 1671, 'cave_place', 527, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (528, 'Document Avenul M5 din Piatra Lupului #11', 'Observatii topografice - tura nr. 352. Am efectuat 423 vizari cu busola si clinometrul. Lungimea poligonalei este de 141 metri. Diferenta de nivel totala: 492 metri. Am folosit statia nr. 200 ca baza. Eroarea de inchidere a poligonalei a fost sub 287 procente. Galeria prezinta un azimut predominant de 448 grade. Panta medie a galeriei este de 148 grade. Latimea variaza intre 471 si aproximativ dublu. Inaltimea maxima a sectiunii este de 328 metri. Am setat 413 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 185. Estimare galerie nemasurata: 285 metri. Am notat 136 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:49. Informam administratia ariei protejate despre descoperirea de la sectorul 374.', 'doc_existing_c29_11.txt', 752, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1234, 29, 'cave', 528, 1775820084);
