INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (542, 'Document Avenul X2 din Piatra Lupului #1', 'Raport formare speologica - curs nr. 285. Am instruit 274 cursanti. Durata cursului: 360 zile. Am efectuat 319 sesiuni practice in pestera. Fiecare cursant a parcurs 357 metri de galerie. Am acoperit 495 module teoretice. Examenul final a fost promovat de 478 participanti. Am distribuit 49 seturi de echipament pentru practica. Feedback-ul mediu: 93 din 10. Urmatorul curs incepe in 425 saptamani.', 'doc_existing_c30_1.txt', 398, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1263, 30, 'cave', 542, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1264, 131, 'cave_area', 542, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (543, 'Document Avenul X2 din Piatra Lupului #2', 'Fisa tehnica echipare put - verticala nr. 262. Adancimea: 181 metri. Am instalat 137 spituri din otel inoxidabil. Distanta intre spituri: 332 metri. Lungimea corzii principale: 378 metri. Coarda de siguranta: 275 metri. Am montat 190 protectoare de franghie. Fractionarea se face la 68 metri de buza putului. Deviatia este la 413 metri sub fractionare. Am testat echiparea cu 461 coborari. Ultimul control al spiturilor: acum 136 luni.', 'doc_existing_c30_2.txt', 435, NULL, 'text_document', 1775820084);
