INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (544, 'Document Avenul X2 din Piatra Lupului #3', 'Observatii topografice - tura nr. 390. Am efectuat 301 vizari cu busola si clinometrul. Lungimea poligonalei este de 159 metri. Diferenta de nivel totala: 377 metri. Am folosit statia nr. 218 ca baza. Eroarea de inchidere a poligonalei a fost sub 316 procente. Galeria prezinta un azimut predominant de 456 grade. Panta medie a galeriei este de 242 grade. Latimea variaza intre 208 si aproximativ dublu. Inaltimea maxima a sectiunii este de 371 metri. Am setat 341 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 254. Estimare galerie nemasurata: 166 metri. Am notat 184 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:111. Informam administratia ariei protejate despre descoperirea de la sectorul 7.', 'doc_existing_c30_3.txt', 751, NULL, 'text_document', 1775820084);
