INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (557, 'Document PeÈ™tera X3 din Piatra Lupului #1', 'Registru vizitatori - luna 58. Total vizitatori inregistrati: 76. Dintre acestia, 475 au participat la ture ghidate. Am organizat 65 ture pentru grupuri scolare. Media participantilor per tura: 445 persoane. Am distribuit 174 pliante informative. Am colectat 94 chestionare de feedback. Nota medie acordata: 93 din 10. Am inregistrat 275 incidente minore. Veniturile din taxe: 126 lei. Am angajat 368 ghizi suplimentari. Programul de vizitare a fost extins cu 270 ore pe saptamana.', 'doc_existing_c31_1.txt', 481, NULL, 'text_document', 1775820084);
