INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (558, 'Document PeÈ™tera X3 din Piatra Lupului #2', 'Observatii topografice - tura nr. 95. Am efectuat 159 vizari cu busola si clinometrul. Lungimea poligonalei este de 336 metri. Diferenta de nivel totala: 465 metri. Am folosit statia nr. 156 ca baza. Eroarea de inchidere a poligonalei a fost sub 20 procente. Galeria prezinta un azimut predominant de 175 grade. Panta medie a galeriei este de 116 grade. Latimea variaza intre 297 si aproximativ dublu. Inaltimea maxima a sectiunii este de 99 metri. Am setat 421 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 248. Estimare galerie nemasurata: 140 metri. Am notat 189 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:225. Informam administratia ariei protejate despre descoperirea de la sectorul 273.', 'doc_existing_c31_2.txt', 750, NULL, 'text_document', 1775820084);
