INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (560, 'Document PeÈ™tera X3 din Piatra Lupului #4', 'Inventar echipament - depozit subteran 419. Total corzi disponibile: 178 metri. Dintre acestea, 179 metri necesita inlocuire. Am verificat 470 carabiniere si 303 plachete. Corzi statice diametru 10mm: 197 bucati. Am adaugat 235 saci de transport noi. Lampi de rezerva: 209 bucati cu baterii pline. Stocul de carbid: 324 kilograme. Truse de prim ajutor: 308 complete, verificate. Echipamentul este depozitat la 164 metri de intrare. Urmatoarea verificare programata peste 239 saptamani. Am retras din uz 474 echipamente expirate. Bugetul anual de echipament: 356 lei.', 'doc_existing_c31_4.txt', 566, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1306, 31, 'cave', 560, 1775820084);
