INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (561, 'Document PeÈ™tera X3 din Piatra Lupului #5', 'Jurnal de expeditie subterana - ziua 133. Am intrat in pestera la ora 322. Parcursul pana la tabara subterana a durat 316 ore. Am transportat 386 kilograme de echipament. La tabara temperatura era de 283 grade. Am montat 155 corturi in sala mare. Rezerva de apa potabila este de 118 litri. Am planificat 265 obiective de explorat. Primul obiectiv se afla la 497 metri de tabara. Comunicarea radio functioneaza pe o distanta de 86 metri. Am verificat starea corzilor pe 329 puturi. Am acumulat 312 ore de topografie. Fotodocumentarea a produs 56 imagini RAW. Urmatoarea tura de explorare incepe in 12 ore. Echipa este formata acum din 491 persoane active. Atmosfera din galeria inferioara contine 428 procente CO2. Am stabilit o limita de siguranta la 11 metri distanta. Stocul de baterii este suficient pentru 320 ore de functionare. Moralul echipei este excelent dupa 212 zile sub pamant.', 'doc_existing_c31_5.txt', 889, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1309, 31, 'cave', 561, 1775820084);
