INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (563, 'Document PeÈ™tera X3 din Piatra Lupului #7', 'Raport conservare patrimoniu - obiectiv 284. Am evaluat starea a 251 inscriptii istorice. Dintre acestea, 240 necesita interventie urgenta. Am curatat 371 metri patrati de graffiti modern. Am instalat 361 panouri informative la intrare. Bariera de protectie acopera 316 metri liniari. Am documentat 103 urme de vandalism. Raportul a fost transmis autoritatilor locale in 272 exemplare. Am propus clasificarea a 51 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 458 persoane simultan. Am instruit 368 ghizi locali. Costul estimat al lucrarilor: 349 lei. Termenul de finalizare: 12 luni.', 'doc_existing_c31_7.txt', 604, NULL, 'text_document', 1775820084);
