INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (564, 'Document PeÈ™tera X3 din Piatra Lupului #8', 'Raport formare speologica - curs nr. 97. Am instruit 280 cursanti. Durata cursului: 92 zile. Am efectuat 243 sesiuni practice in pestera. Fiecare cursant a parcurs 259 metri de galerie. Am acoperit 68 module teoretice. Examenul final a fost promovat de 469 participanti. Am distribuit 321 seturi de echipament pentru practica. Feedback-ul mediu: 201 din 10. Urmatorul curs incepe in 215 saptamani.', 'doc_existing_c31_8.txt', 397, NULL, 'text_document', 1775820084);
