INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (568, 'Document PeÈ™tera X3 din Piatra Lupului #12', 'Nota de mentenanta balize - traseul 215. Am verificat 349 balize reflectorizante. Dintre acestea, 321 au fost inlocuite. Am adaugat 174 balize noi in zonele nemarcate. Distanta medie intre balize: 209 metri. Am folosit 352 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 255 metri cu lampa frontala. Am eliminat 187 marcaje vechi si confuze. Traseul total balizat: 37 metri. Urmatoarea verificare: peste 405 luni. Materialul consumat: 213 benzi reflectorizante.', 'doc_existing_c31_12.txt', 484, NULL, 'text_document', 1775820084);
