INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (575, 'Document PeÈ™tera X4 din Piatra Lupului #1', 'Inventar echipament - depozit subteran 134. Total corzi disponibile: 28 metri. Dintre acestea, 13 metri necesita inlocuire. Am verificat 230 carabiniere si 456 plachete. Corzi statice diametru 10mm: 153 bucati. Am adaugat 12 saci de transport noi. Lampi de rezerva: 468 bucati cu baterii pline. Stocul de carbid: 476 kilograme. Truse de prim ajutor: 69 complete, verificate. Echipamentul este depozitat la 44 metri de intrare. Urmatoarea verificare programata peste 476 saptamani. Am retras din uz 323 echipamente expirate. Bugetul anual de echipament: 171 lei.', 'doc_existing_c32_1.txt', 561, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1341, 32, 'cave', 575, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1342, 138, 'cave_area', 575, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (576, 'Document PeÈ™tera X4 din Piatra Lupului #2', 'Registru vizitatori - luna 283. Total vizitatori inregistrati: 418. Dintre acestia, 15 au participat la ture ghidate. Am organizat 301 ture pentru grupuri scolare. Media participantilor per tura: 143 persoane. Am distribuit 354 pliante informative. Am colectat 407 chestionare de feedback. Nota medie acordata: 107 din 10. Am inregistrat 104 incidente minore. Veniturile din taxe: 113 lei. Am angajat 106 ghizi suplimentari. Programul de vizitare a fost extins cu 117 ore pe saptamana.', 'doc_existing_c32_2.txt', 485, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1343, 32, 'cave', 576, 1775820084);
