INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (577, 'Document PeÈ™tera X4 din Piatra Lupului #3', 'Registru vizitatori - luna 266. Total vizitatori inregistrati: 4. Dintre acestia, 467 au participat la ture ghidate. Am organizat 300 ture pentru grupuri scolare. Media participantilor per tura: 113 persoane. Am distribuit 439 pliante informative. Am colectat 324 chestionare de feedback. Nota medie acordata: 248 din 10. Am inregistrat 8 incidente minore. Veniturile din taxe: 259 lei. Am angajat 359 ghizi suplimentari. Programul de vizitare a fost extins cu 219 ore pe saptamana.', 'doc_existing_c32_3.txt', 482, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1346, 32, 'cave', 577, 1775820084);
