INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (578, 'Document PeÈ™tera X4 din Piatra Lupului #4', 'Fisa tehnica echipare put - verticala nr. 127. Adancimea: 178 metri. Am instalat 183 spituri din otel inoxidabil. Distanta intre spituri: 428 metri. Lungimea corzii principale: 195 metri. Coarda de siguranta: 95 metri. Am montat 81 protectoare de franghie. Fractionarea se face la 257 metri de buza putului. Deviatia este la 76 metri sub fractionare. Am testat echiparea cu 184 coborari. Ultimul control al spiturilor: acum 300 luni.', 'doc_existing_c32_4.txt', 433, NULL, 'text_document', 1775820084);
