INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (589, 'Document PeÈ™tera X6 din Piatra Lupului #1', 'Raport formare speologica - curs nr. 167. Am instruit 175 cursanti. Durata cursului: 268 zile. Am efectuat 55 sesiuni practice in pestera. Fiecare cursant a parcurs 145 metri de galerie. Am acoperit 433 module teoretice. Examenul final a fost promovat de 73 participanti. Am distribuit 336 seturi de echipament pentru practica. Feedback-ul mediu: 212 din 10. Urmatorul curs incepe in 176 saptamani.', 'doc_existing_c33_1.txt', 398, NULL, 'text_document', 1775820084);
