INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (590, 'Document PeÈ™tera X6 din Piatra Lupului #2', 'Fisa tehnica echipare put - verticala nr. 500. Adancimea: 217 metri. Am instalat 51 spituri din otel inoxidabil. Distanta intre spituri: 425 metri. Lungimea corzii principale: 276 metri. Coarda de siguranta: 263 metri. Am montat 147 protectoare de franghie. Fractionarea se face la 358 metri de buza putului. Deviatia este la 143 metri sub fractionare. Am testat echiparea cu 120 coborari. Ultimul control al spiturilor: acum 404 luni.', 'doc_existing_c33_2.txt', 435, NULL, 'text_document', 1775820084);
