INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (593, 'Document PeÈ™tera X6 din Piatra Lupului #5', 'Jurnal de expeditie subterana - ziua 38. Am intrat in pestera la ora 111. Parcursul pana la tabara subterana a durat 142 ore. Am transportat 283 kilograme de echipament. La tabara temperatura era de 250 grade. Am montat 349 corturi in sala mare. Rezerva de apa potabila este de 73 litri. Am planificat 450 obiective de explorat. Primul obiectiv se afla la 7 metri de tabara. Comunicarea radio functioneaza pe o distanta de 100 metri. Am verificat starea corzilor pe 119 puturi. Am acumulat 106 ore de topografie. Fotodocumentarea a produs 415 imagini RAW. Urmatoarea tura de explorare incepe in 363 ore. Echipa este formata acum din 96 persoane active. Atmosfera din galeria inferioara contine 4 procente CO2. Am stabilit o limita de siguranta la 43 metri distanta. Stocul de baterii este suficient pentru 218 ore de functionare. Moralul echipei este excelent dupa 31 zile sub pamant.', 'doc_existing_c33_5.txt', 884, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1385, 33, 'cave', 593, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1386, 1968, 'cave_place', 593, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (594, 'Document PeÈ™tera X6 din Piatra Lupului #6', 'Nota de mentenanta balize - traseul 181. Am verificat 359 balize reflectorizante. Dintre acestea, 475 au fost inlocuite. Am adaugat 82 balize noi in zonele nemarcate. Distanta medie intre balize: 469 metri. Am folosit 380 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 38 metri cu lampa frontala. Am eliminat 124 marcaje vechi si confuze. Traseul total balizat: 316 metri. Urmatoarea verificare: peste 305 luni. Materialul consumat: 40 benzi reflectorizante.', 'doc_existing_c33_6.txt', 482, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1387, 33, 'cave', 594, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (595, 'Document PeÈ™tera X6 din Piatra Lupului #7', 'Observatii topografice - tura nr. 52. Am efectuat 297 vizari cu busola si clinometrul. Lungimea poligonalei este de 280 metri. Diferenta de nivel totala: 257 metri. Am folosit statia nr. 151 ca baza. Eroarea de inchidere a poligonalei a fost sub 110 procente. Galeria prezinta un azimut predominant de 458 grade. Panta medie a galeriei este de 398 grade. Latimea variaza intre 133 si aproximativ dublu. Inaltimea maxima a sectiunii este de 476 metri. Am setat 69 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 174. Estimare galerie nemasurata: 193 metri. Am notat 16 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:412. Informam administratia ariei protejate despre descoperirea de la sectorul 17.', 'doc_existing_c33_7.txt', 749, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1388, 33, 'cave', 595, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1389, 1998, 'cave_place', 595, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (596, 'Document PeÈ™tera X6 din Piatra Lupului #8', 'Nota de mentenanta balize - traseul 442. Am verificat 198 balize reflectorizante. Dintre acestea, 357 au fost inlocuite. Am adaugat 457 balize noi in zonele nemarcate. Distanta medie intre balize: 227 metri. Am folosit 282 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 419 metri cu lampa frontala. Am eliminat 72 marcaje vechi si confuze. Traseul total balizat: 6 metri. Urmatoarea verificare: peste 385 luni. Materialul consumat: 83 benzi reflectorizante.', 'doc_existing_c33_8.txt', 481, NULL, 'text_document', 1775820084);
