INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (597, 'Document PeÈ™tera X6 din Piatra Lupului #9', 'Inventar echipament - depozit subteran 210. Total corzi disponibile: 358 metri. Dintre acestea, 336 metri necesita inlocuire. Am verificat 225 carabiniere si 103 plachete. Corzi statice diametru 10mm: 390 bucati. Am adaugat 46 saci de transport noi. Lampi de rezerva: 251 bucati cu baterii pline. Stocul de carbid: 414 kilograme. Truse de prim ajutor: 157 complete, verificate. Echipamentul este depozitat la 175 metri de intrare. Urmatoarea verificare programata peste 400 saptamani. Am retras din uz 173 echipamente expirate. Bugetul anual de echipament: 68 lei.', 'doc_existing_c33_9.txt', 564, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1392, 33, 'cave', 597, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1393, 1978, 'cave_place', 597, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (598, 'Document PeÈ™tera X6 din Piatra Lupului #10', 'Raport climatologic subteran - statia 173. Senzorul a inregistrat 40 cicluri complete de temperatura. Temperatura medie anuala: 369 grade Celsius. Amplitudinea termica maxima: 31 grade. Umiditatea relativa medie: 42 procente. Concentratia de CO2: 147 ppm. Curentul de aer maxim masurat: 262 metri pe secunda. Directia predominanta a curentului: sector 31. Datalogerul a functionat 191 zile fara intrerupere. Am descarcat 55 megabytes de date brute. Presiunea barometrica la intrare: 186 mbar. Evaporarea masurata: 474 milimetri pe luna. Am comparat datele cu 236 statii meteorologice de suprafata. Raportul complet include 189 grafice si tabele. Monitorizarea continua de 148 luni confirma stabilitatea climatica.', 'doc_existing_c33_10.txt', 713, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1394, 33, 'cave', 598, 1775820084);
