INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1396, 1960, 'cave_place', 598, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (599, 'Document PeÈ™tera X6 din Piatra Lupului #11', 'Plan de explorare - obiectiv 240. Am identificat 100 galerii laterale neexplorate. Lungimea estimata: 360 metri pe fiecare. Sunt necesare 314 zile de explorare. Echipa recomandata: 148 persoane. Echipament vertical necesar pentru 111 puturi. Am pregatit 19 kilograme de echipament. Rezerva de carbid: 309 kilograme. Punctul de plecare este statia topografica 101. Comunicarea radio va fi testata la 68 puncte. Am obtinut 252 autorizatii necesare. Data planificata: peste 213 saptamani. Bugetul estimat: 184 lei.', 'doc_existing_c33_11.txt', 511, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1397, 33, 'cave', 599, 1775820084);
