INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (605, 'Document PeÈ™tera X7 din Piatra Lupului #1', 'Nota de mentenanta balize - traseul 5. Am verificat 423 balize reflectorizante. Dintre acestea, 77 au fost inlocuite. Am adaugat 223 balize noi in zonele nemarcate. Distanta medie intre balize: 468 metri. Am folosit 196 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 37 metri cu lampa frontala. Am eliminat 295 marcaje vechi si confuze. Traseul total balizat: 481 metri. Urmatoarea verificare: peste 347 luni. Materialul consumat: 115 benzi reflectorizante.', 'doc_existing_c34_1.txt', 481, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1410, 34, 'cave', 605, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1411, 2031, 'cave_place', 605, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (606, 'Document PeÈ™tera X7 din Piatra Lupului #2', 'Observatii topografice - tura nr. 392. Am efectuat 273 vizari cu busola si clinometrul. Lungimea poligonalei este de 342 metri. Diferenta de nivel totala: 93 metri. Am folosit statia nr. 107 ca baza. Eroarea de inchidere a poligonalei a fost sub 12 procente. Galeria prezinta un azimut predominant de 62 grade. Panta medie a galeriei este de 184 grade. Latimea variaza intre 69 si aproximativ dublu. Inaltimea maxima a sectiunii este de 402 metri. Am setat 404 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 7. Estimare galerie nemasurata: 290 metri. Am notat 135 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:96. Informam administratia ariei protejate despre descoperirea de la sectorul 63.', 'doc_existing_c34_2.txt', 745, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1412, 34, 'cave', 606, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1413, 2001, 'cave_place', 606, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (607, 'Document PeÈ™tera X7 din Piatra Lupului #3', 'Observatii topografice - tura nr. 45. Am efectuat 339 vizari cu busola si clinometrul. Lungimea poligonalei este de 176 metri. Diferenta de nivel totala: 437 metri. Am folosit statia nr. 477 ca baza. Eroarea de inchidere a poligonalei a fost sub 288 procente. Galeria prezinta un azimut predominant de 6 grade. Panta medie a galeriei este de 401 grade. Latimea variaza intre 109 si aproximativ dublu. Inaltimea maxima a sectiunii este de 242 metri. Am setat 60 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 209. Estimare galerie nemasurata: 243 metri. Am notat 329 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:145. Informam administratia ariei protejate despre descoperirea de la sectorul 147.', 'doc_existing_c34_3.txt', 749, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1414, 34, 'cave', 607, 1775820084);
