INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (608, 'Document PeÈ™tera X7 din Piatra Lupului #4', 'Observatii topografice - tura nr. 105. Am efectuat 201 vizari cu busola si clinometrul. Lungimea poligonalei este de 56 metri. Diferenta de nivel totala: 281 metri. Am folosit statia nr. 207 ca baza. Eroarea de inchidere a poligonalei a fost sub 286 procente. Galeria prezinta un azimut predominant de 63 grade. Panta medie a galeriei este de 438 grade. Latimea variaza intre 13 si aproximativ dublu. Inaltimea maxima a sectiunii este de 382 metri. Am setat 231 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 160. Estimare galerie nemasurata: 477 metri. Am notat 269 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:308. Informam administratia ariei protejate despre descoperirea de la sectorul 396.', 'doc_existing_c34_4.txt', 750, NULL, 'text_document', 1775820084);
