INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (609, 'Document PeÈ™tera X7 din Piatra Lupului #5', 'Inventar echipament - depozit subteran 292. Total corzi disponibile: 484 metri. Dintre acestea, 195 metri necesita inlocuire. Am verificat 53 carabiniere si 323 plachete. Corzi statice diametru 10mm: 170 bucati. Am adaugat 117 saci de transport noi. Lampi de rezerva: 413 bucati cu baterii pline. Stocul de carbid: 257 kilograme. Truse de prim ajutor: 497 complete, verificate. Echipamentul este depozitat la 281 metri de intrare. Urmatoarea verificare programata peste 444 saptamani. Am retras din uz 418 echipamente expirate. Bugetul anual de echipament: 303 lei.', 'doc_existing_c34_5.txt', 565, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1420, 34, 'cave', 609, 1775820084);
