INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (610, 'Document PeÈ™tera X7 din Piatra Lupului #6', 'Inventar echipament - depozit subteran 392. Total corzi disponibile: 442 metri. Dintre acestea, 280 metri necesita inlocuire. Am verificat 303 carabiniere si 278 plachete. Corzi statice diametru 10mm: 464 bucati. Am adaugat 356 saci de transport noi. Lampi de rezerva: 196 bucati cu baterii pline. Stocul de carbid: 379 kilograme. Truse de prim ajutor: 142 complete, verificate. Echipamentul este depozitat la 319 metri de intrare. Urmatoarea verificare programata peste 378 saptamani. Am retras din uz 482 echipamente expirate. Bugetul anual de echipament: 288 lei.', 'doc_existing_c34_6.txt', 566, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1422, 34, 'cave', 610, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (611, 'Document PeÈ™tera X7 din Piatra Lupului #7', 'Plan de explorare - obiectiv 448. Am identificat 59 galerii laterale neexplorate. Lungimea estimata: 404 metri pe fiecare. Sunt necesare 278 zile de explorare. Echipa recomandata: 109 persoane. Echipament vertical necesar pentru 238 puturi. Am pregatit 218 kilograme de echipament. Rezerva de carbid: 209 kilograme. Punctul de plecare este statia topografica 137. Comunicarea radio va fi testata la 377 puncte. Am obtinut 93 autorizatii necesare. Data planificata: peste 415 saptamani. Bugetul estimat: 141 lei.', 'doc_existing_c34_7.txt', 511, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1423, 34, 'cave', 611, 1775820084);
