INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (612, 'Document PeÈ™tera X7 din Piatra Lupului #8', 'Raport formare speologica - curs nr. 244. Am instruit 108 cursanti. Durata cursului: 411 zile. Am efectuat 25 sesiuni practice in pestera. Fiecare cursant a parcurs 215 metri de galerie. Am acoperit 242 module teoretice. Examenul final a fost promovat de 223 participanti. Am distribuit 319 seturi de echipament pentru practica. Feedback-ul mediu: 463 din 10. Urmatorul curs incepe in 200 saptamani.', 'doc_existing_c34_8.txt', 399, NULL, 'text_document', 1775820084);
