INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (615, 'Document PeÈ™tera X7 din Piatra Lupului #11', 'Raport formare speologica - curs nr. 130. Am instruit 435 cursanti. Durata cursului: 183 zile. Am efectuat 430 sesiuni practice in pestera. Fiecare cursant a parcurs 286 metri de galerie. Am acoperit 44 module teoretice. Examenul final a fost promovat de 347 participanti. Am distribuit 249 seturi de echipament pentru practica. Feedback-ul mediu: 256 din 10. Urmatorul curs incepe in 49 saptamani.', 'doc_existing_c34_11.txt', 398, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1433, 34, 'cave', 615, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1434, 2056, 'cave_place', 615, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (616, 'Document PeÈ™tera X7 din Piatra Lupului #12', 'Jurnal de expeditie subterana - ziua 157. Am intrat in pestera la ora 138. Parcursul pana la tabara subterana a durat 309 ore. Am transportat 479 kilograme de echipament. La tabara temperatura era de 346 grade. Am montat 489 corturi in sala mare. Rezerva de apa potabila este de 139 litri. Am planificat 425 obiective de explorat. Primul obiectiv se afla la 150 metri de tabara. Comunicarea radio functioneaza pe o distanta de 50 metri. Am verificat starea corzilor pe 393 puturi. Am acumulat 348 ore de topografie. Fotodocumentarea a produs 163 imagini RAW. Urmatoarea tura de explorare incepe in 109 ore. Echipa este formata acum din 406 persoane active. Atmosfera din galeria inferioara contine 410 procente CO2. Am stabilit o limita de siguranta la 304 metri distanta. Stocul de baterii este suficient pentru 85 ore de functionare. Moralul echipei este excelent dupa 193 zile sub pamant.', 'doc_existing_c34_12.txt', 891, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1435, 34, 'cave', 616, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (617, 'Document PeÈ™tera X7 din Piatra Lupului #13', 'Observatii topografice - tura nr. 91. Am efectuat 107 vizari cu busola si clinometrul. Lungimea poligonalei este de 16 metri. Diferenta de nivel totala: 88 metri. Am folosit statia nr. 276 ca baza. Eroarea de inchidere a poligonalei a fost sub 180 procente. Galeria prezinta un azimut predominant de 90 grade. Panta medie a galeriei este de 296 grade. Latimea variaza intre 25 si aproximativ dublu. Inaltimea maxima a sectiunii este de 406 metri. Am setat 247 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 74. Estimare galerie nemasurata: 371 metri. Am notat 172 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:19. Informam administratia ariei protejate despre descoperirea de la sectorul 219.', 'doc_existing_c34_13.txt', 746, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1436, 34, 'cave', 617, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1437, 148, 'cave_area', 617, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1438, 2070, 'cave_place', 617, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (618, 'Document PeÈ™tera X7 din Piatra Lupului #14', 'Registru vizitatori - luna 165. Total vizitatori inregistrati: 189. Dintre acestia, 181 au participat la ture ghidate. Am organizat 337 ture pentru grupuri scolare. Media participantilor per tura: 105 persoane. Am distribuit 177 pliante informative. Am colectat 152 chestionare de feedback. Nota medie acordata: 233 din 10. Am inregistrat 327 incidente minore. Veniturile din taxe: 265 lei. Am angajat 444 ghizi suplimentari. Programul de vizitare a fost extins cu 451 ore pe saptamana.', 'doc_existing_c34_14.txt', 486, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1439, 34, 'cave', 618, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1440, 148, 'cave_area', 618, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1441, 2026, 'cave_place', 618, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (619, 'Document PeÈ™tera X7 din Piatra Lupului #15', 'Raport conservare patrimoniu - obiectiv 46. Am evaluat starea a 451 inscriptii istorice. Dintre acestea, 476 necesita interventie urgenta. Am curatat 176 metri patrati de graffiti modern. Am instalat 361 panouri informative la intrare. Bariera de protectie acopera 443 metri liniari. Am documentat 67 urme de vandalism. Raportul a fost transmis autoritatilor locale in 408 exemplare. Am propus clasificarea a 451 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 115 persoane simultan. Am instruit 245 ghizi locali. Costul estimat al lucrarilor: 212 lei. Termenul de finalizare: 95 luni.', 'doc_existing_c34_15.txt', 603, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1442, 34, 'cave', 619, 1775820084);
