INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (627, 'Document PeÈ™tera X8 din Piatra Lupului #1', 'Raport conservare patrimoniu - obiectiv 141. Am evaluat starea a 469 inscriptii istorice. Dintre acestea, 428 necesita interventie urgenta. Am curatat 85 metri patrati de graffiti modern. Am instalat 279 panouri informative la intrare. Bariera de protectie acopera 375 metri liniari. Am documentat 129 urme de vandalism. Raportul a fost transmis autoritatilor locale in 68 exemplare. Am propus clasificarea a 292 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 172 persoane simultan. Am instruit 20 ghizi locali. Costul estimat al lucrarilor: 261 lei. Termenul de finalizare: 318 luni.', 'doc_existing_c35_1.txt', 603, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1460, 35, 'cave', 627, 1775820084);
