INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1462, 2168, 'cave_place', 627, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (628, 'Document PeÈ™tera X8 din Piatra Lupului #2', 'Nota de mentenanta balize - traseul 416. Am verificat 270 balize reflectorizante. Dintre acestea, 70 au fost inlocuite. Am adaugat 284 balize noi in zonele nemarcate. Distanta medie intre balize: 292 metri. Am folosit 100 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 163 metri cu lampa frontala. Am eliminat 196 marcaje vechi si confuze. Traseul total balizat: 327 metri. Urmatoarea verificare: peste 106 luni. Materialul consumat: 318 benzi reflectorizante.', 'doc_existing_c35_2.txt', 484, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1463, 35, 'cave', 628, 1775820084);
