INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1465, 2090, 'cave_place', 628, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (629, 'Document PeÈ™tera X8 din Piatra Lupului #3', 'Observatii topografice - tura nr. 375. Am efectuat 486 vizari cu busola si clinometrul. Lungimea poligonalei este de 370 metri. Diferenta de nivel totala: 397 metri. Am folosit statia nr. 479 ca baza. Eroarea de inchidere a poligonalei a fost sub 287 procente. Galeria prezinta un azimut predominant de 497 grade. Panta medie a galeriei este de 59 grade. Latimea variaza intre 278 si aproximativ dublu. Inaltimea maxima a sectiunii este de 498 metri. Am setat 258 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 114. Estimare galerie nemasurata: 211 metri. Am notat 239 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:184. Informam administratia ariei protejate despre descoperirea de la sectorul 413.', 'doc_existing_c35_3.txt', 752, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1466, 35, 'cave', 629, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1467, 151, 'cave_area', 629, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1468, 2091, 'cave_place', 629, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (630, 'Document PeÈ™tera X8 din Piatra Lupului #4', 'Nota de mentenanta balize - traseul 254. Am verificat 471 balize reflectorizante. Dintre acestea, 232 au fost inlocuite. Am adaugat 299 balize noi in zonele nemarcate. Distanta medie intre balize: 80 metri. Am folosit 360 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 384 metri cu lampa frontala. Am eliminat 78 marcaje vechi si confuze. Traseul total balizat: 11 metri. Urmatoarea verificare: peste 319 luni. Materialul consumat: 157 benzi reflectorizante.', 'doc_existing_c35_4.txt', 482, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1469, 35, 'cave', 630, 1775820084);
