INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (631, 'Document PeÈ™tera X8 din Piatra Lupului #5', 'Raport climatologic subteran - statia 191. Senzorul a inregistrat 35 cicluri complete de temperatura. Temperatura medie anuala: 428 grade Celsius. Amplitudinea termica maxima: 1 grade. Umiditatea relativa medie: 407 procente. Concentratia de CO2: 42 ppm. Curentul de aer maxim masurat: 180 metri pe secunda. Directia predominanta a curentului: sector 370. Datalogerul a functionat 127 zile fara intrerupere. Am descarcat 338 megabytes de date brute. Presiunea barometrica la intrare: 226 mbar. Evaporarea masurata: 219 milimetri pe luna. Am comparat datele cu 280 statii meteorologice de suprafata. Raportul complet include 469 grafice si tabele. Monitorizarea continua de 411 luni confirma stabilitatea climatica.', 'doc_existing_c35_5.txt', 714, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1472, 35, 'cave', 631, 1775820084);
