INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (632, 'Document PeÈ™tera X8 din Piatra Lupului #6', 'Raport conservare patrimoniu - obiectiv 472. Am evaluat starea a 311 inscriptii istorice. Dintre acestea, 270 necesita interventie urgenta. Am curatat 133 metri patrati de graffiti modern. Am instalat 277 panouri informative la intrare. Bariera de protectie acopera 61 metri liniari. Am documentat 416 urme de vandalism. Raportul a fost transmis autoritatilor locale in 105 exemplare. Am propus clasificarea a 54 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 352 persoane simultan. Am instruit 222 ghizi locali. Costul estimat al lucrarilor: 355 lei. Termenul de finalizare: 454 luni.', 'doc_existing_c35_6.txt', 604, NULL, 'text_document', 1775820084);
