INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (646, 'Document PeÈ™tera X9 din Piatra Lupului #1', 'Plan de explorare - obiectiv 388. Am identificat 376 galerii laterale neexplorate. Lungimea estimata: 377 metri pe fiecare. Sunt necesare 116 zile de explorare. Echipa recomandata: 84 persoane. Echipament vertical necesar pentru 356 puturi. Am pregatit 284 kilograme de echipament. Rezerva de carbid: 404 kilograme. Punctul de plecare este statia topografica 83. Comunicarea radio va fi testata la 418 puncte. Am obtinut 486 autorizatii necesare. Data planificata: peste 221 saptamani. Bugetul estimat: 469 lei.', 'doc_existing_c36_1.txt', 511, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1505, 36, 'cave', 646, 1775820084);
