INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (647, 'Document PeÈ™tera X9 din Piatra Lupului #2', 'Observatii topografice - tura nr. 120. Am efectuat 349 vizari cu busola si clinometrul. Lungimea poligonalei este de 410 metri. Diferenta de nivel totala: 421 metri. Am folosit statia nr. 388 ca baza. Eroarea de inchidere a poligonalei a fost sub 268 procente. Galeria prezinta un azimut predominant de 327 grade. Panta medie a galeriei este de 221 grade. Latimea variaza intre 322 si aproximativ dublu. Inaltimea maxima a sectiunii este de 254 metri. Am setat 417 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 453. Estimare galerie nemasurata: 199 metri. Am notat 341 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:213. Informam administratia ariei protejate despre descoperirea de la sectorul 462.', 'doc_existing_c36_2.txt', 753, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1508, 36, 'cave', 647, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (648, 'Document PeÈ™tera X9 din Piatra Lupului #3', 'Fisa tehnica echipare put - verticala nr. 231. Adancimea: 74 metri. Am instalat 111 spituri din otel inoxidabil. Distanta intre spituri: 114 metri. Lungimea corzii principale: 452 metri. Coarda de siguranta: 199 metri. Am montat 492 protectoare de franghie. Fractionarea se face la 321 metri de buza putului. Deviatia este la 277 metri sub fractionare. Am testat echiparea cu 398 coborari. Ultimul control al spiturilor: acum 185 luni.', 'doc_existing_c36_3.txt', 435, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1509, 36, 'cave', 648, 1775820084);
