INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (649, 'Document PeÈ™tera X9 din Piatra Lupului #4', 'Inventar echipament - depozit subteran 400. Total corzi disponibile: 152 metri. Dintre acestea, 127 metri necesita inlocuire. Am verificat 258 carabiniere si 409 plachete. Corzi statice diametru 10mm: 255 bucati. Am adaugat 140 saci de transport noi. Lampi de rezerva: 283 bucati cu baterii pline. Stocul de carbid: 488 kilograme. Truse de prim ajutor: 400 complete, verificate. Echipamentul este depozitat la 395 metri de intrare. Urmatoarea verificare programata peste 437 saptamani. Am retras din uz 48 echipamente expirate. Bugetul anual de echipament: 242 lei.', 'doc_existing_c36_4.txt', 565, NULL, 'text_document', 1775820084);
