INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (652, 'Document PeÈ™tera X9 din Piatra Lupului #7', 'Nota de mentenanta balize - traseul 100. Am verificat 194 balize reflectorizante. Dintre acestea, 288 au fost inlocuite. Am adaugat 273 balize noi in zonele nemarcate. Distanta medie intre balize: 218 metri. Am folosit 339 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 389 metri cu lampa frontala. Am eliminat 350 marcaje vechi si confuze. Traseul total balizat: 199 metri. Urmatoarea verificare: peste 455 luni. Materialul consumat: 236 benzi reflectorizante.', 'doc_existing_c36_7.txt', 485, NULL, 'text_document', 1775820084);
