INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (655, 'Document PeÈ™tera X9 din Piatra Lupului #10', 'Jurnal de expeditie subterana - ziua 168. Am intrat in pestera la ora 189. Parcursul pana la tabara subterana a durat 335 ore. Am transportat 464 kilograme de echipament. La tabara temperatura era de 177 grade. Am montat 126 corturi in sala mare. Rezerva de apa potabila este de 331 litri. Am planificat 19 obiective de explorat. Primul obiectiv se afla la 226 metri de tabara. Comunicarea radio functioneaza pe o distanta de 105 metri. Am verificat starea corzilor pe 386 puturi. Am acumulat 103 ore de topografie. Fotodocumentarea a produs 7 imagini RAW. Urmatoarea tura de explorare incepe in 117 ore. Echipa este formata acum din 278 persoane active. Atmosfera din galeria inferioara contine 281 procente CO2. Am stabilit o limita de siguranta la 179 metri distanta. Stocul de baterii este suficient pentru 97 ore de functionare. Moralul echipei este excelent dupa 62 zile sub pamant.', 'doc_existing_c36_10.txt', 888, NULL, 'text_document', 1775820084);
