INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (656, 'Document PeÈ™tera X9 din Piatra Lupului #11', 'Raport formare speologica - curs nr. 307. Am instruit 217 cursanti. Durata cursului: 164 zile. Am efectuat 56 sesiuni practice in pestera. Fiecare cursant a parcurs 404 metri de galerie. Am acoperit 330 module teoretice. Examenul final a fost promovat de 462 participanti. Am distribuit 267 seturi de echipament pentru practica. Feedback-ul mediu: 406 din 10. Urmatorul curs incepe in 486 saptamani.', 'doc_existing_c36_11.txt', 399, NULL, 'text_document', 1775820084);
