INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (675, 'Document PeÈ™tera E1 din Piatra Lupului #1', 'Inventar echipament - depozit subteran 459. Total corzi disponibile: 58 metri. Dintre acestea, 110 metri necesita inlocuire. Am verificat 466 carabiniere si 406 plachete. Corzi statice diametru 10mm: 320 bucati. Am adaugat 26 saci de transport noi. Lampi de rezerva: 77 bucati cu baterii pline. Stocul de carbid: 59 kilograme. Truse de prim ajutor: 123 complete, verificate. Echipamentul este depozitat la 271 metri de intrare. Urmatoarea verificare programata peste 277 saptamani. Am retras din uz 94 echipamente expirate. Bugetul anual de echipament: 278 lei.', 'doc_existing_c37_1.txt', 561, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1572, 37, 'cave', 675, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1573, 2286, 'cave_place', 675, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (676, 'Document PeÈ™tera E1 din Piatra Lupului #2', 'Observatii topografice - tura nr. 49. Am efectuat 49 vizari cu busola si clinometrul. Lungimea poligonalei este de 27 metri. Diferenta de nivel totala: 315 metri. Am folosit statia nr. 9 ca baza. Eroarea de inchidere a poligonalei a fost sub 268 procente. Galeria prezinta un azimut predominant de 275 grade. Panta medie a galeriei este de 196 grade. Latimea variaza intre 301 si aproximativ dublu. Inaltimea maxima a sectiunii este de 282 metri. Am setat 110 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 126. Estimare galerie nemasurata: 489 metri. Am notat 411 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:285. Informam administratia ariei protejate despre descoperirea de la sectorul 61.', 'doc_existing_c37_2.txt', 747, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1574, 37, 'cave', 676, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1575, 2264, 'cave_place', 676, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (677, 'Document PeÈ™tera E1 din Piatra Lupului #3', 'Jurnal de expeditie subterana - ziua 221. Am intrat in pestera la ora 50. Parcursul pana la tabara subterana a durat 396 ore. Am transportat 389 kilograme de echipament. La tabara temperatura era de 221 grade. Am montat 271 corturi in sala mare. Rezerva de apa potabila este de 267 litri. Am planificat 85 obiective de explorat. Primul obiectiv se afla la 449 metri de tabara. Comunicarea radio functioneaza pe o distanta de 412 metri. Am verificat starea corzilor pe 62 puturi. Am acumulat 284 ore de topografie. Fotodocumentarea a produs 189 imagini RAW. Urmatoarea tura de explorare incepe in 418 ore. Echipa este formata acum din 144 persoane active. Atmosfera din galeria inferioara contine 362 procente CO2. Am stabilit o limita de siguranta la 251 metri distanta. Stocul de baterii este suficient pentru 85 ore de functionare. Moralul echipei este excelent dupa 449 zile sub pamant.', 'doc_existing_c37_3.txt', 889, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1576, 37, 'cave', 677, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1577, 161, 'cave_area', 677, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1578, 2267, 'cave_place', 677, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (678, 'Document PeÈ™tera E1 din Piatra Lupului #4', 'Raport formare speologica - curs nr. 106. Am instruit 90 cursanti. Durata cursului: 256 zile. Am efectuat 71 sesiuni practice in pestera. Fiecare cursant a parcurs 226 metri de galerie. Am acoperit 185 module teoretice. Examenul final a fost promovat de 146 participanti. Am distribuit 69 seturi de echipament pentru practica. Feedback-ul mediu: 179 din 10. Urmatorul curs incepe in 56 saptamani.', 'doc_existing_c37_4.txt', 396, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1579, 37, 'cave', 678, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1580, 163, 'cave_area', 678, 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1581, 2279, 'cave_place', 678, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (679, 'Document PeÈ™tera E1 din Piatra Lupului #5', 'Jurnal de expeditie subterana - ziua 207. Am intrat in pestera la ora 176. Parcursul pana la tabara subterana a durat 354 ore. Am transportat 138 kilograme de echipament. La tabara temperatura era de 81 grade. Am montat 76 corturi in sala mare. Rezerva de apa potabila este de 43 litri. Am planificat 459 obiective de explorat. Primul obiectiv se afla la 109 metri de tabara. Comunicarea radio functioneaza pe o distanta de 58 metri. Am verificat starea corzilor pe 17 puturi. Am acumulat 262 ore de topografie. Fotodocumentarea a produs 494 imagini RAW. Urmatoarea tura de explorare incepe in 286 ore. Echipa este formata acum din 323 persoane active. Atmosfera din galeria inferioara contine 48 procente CO2. Am stabilit o limita de siguranta la 95 metri distanta. Stocul de baterii este suficient pentru 80 ore de functionare. Moralul echipei este excelent dupa 104 zile sub pamant.', 'doc_existing_c37_5.txt', 885, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1582, 37, 'cave', 679, 1775820084);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (680, 'Document PeÈ™tera E1 din Piatra Lupului #6', 'Raport climatologic subteran - statia 271. Senzorul a inregistrat 473 cicluri complete de temperatura. Temperatura medie anuala: 446 grade Celsius. Amplitudinea termica maxima: 35 grade. Umiditatea relativa medie: 106 procente. Concentratia de CO2: 230 ppm. Curentul de aer maxim masurat: 452 metri pe secunda. Directia predominanta a curentului: sector 493. Datalogerul a functionat 172 zile fara intrerupere. Am descarcat 331 megabytes de date brute. Presiunea barometrica la intrare: 149 mbar. Evaporarea masurata: 458 milimetri pe luna. Am comparat datele cu 23 statii meteorologice de suprafata. Raportul complet include 262 grafice si tabele. Monitorizarea continua de 403 luni confirma stabilitatea climatica.', 'doc_existing_c37_6.txt', 716, NULL, 'text_document', 1775820084);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1583, 37, 'cave', 680, 1775820084);
