INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (681, 'Document PeÈ™tera E1 din Piatra Lupului #7', 'Jurnal de expeditie subterana - ziua 343. Am intrat in pestera la ora 215. Parcursul pana la tabara subterana a durat 446 ore. Am transportat 199 kilograme de echipament. La tabara temperatura era de 459 grade. Am montat 306 corturi in sala mare. Rezerva de apa potabila este de 328 litri. Am planificat 180 obiective de explorat. Primul obiectiv se afla la 450 metri de tabara. Comunicarea radio functioneaza pe o distanta de 259 metri. Am verificat starea corzilor pe 217 puturi. Am acumulat 155 ore de topografie. Fotodocumentarea a produs 161 imagini RAW. Urmatoarea tura de explorare incepe in 352 ore. Echipa este formata acum din 355 persoane active. Atmosfera din galeria inferioara contine 305 procente CO2. Am stabilit o limita de siguranta la 330 metri distanta. Stocul de baterii este suficient pentru 242 ore de functionare. Moralul echipei este excelent dupa 287 zile sub pamant.', 'doc_existing_c37_7.txt', 893, NULL, 'text_document', 1775820084);
