INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (694, 'Document PeÈ™tera E3 din Piatra Lupului #1', 'Observatii topografice - tura nr. 182. Am efectuat 435 vizari cu busola si clinometrul. Lungimea poligonalei este de 136 metri. Diferenta de nivel totala: 396 metri. Am folosit statia nr. 495 ca baza. Eroarea de inchidere a poligonalei a fost sub 272 procente. Galeria prezinta un azimut predominant de 488 grade. Panta medie a galeriei este de 234 grade. Latimea variaza intre 485 si aproximativ dublu. Inaltimea maxima a sectiunii este de 466 metri. Am setat 199 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 29. Estimare galerie nemasurata: 403 metri. Am notat 288 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:453. Informam administratia ariei protejate despre descoperirea de la sectorul 166.', 'doc_existing_c38_1.txt', 752, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1618, 38, 'cave', 694, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (695, 'Document PeÈ™tera E3 din Piatra Lupului #2', 'Observatii topografice - tura nr. 258. Am efectuat 413 vizari cu busola si clinometrul. Lungimea poligonalei este de 406 metri. Diferenta de nivel totala: 81 metri. Am folosit statia nr. 52 ca baza. Eroarea de inchidere a poligonalei a fost sub 496 procente. Galeria prezinta un azimut predominant de 102 grade. Panta medie a galeriei este de 467 grade. Latimea variaza intre 67 si aproximativ dublu. Inaltimea maxima a sectiunii este de 320 metri. Am setat 179 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 272. Estimare galerie nemasurata: 484 metri. Am notat 401 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:283. Informam administratia ariei protejate despre descoperirea de la sectorul 62.', 'doc_existing_c38_2.txt', 749, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1619, 38, 'cave', 695, 1775820085);
