INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (713, 'Document PeÈ™tera E4 din Piatra Lupului #1', 'Raport climatologic subteran - statia 187. Senzorul a inregistrat 385 cicluri complete de temperatura. Temperatura medie anuala: 303 grade Celsius. Amplitudinea termica maxima: 55 grade. Umiditatea relativa medie: 39 procente. Concentratia de CO2: 433 ppm. Curentul de aer maxim masurat: 429 metri pe secunda. Directia predominanta a curentului: sector 209. Datalogerul a functionat 353 zile fara intrerupere. Am descarcat 179 megabytes de date brute. Presiunea barometrica la intrare: 125 mbar. Evaporarea masurata: 128 milimetri pe luna. Am comparat datele cu 170 statii meteorologice de suprafata. Raportul complet include 254 grafice si tabele. Monitorizarea continua de 149 luni confirma stabilitatea climatica.', 'doc_existing_c39_1.txt', 716, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1660, 39, 'cave', 713, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1661, 2433, 'cave_place', 713, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (714, 'Document PeÈ™tera E4 din Piatra Lupului #2', 'Raport formare speologica - curs nr. 253. Am instruit 417 cursanti. Durata cursului: 108 zile. Am efectuat 86 sesiuni practice in pestera. Fiecare cursant a parcurs 26 metri de galerie. Am acoperit 248 module teoretice. Examenul final a fost promovat de 396 participanti. Am distribuit 378 seturi de echipament pentru practica. Feedback-ul mediu: 142 din 10. Urmatorul curs incepe in 57 saptamani.', 'doc_existing_c39_2.txt', 397, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1662, 39, 'cave', 714, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1663, 170, 'cave_area', 714, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (715, 'Document PeÈ™tera E4 din Piatra Lupului #3', 'Registru vizitatori - luna 157. Total vizitatori inregistrati: 175. Dintre acestia, 81 au participat la ture ghidate. Am organizat 283 ture pentru grupuri scolare. Media participantilor per tura: 234 persoane. Am distribuit 381 pliante informative. Am colectat 364 chestionare de feedback. Nota medie acordata: 108 din 10. Am inregistrat 151 incidente minore. Veniturile din taxe: 185 lei. Am angajat 247 ghizi suplimentari. Programul de vizitare a fost extins cu 361 ore pe saptamana.', 'doc_existing_c39_3.txt', 485, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1664, 39, 'cave', 715, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1665, 175, 'cave_area', 715, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1666, 2402, 'cave_place', 715, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (716, 'Document PeÈ™tera E4 din Piatra Lupului #4', 'Raport conservare patrimoniu - obiectiv 304. Am evaluat starea a 14 inscriptii istorice. Dintre acestea, 370 necesita interventie urgenta. Am curatat 256 metri patrati de graffiti modern. Am instalat 145 panouri informative la intrare. Bariera de protectie acopera 81 metri liniari. Am documentat 417 urme de vandalism. Raportul a fost transmis autoritatilor locale in 127 exemplare. Am propus clasificarea a 304 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 252 persoane simultan. Am instruit 401 ghizi locali. Costul estimat al lucrarilor: 231 lei. Termenul de finalizare: 40 luni.', 'doc_existing_c39_4.txt', 603, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1667, 39, 'cave', 716, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1668, 173, 'cave_area', 716, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1669, 2439, 'cave_place', 716, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (717, 'Document PeÈ™tera E4 din Piatra Lupului #5', 'Registru vizitatori - luna 453. Total vizitatori inregistrati: 71. Dintre acestia, 176 au participat la ture ghidate. Am organizat 4 ture pentru grupuri scolare. Media participantilor per tura: 401 persoane. Am distribuit 442 pliante informative. Am colectat 488 chestionare de feedback. Nota medie acordata: 71 din 10. Am inregistrat 370 incidente minore. Veniturile din taxe: 220 lei. Am angajat 129 ghizi suplimentari. Programul de vizitare a fost extins cu 476 ore pe saptamana.', 'doc_existing_c39_5.txt', 482, NULL, 'text_document', 1775820085);
