INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (718, 'Document PeÈ™tera E4 din Piatra Lupului #6', 'Raport formare speologica - curs nr. 353. Am instruit 477 cursanti. Durata cursului: 117 zile. Am efectuat 21 sesiuni practice in pestera. Fiecare cursant a parcurs 421 metri de galerie. Am acoperit 115 module teoretice. Examenul final a fost promovat de 445 participanti. Am distribuit 401 seturi de echipament pentru practica. Feedback-ul mediu: 180 din 10. Urmatorul curs incepe in 132 saptamani.', 'doc_existing_c39_6.txt', 399, NULL, 'text_document', 1775820085);
