INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (719, 'Document PeÈ™tera E4 din Piatra Lupului #7', 'Nota de mentenanta balize - traseul 32. Am verificat 43 balize reflectorizante. Dintre acestea, 490 au fost inlocuite. Am adaugat 99 balize noi in zonele nemarcate. Distanta medie intre balize: 388 metri. Am folosit 310 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 396 metri cu lampa frontala. Am eliminat 245 marcaje vechi si confuze. Traseul total balizat: 213 metri. Urmatoarea verificare: peste 439 luni. Materialul consumat: 334 benzi reflectorizante.', 'doc_existing_c39_7.txt', 482, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1674, 39, 'cave', 719, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1675, 2383, 'cave_place', 719, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (720, 'Document PeÈ™tera E4 din Piatra Lupului #8', 'Jurnal de expeditie subterana - ziua 422. Am intrat in pestera la ora 168. Parcursul pana la tabara subterana a durat 247 ore. Am transportat 227 kilograme de echipament. La tabara temperatura era de 236 grade. Am montat 493 corturi in sala mare. Rezerva de apa potabila este de 308 litri. Am planificat 221 obiective de explorat. Primul obiectiv se afla la 395 metri de tabara. Comunicarea radio functioneaza pe o distanta de 159 metri. Am verificat starea corzilor pe 346 puturi. Am acumulat 98 ore de topografie. Fotodocumentarea a produs 218 imagini RAW. Urmatoarea tura de explorare incepe in 376 ore. Echipa este formata acum din 268 persoane active. Atmosfera din galeria inferioara contine 304 procente CO2. Am stabilit o limita de siguranta la 324 metri distanta. Stocul de baterii este suficient pentru 305 ore de functionare. Moralul echipei este excelent dupa 352 zile sub pamant.', 'doc_existing_c39_8.txt', 892, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1676, 39, 'cave', 720, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1677, 171, 'cave_area', 720, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1678, 2391, 'cave_place', 720, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (721, 'Document PeÈ™tera E4 din Piatra Lupului #9', 'Observatii topografice - tura nr. 320. Am efectuat 460 vizari cu busola si clinometrul. Lungimea poligonalei este de 43 metri. Diferenta de nivel totala: 493 metri. Am folosit statia nr. 69 ca baza. Eroarea de inchidere a poligonalei a fost sub 487 procente. Galeria prezinta un azimut predominant de 330 grade. Panta medie a galeriei este de 496 grade. Latimea variaza intre 92 si aproximativ dublu. Inaltimea maxima a sectiunii este de 29 metri. Am setat 85 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 87. Estimare galerie nemasurata: 116 metri. Am notat 98 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:368. Informam administratia ariei protejate despre descoperirea de la sectorul 364.', 'doc_existing_c39_9.txt', 746, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1679, 39, 'cave', 721, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1680, 170, 'cave_area', 721, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1681, 2397, 'cave_place', 721, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (722, 'Document PeÈ™tera E4 din Piatra Lupului #10', 'Fisa tehnica echipare put - verticala nr. 49. Adancimea: 345 metri. Am instalat 374 spituri din otel inoxidabil. Distanta intre spituri: 444 metri. Lungimea corzii principale: 341 metri. Coarda de siguranta: 340 metri. Am montat 494 protectoare de franghie. Fractionarea se face la 452 metri de buza putului. Deviatia este la 318 metri sub fractionare. Am testat echiparea cu 488 coborari. Ultimul control al spiturilor: acum 164 luni.', 'doc_existing_c39_10.txt', 435, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1682, 39, 'cave', 722, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1683, 176, 'cave_area', 722, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1684, 2410, 'cave_place', 722, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (723, 'Document PeÈ™tera E4 din Piatra Lupului #11', 'Plan de explorare - obiectiv 298. Am identificat 457 galerii laterale neexplorate. Lungimea estimata: 112 metri pe fiecare. Sunt necesare 305 zile de explorare. Echipa recomandata: 195 persoane. Echipament vertical necesar pentru 111 puturi. Am pregatit 411 kilograme de echipament. Rezerva de carbid: 340 kilograme. Punctul de plecare este statia topografica 67. Comunicarea radio va fi testata la 368 puncte. Am obtinut 263 autorizatii necesare. Data planificata: peste 118 saptamani. Bugetul estimat: 346 lei.', 'doc_existing_c39_11.txt', 512, NULL, 'text_document', 1775820085);
