INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (742, 'Document PeÈ™tera E5 din Piatra Lupului #1', 'Jurnal de expeditie subterana - ziua 344. Am intrat in pestera la ora 30. Parcursul pana la tabara subterana a durat 108 ore. Am transportat 343 kilograme de echipament. La tabara temperatura era de 339 grade. Am montat 392 corturi in sala mare. Rezerva de apa potabila este de 266 litri. Am planificat 417 obiective de explorat. Primul obiectiv se afla la 448 metri de tabara. Comunicarea radio functioneaza pe o distanta de 360 metri. Am verificat starea corzilor pe 16 puturi. Am acumulat 440 ore de topografie. Fotodocumentarea a produs 117 imagini RAW. Urmatoarea tura de explorare incepe in 341 ore. Echipa este formata acum din 199 persoane active. Atmosfera din galeria inferioara contine 313 procente CO2. Am stabilit o limita de siguranta la 261 metri distanta. Stocul de baterii este suficient pentru 348 ore de functionare. Moralul echipei este excelent dupa 125 zile sub pamant.', 'doc_existing_c40_1.txt', 891, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1727, 40, 'cave', 742, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1728, 2458, 'cave_place', 742, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (743, 'Document PeÈ™tera E5 din Piatra Lupului #2', 'Jurnal de expeditie subterana - ziua 220. Am intrat in pestera la ora 393. Parcursul pana la tabara subterana a durat 286 ore. Am transportat 392 kilograme de echipament. La tabara temperatura era de 302 grade. Am montat 198 corturi in sala mare. Rezerva de apa potabila este de 92 litri. Am planificat 204 obiective de explorat. Primul obiectiv se afla la 424 metri de tabara. Comunicarea radio functioneaza pe o distanta de 437 metri. Am verificat starea corzilor pe 256 puturi. Am acumulat 28 ore de topografie. Fotodocumentarea a produs 71 imagini RAW. Urmatoarea tura de explorare incepe in 195 ore. Echipa este formata acum din 362 persoane active. Atmosfera din galeria inferioara contine 159 procente CO2. Am stabilit o limita de siguranta la 401 metri distanta. Stocul de baterii este suficient pentru 382 ore de functionare. Moralul echipei este excelent dupa 241 zile sub pamant.', 'doc_existing_c40_2.txt', 890, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1729, 40, 'cave', 743, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (744, 'Document PeÈ™tera E5 din Piatra Lupului #3', 'Registru vizitatori - luna 150. Total vizitatori inregistrati: 142. Dintre acestia, 226 au participat la ture ghidate. Am organizat 6 ture pentru grupuri scolare. Media participantilor per tura: 388 persoane. Am distribuit 247 pliante informative. Am colectat 397 chestionare de feedback. Nota medie acordata: 438 din 10. Am inregistrat 211 incidente minore. Veniturile din taxe: 206 lei. Am angajat 326 ghizi suplimentari. Programul de vizitare a fost extins cu 21 ore pe saptamana.', 'doc_existing_c40_3.txt', 483, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1730, 40, 'cave', 744, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (745, 'Document PeÈ™tera E5 din Piatra Lupului #4', 'Inventar echipament - depozit subteran 285. Total corzi disponibile: 305 metri. Dintre acestea, 367 metri necesita inlocuire. Am verificat 6 carabiniere si 500 plachete. Corzi statice diametru 10mm: 345 bucati. Am adaugat 387 saci de transport noi. Lampi de rezerva: 103 bucati cu baterii pline. Stocul de carbid: 169 kilograme. Truse de prim ajutor: 340 complete, verificate. Echipamentul este depozitat la 188 metri de intrare. Urmatoarea verificare programata peste 346 saptamani. Am retras din uz 42 echipamente expirate. Bugetul anual de echipament: 226 lei.', 'doc_existing_c40_4.txt', 563, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1731, 40, 'cave', 745, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1732, 178, 'cave_area', 745, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1733, 2507, 'cave_place', 745, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (746, 'Document PeÈ™tera E5 din Piatra Lupului #5', 'Fisa tehnica echipare put - verticala nr. 332. Adancimea: 91 metri. Am instalat 164 spituri din otel inoxidabil. Distanta intre spituri: 426 metri. Lungimea corzii principale: 427 metri. Coarda de siguranta: 354 metri. Am montat 319 protectoare de franghie. Fractionarea se face la 106 metri de buza putului. Deviatia este la 146 metri sub fractionare. Am testat echiparea cu 224 coborari. Ultimul control al spiturilor: acum 394 luni.', 'doc_existing_c40_5.txt', 435, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1734, 40, 'cave', 746, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1735, 2492, 'cave_place', 746, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (747, 'Document PeÈ™tera E5 din Piatra Lupului #6', 'Raport conservare patrimoniu - obiectiv 432. Am evaluat starea a 371 inscriptii istorice. Dintre acestea, 262 necesita interventie urgenta. Am curatat 263 metri patrati de graffiti modern. Am instalat 363 panouri informative la intrare. Bariera de protectie acopera 322 metri liniari. Am documentat 257 urme de vandalism. Raportul a fost transmis autoritatilor locale in 230 exemplare. Am propus clasificarea a 485 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 54 persoane simultan. Am instruit 65 ghizi locali. Costul estimat al lucrarilor: 324 lei. Termenul de finalizare: 307 luni.', 'doc_existing_c40_6.txt', 604, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1736, 40, 'cave', 747, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1737, 178, 'cave_area', 747, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1738, 2457, 'cave_place', 747, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (748, 'Document PeÈ™tera E5 din Piatra Lupului #7', 'Raport formare speologica - curs nr. 207. Am instruit 265 cursanti. Durata cursului: 73 zile. Am efectuat 7 sesiuni practice in pestera. Fiecare cursant a parcurs 24 metri de galerie. Am acoperit 279 module teoretice. Examenul final a fost promovat de 174 participanti. Am distribuit 159 seturi de echipament pentru practica. Feedback-ul mediu: 179 din 10. Urmatorul curs incepe in 323 saptamani.', 'doc_existing_c40_7.txt', 396, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1739, 40, 'cave', 748, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1740, 177, 'cave_area', 748, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1741, 2517, 'cave_place', 748, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (749, 'Document PeÈ™tera E5 din Piatra Lupului #8', 'Plan de explorare - obiectiv 53. Am identificat 135 galerii laterale neexplorate. Lungimea estimata: 88 metri pe fiecare. Sunt necesare 396 zile de explorare. Echipa recomandata: 448 persoane. Echipament vertical necesar pentru 355 puturi. Am pregatit 472 kilograme de echipament. Rezerva de carbid: 385 kilograme. Punctul de plecare este statia topografica 253. Comunicarea radio va fi testata la 410 puncte. Am obtinut 475 autorizatii necesare. Data planificata: peste 345 saptamani. Bugetul estimat: 105 lei.', 'doc_existing_c40_8.txt', 511, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1742, 40, 'cave', 749, 1775820085);
