INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (773, 'Document PeÈ™tera F1 din Piatra Lupului #1', 'Raport formare speologica - curs nr. 284. Am instruit 389 cursanti. Durata cursului: 251 zile. Am efectuat 53 sesiuni practice in pestera. Fiecare cursant a parcurs 119 metri de galerie. Am acoperit 187 module teoretice. Examenul final a fost promovat de 384 participanti. Am distribuit 248 seturi de echipament pentru practica. Feedback-ul mediu: 34 din 10. Urmatorul curs incepe in 312 saptamani.', 'doc_existing_c42_1.txt', 398, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1801, 42, 'cave', 773, 1775820085);
