INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (774, 'Document PeÈ™tera F1 din Piatra Lupului #2', 'Raport climatologic subteran - statia 73. Senzorul a inregistrat 261 cicluri complete de temperatura. Temperatura medie anuala: 301 grade Celsius. Amplitudinea termica maxima: 305 grade. Umiditatea relativa medie: 212 procente. Concentratia de CO2: 1 ppm. Curentul de aer maxim masurat: 434 metri pe secunda. Directia predominanta a curentului: sector 278. Datalogerul a functionat 174 zile fara intrerupere. Am descarcat 56 megabytes de date brute. Presiunea barometrica la intrare: 494 mbar. Evaporarea masurata: 160 milimetri pe luna. Am comparat datele cu 84 statii meteorologice de suprafata. Raportul complet include 143 grafice si tabele. Monitorizarea continua de 443 luni confirma stabilitatea climatica.', 'doc_existing_c42_2.txt', 713, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1803, 42, 'cave', 774, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1804, 194, 'cave_area', 774, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (775, 'Document PeÈ™tera F1 din Piatra Lupului #3', 'Raport formare speologica - curs nr. 304. Am instruit 199 cursanti. Durata cursului: 66 zile. Am efectuat 346 sesiuni practice in pestera. Fiecare cursant a parcurs 57 metri de galerie. Am acoperit 235 module teoretice. Examenul final a fost promovat de 176 participanti. Am distribuit 360 seturi de echipament pentru practica. Feedback-ul mediu: 267 din 10. Urmatorul curs incepe in 14 saptamani.', 'doc_existing_c42_3.txt', 397, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1805, 42, 'cave', 775, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (776, 'Document PeÈ™tera F1 din Piatra Lupului #4', 'Nota de mentenanta balize - traseul 24. Am verificat 449 balize reflectorizante. Dintre acestea, 77 au fost inlocuite. Am adaugat 174 balize noi in zonele nemarcate. Distanta medie intre balize: 36 metri. Am folosit 425 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 146 metri cu lampa frontala. Am eliminat 70 marcaje vechi si confuze. Traseul total balizat: 268 metri. Urmatoarea verificare: peste 28 luni. Materialul consumat: 395 benzi reflectorizante.', 'doc_existing_c42_4.txt', 480, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1806, 42, 'cave', 776, 1775820085);
