INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (777, 'Document PeÈ™tera F1 din Piatra Lupului #5', 'Nota de mentenanta balize - traseul 405. Am verificat 305 balize reflectorizante. Dintre acestea, 387 au fost inlocuite. Am adaugat 397 balize noi in zonele nemarcate. Distanta medie intre balize: 264 metri. Am folosit 392 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 249 metri cu lampa frontala. Am eliminat 493 marcaje vechi si confuze. Traseul total balizat: 67 metri. Urmatoarea verificare: peste 165 luni. Materialul consumat: 300 benzi reflectorizante.', 'doc_existing_c42_5.txt', 484, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1809, 42, 'cave', 777, 1775820085);
