INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (779, 'Document PeÈ™tera F1 din Piatra Lupului #7', 'Plan de explorare - obiectiv 117. Am identificat 352 galerii laterale neexplorate. Lungimea estimata: 36 metri pe fiecare. Sunt necesare 165 zile de explorare. Echipa recomandata: 267 persoane. Echipament vertical necesar pentru 334 puturi. Am pregatit 272 kilograme de echipament. Rezerva de carbid: 402 kilograme. Punctul de plecare este statia topografica 483. Comunicarea radio va fi testata la 460 puncte. Am obtinut 293 autorizatii necesare. Data planificata: peste 26 saptamani. Bugetul estimat: 310 lei.', 'doc_existing_c42_7.txt', 511, NULL, 'text_document', 1775820085);
