INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (784, 'Document PeÈ™tera F1 din Piatra Lupului #12', 'Raport formare speologica - curs nr. 172. Am instruit 220 cursanti. Durata cursului: 479 zile. Am efectuat 334 sesiuni practice in pestera. Fiecare cursant a parcurs 137 metri de galerie. Am acoperit 70 module teoretice. Examenul final a fost promovat de 463 participanti. Am distribuit 103 seturi de echipament pentru practica. Feedback-ul mediu: 11 din 10. Urmatorul curs incepe in 137 saptamani.', 'doc_existing_c42_12.txt', 398, NULL, 'text_document', 1775820085);
