INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (785, 'Document PeÈ™tera F1 din Piatra Lupului #13', 'Plan de explorare - obiectiv 484. Am identificat 59 galerii laterale neexplorate. Lungimea estimata: 81 metri pe fiecare. Sunt necesare 18 zile de explorare. Echipa recomandata: 210 persoane. Echipament vertical necesar pentru 288 puturi. Am pregatit 143 kilograme de echipament. Rezerva de carbid: 303 kilograme. Punctul de plecare este statia topografica 57. Comunicarea radio va fi testata la 256 puncte. Am obtinut 345 autorizatii necesare. Data planificata: peste 221 saptamani. Bugetul estimat: 490 lei.', 'doc_existing_c42_13.txt', 509, NULL, 'text_document', 1775820085);
