INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (808, 'Document PeÈ™tera F2 din Piatra Lupului #1', 'Nota de mentenanta balize - traseul 144. Am verificat 413 balize reflectorizante. Dintre acestea, 315 au fost inlocuite. Am adaugat 487 balize noi in zonele nemarcate. Distanta medie intre balize: 126 metri. Am folosit 64 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 478 metri cu lampa frontala. Am eliminat 478 marcaje vechi si confuze. Traseul total balizat: 262 metri. Urmatoarea verificare: peste 353 luni. Materialul consumat: 413 benzi reflectorizante.', 'doc_existing_c43_1.txt', 484, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1881, 43, 'cave', 808, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1882, 195, 'cave_area', 808, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1883, 2645, 'cave_place', 808, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (809, 'Document PeÈ™tera F2 din Piatra Lupului #2', 'Fisa tehnica echipare put - verticala nr. 229. Adancimea: 116 metri. Am instalat 151 spituri din otel inoxidabil. Distanta intre spituri: 164 metri. Lungimea corzii principale: 117 metri. Coarda de siguranta: 244 metri. Am montat 283 protectoare de franghie. Fractionarea se face la 155 metri de buza putului. Deviatia este la 278 metri sub fractionare. Am testat echiparea cu 379 coborari. Ultimul control al spiturilor: acum 402 luni.', 'doc_existing_c43_2.txt', 436, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1884, 43, 'cave', 809, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1885, 195, 'cave_area', 809, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1886, 2624, 'cave_place', 809, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (810, 'Document PeÈ™tera F2 din Piatra Lupului #3', 'Observatii topografice - tura nr. 427. Am efectuat 352 vizari cu busola si clinometrul. Lungimea poligonalei este de 387 metri. Diferenta de nivel totala: 77 metri. Am folosit statia nr. 165 ca baza. Eroarea de inchidere a poligonalei a fost sub 345 procente. Galeria prezinta un azimut predominant de 282 grade. Panta medie a galeriei este de 188 grade. Latimea variaza intre 205 si aproximativ dublu. Inaltimea maxima a sectiunii este de 439 metri. Am setat 19 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 236. Estimare galerie nemasurata: 341 metri. Am notat 40 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:33. Informam administratia ariei protejate despre descoperirea de la sectorul 456.', 'doc_existing_c43_3.txt', 749, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1887, 43, 'cave', 810, 1775820085);
