INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (811, 'Document PeÈ™tera F2 din Piatra Lupului #4', 'Raport conservare patrimoniu - obiectiv 331. Am evaluat starea a 22 inscriptii istorice. Dintre acestea, 76 necesita interventie urgenta. Am curatat 34 metri patrati de graffiti modern. Am instalat 369 panouri informative la intrare. Bariera de protectie acopera 267 metri liniari. Am documentat 398 urme de vandalism. Raportul a fost transmis autoritatilor locale in 285 exemplare. Am propus clasificarea a 9 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 77 persoane simultan. Am instruit 14 ghizi locali. Costul estimat al lucrarilor: 312 lei. Termenul de finalizare: 228 luni.', 'doc_existing_c43_4.txt', 599, NULL, 'text_document', 1775820085);
