INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (812, 'Document PeÈ™tera F2 din Piatra Lupului #5', 'Observatii topografice - tura nr. 230. Am efectuat 307 vizari cu busola si clinometrul. Lungimea poligonalei este de 247 metri. Diferenta de nivel totala: 381 metri. Am folosit statia nr. 482 ca baza. Eroarea de inchidere a poligonalei a fost sub 427 procente. Galeria prezinta un azimut predominant de 380 grade. Panta medie a galeriei este de 16 grade. Latimea variaza intre 330 si aproximativ dublu. Inaltimea maxima a sectiunii este de 467 metri. Am setat 367 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 413. Estimare galerie nemasurata: 107 metri. Am notat 380 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:144. Informam administratia ariei protejate despre descoperirea de la sectorul 380.', 'doc_existing_c43_5.txt', 752, NULL, 'text_document', 1775820085);
