INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (814, 'Document PeÈ™tera F2 din Piatra Lupului #7', 'Inventar echipament - depozit subteran 339. Total corzi disponibile: 441 metri. Dintre acestea, 154 metri necesita inlocuire. Am verificat 6 carabiniere si 331 plachete. Corzi statice diametru 10mm: 204 bucati. Am adaugat 19 saci de transport noi. Lampi de rezerva: 28 bucati cu baterii pline. Stocul de carbid: 436 kilograme. Truse de prim ajutor: 92 complete, verificate. Echipamentul este depozitat la 79 metri de intrare. Urmatoarea verificare programata peste 480 saptamani. Am retras din uz 28 echipamente expirate. Bugetul anual de echipament: 71 lei.', 'doc_existing_c43_7.txt', 558, NULL, 'text_document', 1775820085);
