INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (831, 'Document PeÈ™tera F3 din Piatra Lupului #1', 'Nota de mentenanta balize - traseul 38. Am verificat 371 balize reflectorizante. Dintre acestea, 351 au fost inlocuite. Am adaugat 87 balize noi in zonele nemarcate. Distanta medie intre balize: 443 metri. Am folosit 160 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 97 metri cu lampa frontala. Am eliminat 308 marcaje vechi si confuze. Traseul total balizat: 459 metri. Urmatoarea verificare: peste 78 luni. Materialul consumat: 132 benzi reflectorizante.', 'doc_existing_c44_1.txt', 481, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1938, 44, 'cave', 831, 1775820085);
