INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (832, 'Document PeÈ™tera F3 din Piatra Lupului #2', 'Raport formare speologica - curs nr. 123. Am instruit 459 cursanti. Durata cursului: 355 zile. Am efectuat 441 sesiuni practice in pestera. Fiecare cursant a parcurs 265 metri de galerie. Am acoperit 334 module teoretice. Examenul final a fost promovat de 422 participanti. Am distribuit 459 seturi de echipament pentru practica. Feedback-ul mediu: 120 din 10. Urmatorul curs incepe in 139 saptamani.', 'doc_existing_c44_2.txt', 400, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (1941, 44, 'cave', 832, 1775820085);
