INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (833, 'Document PeÈ™tera F3 din Piatra Lupului #3', 'Raport formare speologica - curs nr. 209. Am instruit 123 cursanti. Durata cursului: 412 zile. Am efectuat 148 sesiuni practice in pestera. Fiecare cursant a parcurs 374 metri de galerie. Am acoperit 103 module teoretice. Examenul final a fost promovat de 371 participanti. Am distribuit 20 seturi de echipament pentru practica. Feedback-ul mediu: 408 din 10. Urmatorul curs incepe in 184 saptamani.', 'doc_existing_c44_3.txt', 399, NULL, 'text_document', 1775820085);
