INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (872, 'Document PeÈ™tera F5 din Piatra Lupului #1', 'Observatii topografice - tura nr. 128. Am efectuat 418 vizari cu busola si clinometrul. Lungimea poligonalei este de 234 metri. Diferenta de nivel totala: 199 metri. Am folosit statia nr. 182 ca baza. Eroarea de inchidere a poligonalei a fost sub 447 procente. Galeria prezinta un azimut predominant de 12 grade. Panta medie a galeriei este de 171 grade. Latimea variaza intre 463 si aproximativ dublu. Inaltimea maxima a sectiunii este de 213 metri. Am setat 380 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 74. Estimare galerie nemasurata: 484 metri. Am notat 104 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:248. Informam administratia ariei protejate despre descoperirea de la sectorul 28.', 'doc_existing_c46_1.txt', 750, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2035, 46, 'cave', 872, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2036, 211, 'cave_area', 872, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2037, 2874, 'cave_place', 872, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (873, 'Document PeÈ™tera F5 din Piatra Lupului #2', 'Registru vizitatori - luna 236. Total vizitatori inregistrati: 500. Dintre acestia, 21 au participat la ture ghidate. Am organizat 485 ture pentru grupuri scolare. Media participantilor per tura: 433 persoane. Am distribuit 278 pliante informative. Am colectat 109 chestionare de feedback. Nota medie acordata: 348 din 10. Am inregistrat 247 incidente minore. Veniturile din taxe: 440 lei. Am angajat 445 ghizi suplimentari. Programul de vizitare a fost extins cu 409 ore pe saptamana.', 'doc_existing_c46_2.txt', 485, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2038, 46, 'cave', 873, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (874, 'Document PeÈ™tera F5 din Piatra Lupului #3', 'Plan de explorare - obiectiv 500. Am identificat 238 galerii laterale neexplorate. Lungimea estimata: 232 metri pe fiecare. Sunt necesare 44 zile de explorare. Echipa recomandata: 271 persoane. Echipament vertical necesar pentru 276 puturi. Am pregatit 420 kilograme de echipament. Rezerva de carbid: 208 kilograme. Punctul de plecare este statia topografica 150. Comunicarea radio va fi testata la 416 puncte. Am obtinut 417 autorizatii necesare. Data planificata: peste 310 saptamani. Bugetul estimat: 469 lei.', 'doc_existing_c46_3.txt', 512, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2039, 46, 'cave', 874, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2040, 2830, 'cave_place', 874, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (875, 'Document PeÈ™tera F5 din Piatra Lupului #4', 'Plan de explorare - obiectiv 264. Am identificat 156 galerii laterale neexplorate. Lungimea estimata: 450 metri pe fiecare. Sunt necesare 77 zile de explorare. Echipa recomandata: 205 persoane. Echipament vertical necesar pentru 393 puturi. Am pregatit 66 kilograme de echipament. Rezerva de carbid: 84 kilograme. Punctul de plecare este statia topografica 44. Comunicarea radio va fi testata la 476 puncte. Am obtinut 103 autorizatii necesare. Data planificata: peste 494 saptamani. Bugetul estimat: 119 lei.', 'doc_existing_c46_4.txt', 509, NULL, 'text_document', 1775820085);
