INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (892, 'Document PeÈ™tera G1 din Piatra Lupului #1', 'Nota de mentenanta balize - traseul 151. Am verificat 45 balize reflectorizante. Dintre acestea, 133 au fost inlocuite. Am adaugat 428 balize noi in zonele nemarcate. Distanta medie intre balize: 492 metri. Am folosit 247 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 159 metri cu lampa frontala. Am eliminat 23 marcaje vechi si confuze. Traseul total balizat: 403 metri. Urmatoarea verificare: peste 44 luni. Materialul consumat: 232 benzi reflectorizante.', 'doc_existing_c47_1.txt', 482, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2082, 47, 'cave', 892, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2083, 213, 'cave_area', 892, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (893, 'Document PeÈ™tera G1 din Piatra Lupului #2', 'Fisa tehnica echipare put - verticala nr. 116. Adancimea: 472 metri. Am instalat 66 spituri din otel inoxidabil. Distanta intre spituri: 16 metri. Lungimea corzii principale: 466 metri. Coarda de siguranta: 87 metri. Am montat 481 protectoare de franghie. Fractionarea se face la 19 metri de buza putului. Deviatia este la 189 metri sub fractionare. Am testat echiparea cu 376 coborari. Ultimul control al spiturilor: acum 495 luni.', 'doc_existing_c47_2.txt', 432, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2084, 47, 'cave', 893, 1775820085);
