INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (899, 'Document PeÈ™tera G2 din Piatra Lupului #1', 'Inventar echipament - depozit subteran 19. Total corzi disponibile: 272 metri. Dintre acestea, 223 metri necesita inlocuire. Am verificat 449 carabiniere si 160 plachete. Corzi statice diametru 10mm: 471 bucati. Am adaugat 351 saci de transport noi. Lampi de rezerva: 143 bucati cu baterii pline. Stocul de carbid: 157 kilograme. Truse de prim ajutor: 480 complete, verificate. Echipamentul este depozitat la 276 metri de intrare. Urmatoarea verificare programata peste 139 saptamani. Am retras din uz 307 echipamente expirate. Bugetul anual de echipament: 219 lei.', 'doc_existing_c48_1.txt', 565, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2097, 48, 'cave', 899, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2098, 3011, 'cave_place', 899, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (900, 'Document PeÈ™tera G2 din Piatra Lupului #2', 'Observatii topografice - tura nr. 458. Am efectuat 399 vizari cu busola si clinometrul. Lungimea poligonalei este de 456 metri. Diferenta de nivel totala: 437 metri. Am folosit statia nr. 44 ca baza. Eroarea de inchidere a poligonalei a fost sub 164 procente. Galeria prezinta un azimut predominant de 179 grade. Panta medie a galeriei este de 364 grade. Latimea variaza intre 326 si aproximativ dublu. Inaltimea maxima a sectiunii este de 409 metri. Am setat 91 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 193. Estimare galerie nemasurata: 307 metri. Am notat 206 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:381. Informam administratia ariei protejate despre descoperirea de la sectorul 155.', 'doc_existing_c48_2.txt', 751, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2099, 48, 'cave', 900, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2100, 2974, 'cave_place', 900, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (901, 'Document PeÈ™tera G2 din Piatra Lupului #3', 'Observatii topografice - tura nr. 433. Am efectuat 24 vizari cu busola si clinometrul. Lungimea poligonalei este de 104 metri. Diferenta de nivel totala: 77 metri. Am folosit statia nr. 356 ca baza. Eroarea de inchidere a poligonalei a fost sub 456 procente. Galeria prezinta un azimut predominant de 68 grade. Panta medie a galeriei este de 387 grade. Latimea variaza intre 406 si aproximativ dublu. Inaltimea maxima a sectiunii este de 223 metri. Am setat 200 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 430. Estimare galerie nemasurata: 227 metri. Am notat 405 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:224. Informam administratia ariei protejate despre descoperirea de la sectorul 348.', 'doc_existing_c48_3.txt', 750, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2101, 48, 'cave', 901, 1775820085);
