INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (902, 'Document PeÈ™tera G2 din Piatra Lupului #4', 'Nota de mentenanta balize - traseul 125. Am verificat 453 balize reflectorizante. Dintre acestea, 240 au fost inlocuite. Am adaugat 350 balize noi in zonele nemarcate. Distanta medie intre balize: 367 metri. Am folosit 456 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 90 metri cu lampa frontala. Am eliminat 273 marcaje vechi si confuze. Traseul total balizat: 320 metri. Urmatoarea verificare: peste 107 luni. Materialul consumat: 493 benzi reflectorizante.', 'doc_existing_c48_4.txt', 484, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2103, 48, 'cave', 902, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2104, 218, 'cave_area', 902, 1775820085);
