INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (903, 'Document PeÈ™tera G2 din Piatra Lupului #5', 'Registru vizitatori - luna 24. Total vizitatori inregistrati: 189. Dintre acestia, 196 au participat la ture ghidate. Am organizat 130 ture pentru grupuri scolare. Media participantilor per tura: 97 persoane. Am distribuit 24 pliante informative. Am colectat 175 chestionare de feedback. Nota medie acordata: 433 din 10. Am inregistrat 114 incidente minore. Veniturile din taxe: 298 lei. Am angajat 346 ghizi suplimentari. Programul de vizitare a fost extins cu 323 ore pe saptamana.', 'doc_existing_c48_5.txt', 483, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2106, 48, 'cave', 903, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2107, 2984, 'cave_place', 903, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (904, 'Document PeÈ™tera G2 din Piatra Lupului #6', 'Plan de explorare - obiectiv 433. Am identificat 277 galerii laterale neexplorate. Lungimea estimata: 230 metri pe fiecare. Sunt necesare 264 zile de explorare. Echipa recomandata: 8 persoane. Echipament vertical necesar pentru 291 puturi. Am pregatit 402 kilograme de echipament. Rezerva de carbid: 256 kilograme. Punctul de plecare este statia topografica 278. Comunicarea radio va fi testata la 186 puncte. Am obtinut 73 autorizatii necesare. Data planificata: peste 170 saptamani. Bugetul estimat: 314 lei.', 'doc_existing_c48_6.txt', 510, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2108, 48, 'cave', 904, 1775820085);
