INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (905, 'Document PeÈ™tera G2 din Piatra Lupului #7', 'Observatii topografice - tura nr. 16. Am efectuat 210 vizari cu busola si clinometrul. Lungimea poligonalei este de 295 metri. Diferenta de nivel totala: 312 metri. Am folosit statia nr. 56 ca baza. Eroarea de inchidere a poligonalei a fost sub 349 procente. Galeria prezinta un azimut predominant de 160 grade. Panta medie a galeriei este de 337 grade. Latimea variaza intre 373 si aproximativ dublu. Inaltimea maxima a sectiunii este de 19 metri. Am setat 414 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 439. Estimare galerie nemasurata: 256 metri. Am notat 471 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:89. Informam administratia ariei protejate despre descoperirea de la sectorul 447.', 'doc_existing_c48_7.txt', 749, NULL, 'text_document', 1775820085);
