INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (907, 'Document PeÈ™tera G2 din Piatra Lupului #9', 'Raport conservare patrimoniu - obiectiv 230. Am evaluat starea a 473 inscriptii istorice. Dintre acestea, 291 necesita interventie urgenta. Am curatat 427 metri patrati de graffiti modern. Am instalat 160 panouri informative la intrare. Bariera de protectie acopera 103 metri liniari. Am documentat 93 urme de vandalism. Raportul a fost transmis autoritatilor locale in 16 exemplare. Am propus clasificarea a 251 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 152 persoane simultan. Am instruit 421 ghizi locali. Costul estimat al lucrarilor: 140 lei. Termenul de finalizare: 70 luni.', 'doc_existing_c48_9.txt', 603, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2115, 48, 'cave', 907, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2116, 2981, 'cave_place', 907, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (908, 'Document PeÈ™tera G2 din Piatra Lupului #10', 'Nota de mentenanta balize - traseul 428. Am verificat 140 balize reflectorizante. Dintre acestea, 273 au fost inlocuite. Am adaugat 303 balize noi in zonele nemarcate. Distanta medie intre balize: 170 metri. Am folosit 367 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 316 metri cu lampa frontala. Am eliminat 171 marcaje vechi si confuze. Traseul total balizat: 222 metri. Urmatoarea verificare: peste 459 luni. Materialul consumat: 335 benzi reflectorizante.', 'doc_existing_c48_10.txt', 485, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2117, 48, 'cave', 908, 1775820085);
