INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (909, 'Document PeÈ™tera G2 din Piatra Lupului #11', 'Inventar echipament - depozit subteran 258. Total corzi disponibile: 142 metri. Dintre acestea, 149 metri necesita inlocuire. Am verificat 65 carabiniere si 182 plachete. Corzi statice diametru 10mm: 89 bucati. Am adaugat 61 saci de transport noi. Lampi de rezerva: 483 bucati cu baterii pline. Stocul de carbid: 431 kilograme. Truse de prim ajutor: 220 complete, verificate. Echipamentul este depozitat la 351 metri de intrare. Urmatoarea verificare programata peste 239 saptamani. Am retras din uz 355 echipamente expirate. Bugetul anual de echipament: 27 lei.', 'doc_existing_c48_11.txt', 562, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2120, 48, 'cave', 909, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2121, 2979, 'cave_place', 909, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (910, 'Document PeÈ™tera G2 din Piatra Lupului #12', 'Fisa tehnica echipare put - verticala nr. 79. Adancimea: 386 metri. Am instalat 494 spituri din otel inoxidabil. Distanta intre spituri: 191 metri. Lungimea corzii principale: 460 metri. Coarda de siguranta: 307 metri. Am montat 107 protectoare de franghie. Fractionarea se face la 345 metri de buza putului. Deviatia este la 19 metri sub fractionare. Am testat echiparea cu 142 coborari. Ultimul control al spiturilor: acum 116 luni.', 'doc_existing_c48_12.txt', 434, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2122, 48, 'cave', 910, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2123, 218, 'cave_area', 910, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2124, 2977, 'cave_place', 910, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (911, 'Document PeÈ™tera G2 din Piatra Lupului #13', 'Jurnal de expeditie subterana - ziua 306. Am intrat in pestera la ora 71. Parcursul pana la tabara subterana a durat 441 ore. Am transportat 233 kilograme de echipament. La tabara temperatura era de 469 grade. Am montat 191 corturi in sala mare. Rezerva de apa potabila este de 424 litri. Am planificat 183 obiective de explorat. Primul obiectiv se afla la 212 metri de tabara. Comunicarea radio functioneaza pe o distanta de 133 metri. Am verificat starea corzilor pe 3 puturi. Am acumulat 281 ore de topografie. Fotodocumentarea a produs 381 imagini RAW. Urmatoarea tura de explorare incepe in 369 ore. Echipa este formata acum din 97 persoane active. Atmosfera din galeria inferioara contine 228 procente CO2. Am stabilit o limita de siguranta la 346 metri distanta. Stocul de baterii este suficient pentru 262 ore de functionare. Moralul echipei este excelent dupa 310 zile sub pamant.', 'doc_existing_c48_13.txt', 889, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2125, 48, 'cave', 911, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2126, 2986, 'cave_place', 911, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (912, 'Document PeÈ™tera G2 din Piatra Lupului #14', 'Registru vizitatori - luna 62. Total vizitatori inregistrati: 473. Dintre acestia, 129 au participat la ture ghidate. Am organizat 95 ture pentru grupuri scolare. Media participantilor per tura: 20 persoane. Am distribuit 163 pliante informative. Am colectat 382 chestionare de feedback. Nota medie acordata: 409 din 10. Am inregistrat 249 incidente minore. Veniturile din taxe: 344 lei. Am angajat 46 ghizi suplimentari. Programul de vizitare a fost extins cu 467 ore pe saptamana.', 'doc_existing_c48_14.txt', 482, NULL, 'text_document', 1775820085);
