INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (934, 'Document PeÈ™tera G3 din Piatra Lupului #1', 'Fisa tehnica echipare put - verticala nr. 398. Adancimea: 347 metri. Am instalat 448 spituri din otel inoxidabil. Distanta intre spituri: 323 metri. Lungimea corzii principale: 291 metri. Coarda de siguranta: 357 metri. Am montat 99 protectoare de franghie. Fractionarea se face la 104 metri de buza putului. Deviatia este la 445 metri sub fractionare. Am testat echiparea cu 456 coborari. Ultimul control al spiturilor: acum 330 luni.', 'doc_existing_c49_1.txt', 435, NULL, 'text_document', 1775820085);
