INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (935, 'Document PeÈ™tera G3 din Piatra Lupului #2', 'Registru vizitatori - luna 315. Total vizitatori inregistrati: 296. Dintre acestia, 287 au participat la ture ghidate. Am organizat 383 ture pentru grupuri scolare. Media participantilor per tura: 321 persoane. Am distribuit 281 pliante informative. Am colectat 406 chestionare de feedback. Nota medie acordata: 328 din 10. Am inregistrat 440 incidente minore. Veniturile din taxe: 9 lei. Am angajat 19 ghizi suplimentari. Programul de vizitare a fost extins cu 410 ore pe saptamana.', 'doc_existing_c49_2.txt', 483, NULL, 'text_document', 1775820085);
