INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (938, 'Document PeÈ™tera H1 din Piatra Lupului #1', 'Plan de explorare - obiectiv 394. Am identificat 330 galerii laterale neexplorate. Lungimea estimata: 68 metri pe fiecare. Sunt necesare 264 zile de explorare. Echipa recomandata: 298 persoane. Echipament vertical necesar pentru 136 puturi. Am pregatit 177 kilograme de echipament. Rezerva de carbid: 233 kilograme. Punctul de plecare este statia topografica 145. Comunicarea radio va fi testata la 30 puncte. Am obtinut 55 autorizatii necesare. Data planificata: peste 457 saptamani. Bugetul estimat: 426 lei.', 'doc_existing_c50_1.txt', 510, NULL, 'text_document', 1775820085);
