INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (939, 'Document PeÈ™tera H1 din Piatra Lupului #2', 'Plan de explorare - obiectiv 313. Am identificat 369 galerii laterale neexplorate. Lungimea estimata: 85 metri pe fiecare. Sunt necesare 70 zile de explorare. Echipa recomandata: 205 persoane. Echipament vertical necesar pentru 237 puturi. Am pregatit 323 kilograme de echipament. Rezerva de carbid: 247 kilograme. Punctul de plecare este statia topografica 50. Comunicarea radio va fi testata la 406 puncte. Am obtinut 155 autorizatii necesare. Data planificata: peste 202 saptamani. Bugetul estimat: 25 lei.', 'doc_existing_c50_2.txt', 509, NULL, 'text_document', 1775820085);
