INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (940, 'Document PeÈ™tera H1 din Piatra Lupului #3', 'Raport conservare patrimoniu - obiectiv 241. Am evaluat starea a 322 inscriptii istorice. Dintre acestea, 423 necesita interventie urgenta. Am curatat 372 metri patrati de graffiti modern. Am instalat 260 panouri informative la intrare. Bariera de protectie acopera 212 metri liniari. Am documentat 443 urme de vandalism. Raportul a fost transmis autoritatilor locale in 3 exemplare. Am propus clasificarea a 282 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 413 persoane simultan. Am instruit 162 ghizi locali. Costul estimat al lucrarilor: 285 lei. Termenul de finalizare: 391 luni.', 'doc_existing_c50_3.txt', 604, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2194, 50, 'cave', 940, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2195, 3146, 'cave_place', 940, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (941, 'Document PeÈ™tera H1 din Piatra Lupului #4', 'Observatii topografice - tura nr. 437. Am efectuat 258 vizari cu busola si clinometrul. Lungimea poligonalei este de 171 metri. Diferenta de nivel totala: 227 metri. Am folosit statia nr. 464 ca baza. Eroarea de inchidere a poligonalei a fost sub 398 procente. Galeria prezinta un azimut predominant de 358 grade. Panta medie a galeriei este de 203 grade. Latimea variaza intre 325 si aproximativ dublu. Inaltimea maxima a sectiunii este de 270 metri. Am setat 46 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 438. Estimare galerie nemasurata: 47 metri. Am notat 93 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:221. Informam administratia ariei protejate despre descoperirea de la sectorul 85.', 'doc_existing_c50_4.txt', 749, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2196, 50, 'cave', 941, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2197, 229, 'cave_area', 941, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2198, 3138, 'cave_place', 941, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (942, 'Document PeÈ™tera H1 din Piatra Lupului #5', 'Plan de explorare - obiectiv 116. Am identificat 468 galerii laterale neexplorate. Lungimea estimata: 430 metri pe fiecare. Sunt necesare 418 zile de explorare. Echipa recomandata: 367 persoane. Echipament vertical necesar pentru 13 puturi. Am pregatit 144 kilograme de echipament. Rezerva de carbid: 112 kilograme. Punctul de plecare este statia topografica 114. Comunicarea radio va fi testata la 274 puncte. Am obtinut 331 autorizatii necesare. Data planificata: peste 137 saptamani. Bugetul estimat: 271 lei.', 'doc_existing_c50_5.txt', 512, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2199, 50, 'cave', 942, 1775820085);
