INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (943, 'Document PeÈ™tera H1 din Piatra Lupului #6', 'Jurnal de expeditie subterana - ziua 46. Am intrat in pestera la ora 155. Parcursul pana la tabara subterana a durat 419 ore. Am transportat 121 kilograme de echipament. La tabara temperatura era de 373 grade. Am montat 135 corturi in sala mare. Rezerva de apa potabila este de 415 litri. Am planificat 433 obiective de explorat. Primul obiectiv se afla la 349 metri de tabara. Comunicarea radio functioneaza pe o distanta de 221 metri. Am verificat starea corzilor pe 7 puturi. Am acumulat 225 ore de topografie. Fotodocumentarea a produs 65 imagini RAW. Urmatoarea tura de explorare incepe in 233 ore. Echipa este formata acum din 436 persoane active. Atmosfera din galeria inferioara contine 339 procente CO2. Am stabilit o limita de siguranta la 22 metri distanta. Stocul de baterii este suficient pentru 273 ore de functionare. Moralul echipei este excelent dupa 461 zile sub pamant.', 'doc_existing_c50_6.txt', 888, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2201, 50, 'cave', 943, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2202, 3144, 'cave_place', 943, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (944, 'Document PeÈ™tera H1 din Piatra Lupului #7', 'Nota de mentenanta balize - traseul 4. Am verificat 366 balize reflectorizante. Dintre acestea, 483 au fost inlocuite. Am adaugat 265 balize noi in zonele nemarcate. Distanta medie intre balize: 343 metri. Am folosit 223 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 489 metri cu lampa frontala. Am eliminat 230 marcaje vechi si confuze. Traseul total balizat: 410 metri. Urmatoarea verificare: peste 500 luni. Materialul consumat: 9 benzi reflectorizante.', 'doc_existing_c50_7.txt', 481, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2203, 50, 'cave', 944, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2204, 227, 'cave_area', 944, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2205, 3129, 'cave_place', 944, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (945, 'Document PeÈ™tera H1 din Piatra Lupului #8', 'Inventar echipament - depozit subteran 405. Total corzi disponibile: 327 metri. Dintre acestea, 264 metri necesita inlocuire. Am verificat 322 carabiniere si 7 plachete. Corzi statice diametru 10mm: 381 bucati. Am adaugat 196 saci de transport noi. Lampi de rezerva: 240 bucati cu baterii pline. Stocul de carbid: 426 kilograme. Truse de prim ajutor: 285 complete, verificate. Echipamentul este depozitat la 108 metri de intrare. Urmatoarea verificare programata peste 340 saptamani. Am retras din uz 213 echipamente expirate. Bugetul anual de echipament: 29 lei.', 'doc_existing_c50_8.txt', 563, NULL, 'text_document', 1775820085);
