INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (946, 'Document PeÈ™tera H1 din Piatra Lupului #9', 'Fisa tehnica echipare put - verticala nr. 329. Adancimea: 495 metri. Am instalat 176 spituri din otel inoxidabil. Distanta intre spituri: 194 metri. Lungimea corzii principale: 363 metri. Coarda de siguranta: 14 metri. Am montat 371 protectoare de franghie. Fractionarea se face la 220 metri de buza putului. Deviatia este la 45 metri sub fractionare. Am testat echiparea cu 387 coborari. Ultimul control al spiturilor: acum 292 luni.', 'doc_existing_c50_9.txt', 434, NULL, 'text_document', 1775820085);
