INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (947, 'Document PeÈ™tera H1 din Piatra Lupului #10', 'Plan de explorare - obiectiv 65. Am identificat 41 galerii laterale neexplorate. Lungimea estimata: 396 metri pe fiecare. Sunt necesare 101 zile de explorare. Echipa recomandata: 287 persoane. Echipament vertical necesar pentru 481 puturi. Am pregatit 433 kilograme de echipament. Rezerva de carbid: 415 kilograme. Punctul de plecare este statia topografica 351. Comunicarea radio va fi testata la 479 puncte. Am obtinut 180 autorizatii necesare. Data planificata: peste 91 saptamani. Bugetul estimat: 265 lei.', 'doc_existing_c50_10.txt', 510, NULL, 'text_document', 1775820085);
