INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (948, 'Document PeÈ™tera H1 din Piatra Lupului #11', 'Raport conservare patrimoniu - obiectiv 204. Am evaluat starea a 428 inscriptii istorice. Dintre acestea, 238 necesita interventie urgenta. Am curatat 42 metri patrati de graffiti modern. Am instalat 394 panouri informative la intrare. Bariera de protectie acopera 236 metri liniari. Am documentat 152 urme de vandalism. Raportul a fost transmis autoritatilor locale in 150 exemplare. Am propus clasificarea a 333 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 107 persoane simultan. Am instruit 117 ghizi locali. Costul estimat al lucrarilor: 102 lei. Termenul de finalizare: 2 luni.', 'doc_existing_c50_11.txt', 603, NULL, 'text_document', 1775820085);
