INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (949, 'Document PeÈ™tera H1 din Piatra Lupului #12', 'Raport climatologic subteran - statia 349. Senzorul a inregistrat 160 cicluri complete de temperatura. Temperatura medie anuala: 444 grade Celsius. Amplitudinea termica maxima: 366 grade. Umiditatea relativa medie: 121 procente. Concentratia de CO2: 255 ppm. Curentul de aer maxim masurat: 205 metri pe secunda. Directia predominanta a curentului: sector 85. Datalogerul a functionat 65 zile fara intrerupere. Am descarcat 322 megabytes de date brute. Presiunea barometrica la intrare: 454 mbar. Evaporarea masurata: 91 milimetri pe luna. Am comparat datele cu 408 statii meteorologice de suprafata. Raportul complet include 378 grafice si tabele. Monitorizarea continua de 373 luni confirma stabilitatea climatica.', 'doc_existing_c50_12.txt', 715, NULL, 'text_document', 1775820085);
