INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (953, 'Document PeÈ™tera H1 din Piatra Lupului #16', 'Raport formare speologica - curs nr. 230. Am instruit 175 cursanti. Durata cursului: 363 zile. Am efectuat 491 sesiuni practice in pestera. Fiecare cursant a parcurs 285 metri de galerie. Am acoperit 84 module teoretice. Examenul final a fost promovat de 244 participanti. Am distribuit 264 seturi de echipament pentru practica. Feedback-ul mediu: 160 din 10. Urmatorul curs incepe in 432 saptamani.', 'doc_existing_c50_16.txt', 399, NULL, 'text_document', 1775820085);
