INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (954, 'Document PeÈ™tera H1 din Piatra Lupului #17', 'Nota de mentenanta balize - traseul 42. Am verificat 239 balize reflectorizante. Dintre acestea, 339 au fost inlocuite. Am adaugat 64 balize noi in zonele nemarcate. Distanta medie intre balize: 254 metri. Am folosit 375 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 230 metri cu lampa frontala. Am eliminat 7 marcaje vechi si confuze. Traseul total balizat: 449 metri. Urmatoarea verificare: peste 411 luni. Materialul consumat: 355 benzi reflectorizante.', 'doc_existing_c50_17.txt', 481, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2229, 50, 'cave', 954, 1775820085);
