INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (955, 'Document PeÈ™tera H1 din Piatra Lupului #18', 'Jurnal de expeditie subterana - ziua 112. Am intrat in pestera la ora 125. Parcursul pana la tabara subterana a durat 289 ore. Am transportat 196 kilograme de echipament. La tabara temperatura era de 333 grade. Am montat 117 corturi in sala mare. Rezerva de apa potabila este de 238 litri. Am planificat 432 obiective de explorat. Primul obiectiv se afla la 263 metri de tabara. Comunicarea radio functioneaza pe o distanta de 383 metri. Am verificat starea corzilor pe 256 puturi. Am acumulat 70 ore de topografie. Fotodocumentarea a produs 424 imagini RAW. Urmatoarea tura de explorare incepe in 137 ore. Echipa este formata acum din 135 persoane active. Atmosfera din galeria inferioara contine 263 procente CO2. Am stabilit o limita de siguranta la 213 metri distanta. Stocul de baterii este suficient pentru 432 ore de functionare. Moralul echipei este excelent dupa 22 zile sub pamant.', 'doc_existing_c50_18.txt', 891, NULL, 'text_document', 1775820085);
