INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (958, 'Document PeÈ™tera H2 din Piatra Lupului #1', 'Raport formare speologica - curs nr. 195. Am instruit 175 cursanti. Durata cursului: 29 zile. Am efectuat 467 sesiuni practice in pestera. Fiecare cursant a parcurs 399 metri de galerie. Am acoperit 229 module teoretice. Examenul final a fost promovat de 111 participanti. Am distribuit 425 seturi de echipament pentru practica. Feedback-ul mediu: 113 din 10. Urmatorul curs incepe in 249 saptamani.', 'doc_existing_c51_1.txt', 399, NULL, 'text_document', 1775820085);
