INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (959, 'Document PeÈ™tera H2 din Piatra Lupului #2', 'Observatii topografice - tura nr. 377. Am efectuat 451 vizari cu busola si clinometrul. Lungimea poligonalei este de 288 metri. Diferenta de nivel totala: 212 metri. Am folosit statia nr. 304 ca baza. Eroarea de inchidere a poligonalei a fost sub 382 procente. Galeria prezinta un azimut predominant de 166 grade. Panta medie a galeriei este de 396 grade. Latimea variaza intre 427 si aproximativ dublu. Inaltimea maxima a sectiunii este de 134 metri. Am setat 165 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 193. Estimare galerie nemasurata: 417 metri. Am notat 314 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:498. Informam administratia ariei protejate despre descoperirea de la sectorul 341.', 'doc_existing_c51_2.txt', 753, NULL, 'text_document', 1775820085);
