INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (961, 'Document PeÈ™tera H2 din Piatra Lupului #4', 'Registru vizitatori - luna 266. Total vizitatori inregistrati: 56. Dintre acestia, 283 au participat la ture ghidate. Am organizat 121 ture pentru grupuri scolare. Media participantilor per tura: 335 persoane. Am distribuit 204 pliante informative. Am colectat 220 chestionare de feedback. Nota medie acordata: 312 din 10. Am inregistrat 125 incidente minore. Veniturile din taxe: 50 lei. Am angajat 500 ghizi suplimentari. Programul de vizitare a fost extins cu 494 ore pe saptamana.', 'doc_existing_c51_4.txt', 484, NULL, 'text_document', 1775820085);
