INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (964, 'Document PeÈ™tera H2 din Piatra Lupului #7', 'Raport conservare patrimoniu - obiectiv 82. Am evaluat starea a 371 inscriptii istorice. Dintre acestea, 60 necesita interventie urgenta. Am curatat 256 metri patrati de graffiti modern. Am instalat 136 panouri informative la intrare. Bariera de protectie acopera 411 metri liniari. Am documentat 99 urme de vandalism. Raportul a fost transmis autoritatilor locale in 255 exemplare. Am propus clasificarea a 221 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 111 persoane simultan. Am instruit 323 ghizi locali. Costul estimat al lucrarilor: 213 lei. Termenul de finalizare: 285 luni.', 'doc_existing_c51_7.txt', 603, NULL, 'text_document', 1775820085);
