INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (966, 'Document PeÈ™tera H2 din Piatra Lupului #9', 'Plan de explorare - obiectiv 396. Am identificat 299 galerii laterale neexplorate. Lungimea estimata: 89 metri pe fiecare. Sunt necesare 258 zile de explorare. Echipa recomandata: 238 persoane. Echipament vertical necesar pentru 239 puturi. Am pregatit 128 kilograme de echipament. Rezerva de carbid: 44 kilograme. Punctul de plecare este statia topografica 177. Comunicarea radio va fi testata la 416 puncte. Am obtinut 384 autorizatii necesare. Data planificata: peste 451 saptamani. Bugetul estimat: 308 lei.', 'doc_existing_c51_9.txt', 511, NULL, 'text_document', 1775820085);
