INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (968, 'Document PeÈ™tera H2 din Piatra Lupului #11', 'Raport climatologic subteran - statia 92. Senzorul a inregistrat 231 cicluri complete de temperatura. Temperatura medie anuala: 193 grade Celsius. Amplitudinea termica maxima: 374 grade. Umiditatea relativa medie: 255 procente. Concentratia de CO2: 166 ppm. Curentul de aer maxim masurat: 42 metri pe secunda. Directia predominanta a curentului: sector 131. Datalogerul a functionat 329 zile fara intrerupere. Am descarcat 214 megabytes de date brute. Presiunea barometrica la intrare: 305 mbar. Evaporarea masurata: 38 milimetri pe luna. Am comparat datele cu 372 statii meteorologice de suprafata. Raportul complet include 192 grafice si tabele. Monitorizarea continua de 164 luni confirma stabilitatea climatica.', 'doc_existing_c51_11.txt', 715, NULL, 'text_document', 1775820085);
