INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (973, 'Document PeÈ™tera H2 din Piatra Lupului #16', 'Inventar echipament - depozit subteran 79. Total corzi disponibile: 364 metri. Dintre acestea, 426 metri necesita inlocuire. Am verificat 243 carabiniere si 359 plachete. Corzi statice diametru 10mm: 24 bucati. Am adaugat 423 saci de transport noi. Lampi de rezerva: 245 bucati cu baterii pline. Stocul de carbid: 19 kilograme. Truse de prim ajutor: 363 complete, verificate. Echipamentul este depozitat la 207 metri de intrare. Urmatoarea verificare programata peste 362 saptamani. Am retras din uz 177 echipamente expirate. Bugetul anual de echipament: 344 lei.', 'doc_existing_c51_16.txt', 563, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2276, 51, 'cave', 973, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (974, 'Document PeÈ™tera H2 din Piatra Lupului #17', 'Raport formare speologica - curs nr. 117. Am instruit 380 cursanti. Durata cursului: 379 zile. Am efectuat 336 sesiuni practice in pestera. Fiecare cursant a parcurs 344 metri de galerie. Am acoperit 146 module teoretice. Examenul final a fost promovat de 329 participanti. Am distribuit 405 seturi de echipament pentru practica. Feedback-ul mediu: 77 din 10. Urmatorul curs incepe in 419 saptamani.', 'doc_existing_c51_17.txt', 399, NULL, 'text_document', 1775820085);
