INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (986, 'Document PeÈ™tera H3 din Piatra Lupului #1', 'Plan de explorare - obiectiv 468. Am identificat 278 galerii laterale neexplorate. Lungimea estimata: 45 metri pe fiecare. Sunt necesare 366 zile de explorare. Echipa recomandata: 74 persoane. Echipament vertical necesar pentru 232 puturi. Am pregatit 153 kilograme de echipament. Rezerva de carbid: 391 kilograme. Punctul de plecare este statia topografica 167. Comunicarea radio va fi testata la 181 puncte. Am obtinut 349 autorizatii necesare. Data planificata: peste 271 saptamani. Bugetul estimat: 500 lei.', 'doc_existing_c52_1.txt', 511, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2304, 52, 'cave', 986, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2305, 3229, 'cave_place', 986, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (987, 'Document PeÈ™tera H3 din Piatra Lupului #2', 'Observatii topografice - tura nr. 61. Am efectuat 118 vizari cu busola si clinometrul. Lungimea poligonalei este de 221 metri. Diferenta de nivel totala: 274 metri. Am folosit statia nr. 90 ca baza. Eroarea de inchidere a poligonalei a fost sub 103 procente. Galeria prezinta un azimut predominant de 491 grade. Panta medie a galeriei este de 278 grade. Latimea variaza intre 307 si aproximativ dublu. Inaltimea maxima a sectiunii este de 341 metri. Am setat 174 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 394. Estimare galerie nemasurata: 427 metri. Am notat 38 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:313. Informam administratia ariei protejate despre descoperirea de la sectorul 424.', 'doc_existing_c52_2.txt', 750, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2306, 52, 'cave', 987, 1775820085);
