INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (994, 'Document PeÈ™tera H4 din Piatra Lupului #1', 'Observatii topografice - tura nr. 3. Am efectuat 400 vizari cu busola si clinometrul. Lungimea poligonalei este de 447 metri. Diferenta de nivel totala: 46 metri. Am folosit statia nr. 371 ca baza. Eroarea de inchidere a poligonalei a fost sub 236 procente. Galeria prezinta un azimut predominant de 316 grade. Panta medie a galeriei este de 120 grade. Latimea variaza intre 228 si aproximativ dublu. Inaltimea maxima a sectiunii este de 203 metri. Am setat 61 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 123. Estimare galerie nemasurata: 17 metri. Am notat 369 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:39. Informam administratia ariei protejate despre descoperirea de la sectorul 308.', 'doc_existing_c53_1.txt', 747, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2322, 53, 'cave', 994, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2323, 3287, 'cave_place', 994, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (995, 'Document PeÈ™tera H4 din Piatra Lupului #2', 'Raport climatologic subteran - statia 451. Senzorul a inregistrat 335 cicluri complete de temperatura. Temperatura medie anuala: 249 grade Celsius. Amplitudinea termica maxima: 154 grade. Umiditatea relativa medie: 153 procente. Concentratia de CO2: 315 ppm. Curentul de aer maxim masurat: 42 metri pe secunda. Directia predominanta a curentului: sector 300. Datalogerul a functionat 406 zile fara intrerupere. Am descarcat 70 megabytes de date brute. Presiunea barometrica la intrare: 22 mbar. Evaporarea masurata: 199 milimetri pe luna. Am comparat datele cu 264 statii meteorologice de suprafata. Raportul complet include 4 grafice si tabele. Monitorizarea continua de 322 luni confirma stabilitatea climatica.', 'doc_existing_c53_2.txt', 713, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2324, 53, 'cave', 995, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2325, 3337, 'cave_place', 995, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (996, 'Document PeÈ™tera H4 din Piatra Lupului #3', 'Fisa tehnica echipare put - verticala nr. 92. Adancimea: 188 metri. Am instalat 32 spituri din otel inoxidabil. Distanta intre spituri: 228 metri. Lungimea corzii principale: 58 metri. Coarda de siguranta: 365 metri. Am montat 203 protectoare de franghie. Fractionarea se face la 153 metri de buza putului. Deviatia este la 305 metri sub fractionare. Am testat echiparea cu 328 coborari. Ultimul control al spiturilor: acum 119 luni.', 'doc_existing_c53_3.txt', 433, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2326, 53, 'cave', 996, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2327, 241, 'cave_area', 996, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2328, 3323, 'cave_place', 996, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (997, 'Document PeÈ™tera H4 din Piatra Lupului #4', 'Plan de explorare - obiectiv 191. Am identificat 443 galerii laterale neexplorate. Lungimea estimata: 118 metri pe fiecare. Sunt necesare 380 zile de explorare. Echipa recomandata: 252 persoane. Echipament vertical necesar pentru 114 puturi. Am pregatit 339 kilograme de echipament. Rezerva de carbid: 203 kilograme. Punctul de plecare este statia topografica 36. Comunicarea radio va fi testata la 463 puncte. Am obtinut 361 autorizatii necesare. Data planificata: peste 460 saptamani. Bugetul estimat: 252 lei.', 'doc_existing_c53_4.txt', 512, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2329, 53, 'cave', 997, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2330, 243, 'cave_area', 997, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2331, 3296, 'cave_place', 997, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (998, 'Document PeÈ™tera H4 din Piatra Lupului #5', 'Jurnal de expeditie subterana - ziua 291. Am intrat in pestera la ora 134. Parcursul pana la tabara subterana a durat 79 ore. Am transportat 138 kilograme de echipament. La tabara temperatura era de 436 grade. Am montat 348 corturi in sala mare. Rezerva de apa potabila este de 121 litri. Am planificat 306 obiective de explorat. Primul obiectiv se afla la 183 metri de tabara. Comunicarea radio functioneaza pe o distanta de 120 metri. Am verificat starea corzilor pe 399 puturi. Am acumulat 305 ore de topografie. Fotodocumentarea a produs 51 imagini RAW. Urmatoarea tura de explorare incepe in 279 ore. Echipa este formata acum din 198 persoane active. Atmosfera din galeria inferioara contine 78 procente CO2. Am stabilit o limita de siguranta la 489 metri distanta. Stocul de baterii este suficient pentru 266 ore de functionare. Moralul echipei este excelent dupa 182 zile sub pamant.', 'doc_existing_c53_5.txt', 890, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2332, 53, 'cave', 998, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (999, 'Document PeÈ™tera H4 din Piatra Lupului #6', 'Raport conservare patrimoniu - obiectiv 206. Am evaluat starea a 274 inscriptii istorice. Dintre acestea, 169 necesita interventie urgenta. Am curatat 259 metri patrati de graffiti modern. Am instalat 147 panouri informative la intrare. Bariera de protectie acopera 84 metri liniari. Am documentat 93 urme de vandalism. Raportul a fost transmis autoritatilor locale in 83 exemplare. Am propus clasificarea a 150 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 342 persoane simultan. Am instruit 104 ghizi locali. Costul estimat al lucrarilor: 37 lei. Termenul de finalizare: 408 luni.', 'doc_existing_c53_6.txt', 602, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2333, 53, 'cave', 999, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2334, 3363, 'cave_place', 999, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1000, 'Document PeÈ™tera H4 din Piatra Lupului #7', 'Inventar echipament - depozit subteran 9. Total corzi disponibile: 218 metri. Dintre acestea, 27 metri necesita inlocuire. Am verificat 235 carabiniere si 360 plachete. Corzi statice diametru 10mm: 257 bucati. Am adaugat 122 saci de transport noi. Lampi de rezerva: 49 bucati cu baterii pline. Stocul de carbid: 69 kilograme. Truse de prim ajutor: 76 complete, verificate. Echipamentul este depozitat la 280 metri de intrare. Urmatoarea verificare programata peste 382 saptamani. Am retras din uz 239 echipamente expirate. Bugetul anual de echipament: 21 lei.', 'doc_existing_c53_7.txt', 559, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2335, 53, 'cave', 1000, 1775820085);
