INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1009, 'Document PeÈ™tera din Dealul Glimea #1', 'Observatii topografice - tura nr. 162. Am efectuat 55 vizari cu busola si clinometrul. Lungimea poligonalei este de 18 metri. Diferenta de nivel totala: 115 metri. Am folosit statia nr. 51 ca baza. Eroarea de inchidere a poligonalei a fost sub 99 procente. Galeria prezinta un azimut predominant de 354 grade. Panta medie a galeriei este de 102 grade. Latimea variaza intre 392 si aproximativ dublu. Inaltimea maxima a sectiunii este de 229 metri. Am setat 216 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 345. Estimare galerie nemasurata: 444 metri. Am notat 39 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:408. Informam administratia ariei protejate despre descoperirea de la sectorul 91.', 'doc_existing_c54_1.txt', 747, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2356, 54, 'cave', 1009, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2357, 245, 'cave_area', 1009, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2358, 3406, 'cave_place', 1009, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1010, 'Document PeÈ™tera din Dealul Glimea #2', 'Raport climatologic subteran - statia 198. Senzorul a inregistrat 345 cicluri complete de temperatura. Temperatura medie anuala: 77 grade Celsius. Amplitudinea termica maxima: 18 grade. Umiditatea relativa medie: 343 procente. Concentratia de CO2: 320 ppm. Curentul de aer maxim masurat: 277 metri pe secunda. Directia predominanta a curentului: sector 24. Datalogerul a functionat 409 zile fara intrerupere. Am descarcat 117 megabytes de date brute. Presiunea barometrica la intrare: 338 mbar. Evaporarea masurata: 395 milimetri pe luna. Am comparat datele cu 73 statii meteorologice de suprafata. Raportul complet include 468 grafice si tabele. Monitorizarea continua de 423 luni confirma stabilitatea climatica.', 'doc_existing_c54_2.txt', 714, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2359, 54, 'cave', 1010, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2360, 247, 'cave_area', 1010, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2361, 3377, 'cave_place', 1010, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1011, 'Document PeÈ™tera din Dealul Glimea #3', 'Raport formare speologica - curs nr. 337. Am instruit 89 cursanti. Durata cursului: 152 zile. Am efectuat 5 sesiuni practice in pestera. Fiecare cursant a parcurs 17 metri de galerie. Am acoperit 170 module teoretice. Examenul final a fost promovat de 478 participanti. Am distribuit 480 seturi de echipament pentru practica. Feedback-ul mediu: 73 din 10. Urmatorul curs incepe in 469 saptamani.', 'doc_existing_c54_3.txt', 395, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2362, 54, 'cave', 1011, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2363, 248, 'cave_area', 1011, 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2364, 3442, 'cave_place', 1011, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1012, 'Document PeÈ™tera din Dealul Glimea #4', 'Raport formare speologica - curs nr. 441. Am instruit 65 cursanti. Durata cursului: 151 zile. Am efectuat 373 sesiuni practice in pestera. Fiecare cursant a parcurs 460 metri de galerie. Am acoperit 72 module teoretice. Examenul final a fost promovat de 137 participanti. Am distribuit 393 seturi de echipament pentru practica. Feedback-ul mediu: 48 din 10. Urmatorul curs incepe in 68 saptamani.', 'doc_existing_c54_4.txt', 396, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2365, 54, 'cave', 1012, 1775820085);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1013, 'Document PeÈ™tera din Dealul Glimea #5', 'Fisa tehnica echipare put - verticala nr. 204. Adancimea: 37 metri. Am instalat 110 spituri din otel inoxidabil. Distanta intre spituri: 240 metri. Lungimea corzii principale: 378 metri. Coarda de siguranta: 295 metri. Am montat 14 protectoare de franghie. Fractionarea se face la 266 metri de buza putului. Deviatia este la 245 metri sub fractionare. Am testat echiparea cu 14 coborari. Ultimul control al spiturilor: acum 55 luni.', 'doc_existing_c54_5.txt', 432, NULL, 'text_document', 1775820085);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2366, 54, 'cave', 1013, 1775820085);
