INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1014, 'Document PeÈ™tera din Dealul Glimea #6', 'Registru vizitatori - luna 222. Total vizitatori inregistrati: 120. Dintre acestia, 363 au participat la ture ghidate. Am organizat 104 ture pentru grupuri scolare. Media participantilor per tura: 184 persoane. Am distribuit 364 pliante informative. Am colectat 187 chestionare de feedback. Nota medie acordata: 347 din 10. Am inregistrat 230 incidente minore. Veniturile din taxe: 424 lei. Am angajat 464 ghizi suplimentari. Programul de vizitare a fost extins cu 202 ore pe saptamana.', 'doc_existing_c54_6.txt', 486, NULL, 'text_document', 1775820085);
