INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1024, 'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #1', 'Raport conservare patrimoniu - obiectiv 270. Am evaluat starea a 389 inscriptii istorice. Dintre acestea, 438 necesita interventie urgenta. Am curatat 315 metri patrati de graffiti modern. Am instalat 306 panouri informative la intrare. Bariera de protectie acopera 389 metri liniari. Am documentat 461 urme de vandalism. Raportul a fost transmis autoritatilor locale in 316 exemplare. Am propus clasificarea a 328 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 421 persoane simultan. Am instruit 105 ghizi locali. Costul estimat al lucrarilor: 392 lei. Termenul de finalizare: 347 luni.', 'doc_existing_c55_1.txt', 606, NULL, 'text_document', 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2391, 55, 'cave', 1024, 1775820086);
