INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1025, 'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #2', 'Inventar echipament - depozit subteran 75. Total corzi disponibile: 93 metri. Dintre acestea, 306 metri necesita inlocuire. Am verificat 231 carabiniere si 172 plachete. Corzi statice diametru 10mm: 88 bucati. Am adaugat 353 saci de transport noi. Lampi de rezerva: 225 bucati cu baterii pline. Stocul de carbid: 445 kilograme. Truse de prim ajutor: 289 complete, verificate. Echipamentul este depozitat la 256 metri de intrare. Urmatoarea verificare programata peste 73 saptamani. Am retras din uz 328 echipamente expirate. Bugetul anual de echipament: 199 lei.', 'doc_existing_c55_2.txt', 562, NULL, 'text_document', 1775820086);
