INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1026, 'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #3', 'Fisa tehnica echipare put - verticala nr. 481. Adancimea: 428 metri. Am instalat 329 spituri din otel inoxidabil. Distanta intre spituri: 70 metri. Lungimea corzii principale: 218 metri. Coarda de siguranta: 336 metri. Am montat 249 protectoare de franghie. Fractionarea se face la 290 metri de buza putului. Deviatia este la 490 metri sub fractionare. Am testat echiparea cu 225 coborari. Ultimul control al spiturilor: acum 113 luni.', 'doc_existing_c55_3.txt', 435, NULL, 'text_document', 1775820086);
