INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1027, 'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #4', 'Inventar echipament - depozit subteran 40. Total corzi disponibile: 45 metri. Dintre acestea, 432 metri necesita inlocuire. Am verificat 66 carabiniere si 263 plachete. Corzi statice diametru 10mm: 15 bucati. Am adaugat 85 saci de transport noi. Lampi de rezerva: 53 bucati cu baterii pline. Stocul de carbid: 370 kilograme. Truse de prim ajutor: 12 complete, verificate. Echipamentul este depozitat la 277 metri de intrare. Urmatoarea verificare programata peste 103 saptamani. Am retras din uz 128 echipamente expirate. Bugetul anual de echipament: 272 lei.', 'doc_existing_c55_4.txt', 559, NULL, 'text_document', 1775820086);
