INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1029, 'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #6', 'Registru vizitatori - luna 473. Total vizitatori inregistrati: 200. Dintre acestia, 253 au participat la ture ghidate. Am organizat 142 ture pentru grupuri scolare. Media participantilor per tura: 355 persoane. Am distribuit 419 pliante informative. Am colectat 111 chestionare de feedback. Nota medie acordata: 198 din 10. Am inregistrat 256 incidente minore. Veniturile din taxe: 6 lei. Am angajat 70 ghizi suplimentari. Programul de vizitare a fost extins cu 111 ore pe saptamana.', 'doc_existing_c55_6.txt', 483, NULL, 'text_document', 1775820086);
