INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1030, 'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #7', 'Fisa tehnica echipare put - verticala nr. 440. Adancimea: 478 metri. Am instalat 352 spituri din otel inoxidabil. Distanta intre spituri: 267 metri. Lungimea corzii principale: 298 metri. Coarda de siguranta: 138 metri. Am montat 77 protectoare de franghie. Fractionarea se face la 144 metri de buza putului. Deviatia este la 261 metri sub fractionare. Am testat echiparea cu 406 coborari. Ultimul control al spiturilor: acum 398 luni.', 'doc_existing_c55_7.txt', 435, NULL, 'text_document', 1775820086);
