INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1031, 'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #8', 'Raport formare speologica - curs nr. 432. Am instruit 44 cursanti. Durata cursului: 446 zile. Am efectuat 454 sesiuni practice in pestera. Fiecare cursant a parcurs 467 metri de galerie. Am acoperit 293 module teoretice. Examenul final a fost promovat de 259 participanti. Am distribuit 436 seturi de echipament pentru practica. Feedback-ul mediu: 361 din 10. Urmatorul curs incepe in 158 saptamani.', 'doc_existing_c55_8.txt', 399, NULL, 'text_document', 1775820086);
