INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1032, 'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #9', 'Raport conservare patrimoniu - obiectiv 296. Am evaluat starea a 375 inscriptii istorice. Dintre acestea, 91 necesita interventie urgenta. Am curatat 59 metri patrati de graffiti modern. Am instalat 495 panouri informative la intrare. Bariera de protectie acopera 102 metri liniari. Am documentat 261 urme de vandalism. Raportul a fost transmis autoritatilor locale in 79 exemplare. Am propus clasificarea a 56 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 455 persoane simultan. Am instruit 341 ghizi locali. Costul estimat al lucrarilor: 484 lei. Termenul de finalizare: 116 luni.', 'doc_existing_c55_9.txt', 602, NULL, 'text_document', 1775820086);
