INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1033, 'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #10', 'Observatii topografice - tura nr. 457. Am efectuat 430 vizari cu busola si clinometrul. Lungimea poligonalei este de 291 metri. Diferenta de nivel totala: 492 metri. Am folosit statia nr. 434 ca baza. Eroarea de inchidere a poligonalei a fost sub 347 procente. Galeria prezinta un azimut predominant de 265 grade. Panta medie a galeriei este de 64 grade. Latimea variaza intre 396 si aproximativ dublu. Inaltimea maxima a sectiunii este de 216 metri. Am setat 63 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 425. Estimare galerie nemasurata: 448 metri. Am notat 259 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:135. Informam administratia ariei protejate despre descoperirea de la sectorul 418.', 'doc_existing_c55_10.txt', 751, NULL, 'text_document', 1775820086);
