INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1035, 'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #12', 'Inventar echipament - depozit subteran 179. Total corzi disponibile: 279 metri. Dintre acestea, 415 metri necesita inlocuire. Am verificat 395 carabiniere si 385 plachete. Corzi statice diametru 10mm: 12 bucati. Am adaugat 431 saci de transport noi. Lampi de rezerva: 464 bucati cu baterii pline. Stocul de carbid: 430 kilograme. Truse de prim ajutor: 385 complete, verificate. Echipamentul este depozitat la 297 metri de intrare. Urmatoarea verificare programata peste 86 saptamani. Am retras din uz 431 echipamente expirate. Bugetul anual de echipament: 43 lei.', 'doc_existing_c55_12.txt', 563, NULL, 'text_document', 1775820086);
