INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1036, 'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #13', 'Jurnal de expeditie subterana - ziua 487. Am intrat in pestera la ora 207. Parcursul pana la tabara subterana a durat 376 ore. Am transportat 347 kilograme de echipament. La tabara temperatura era de 160 grade. Am montat 284 corturi in sala mare. Rezerva de apa potabila este de 220 litri. Am planificat 208 obiective de explorat. Primul obiectiv se afla la 267 metri de tabara. Comunicarea radio functioneaza pe o distanta de 392 metri. Am verificat starea corzilor pe 12 puturi. Am acumulat 248 ore de topografie. Fotodocumentarea a produs 348 imagini RAW. Urmatoarea tura de explorare incepe in 318 ore. Echipa este formata acum din 351 persoane active. Atmosfera din galeria inferioara contine 229 procente CO2. Am stabilit o limita de siguranta la 444 metri distanta. Stocul de baterii este suficient pentru 460 ore de functionare. Moralul echipei este excelent dupa 339 zile sub pamant.', 'doc_existing_c55_13.txt', 892, NULL, 'text_document', 1775820086);
