INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1053, 'Document PeÈ™tera nr. 2 de la FaÈ›a Cerbului #1', 'Raport conservare patrimoniu - obiectiv 65. Am evaluat starea a 223 inscriptii istorice. Dintre acestea, 253 necesita interventie urgenta. Am curatat 146 metri patrati de graffiti modern. Am instalat 134 panouri informative la intrare. Bariera de protectie acopera 224 metri liniari. Am documentat 347 urme de vandalism. Raportul a fost transmis autoritatilor locale in 458 exemplare. Am propus clasificarea a 370 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 384 persoane simultan. Am instruit 86 ghizi locali. Costul estimat al lucrarilor: 24 lei. Termenul de finalizare: 87 luni.', 'doc_existing_c56_1.txt', 602, NULL, 'text_document', 1775820086);
