INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1054, 'Document PeÈ™tera nr. 2 de la FaÈ›a Cerbului #2', 'Jurnal de expeditie subterana - ziua 210. Am intrat in pestera la ora 127. Parcursul pana la tabara subterana a durat 389 ore. Am transportat 312 kilograme de echipament. La tabara temperatura era de 132 grade. Am montat 223 corturi in sala mare. Rezerva de apa potabila este de 355 litri. Am planificat 381 obiective de explorat. Primul obiectiv se afla la 430 metri de tabara. Comunicarea radio functioneaza pe o distanta de 273 metri. Am verificat starea corzilor pe 341 puturi. Am acumulat 312 ore de topografie. Fotodocumentarea a produs 443 imagini RAW. Urmatoarea tura de explorare incepe in 464 ore. Echipa este formata acum din 120 persoane active. Atmosfera din galeria inferioara contine 157 procente CO2. Am stabilit o limita de siguranta la 48 metri distanta. Stocul de baterii este suficient pentru 129 ore de functionare. Moralul echipei este excelent dupa 295 zile sub pamant.', 'doc_existing_c56_2.txt', 892, NULL, 'text_document', 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2465, 56, 'cave', 1054, 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2466, 251, 'cave_area', 1054, 1775820086);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1055, 'Document PeÈ™tera nr. 2 de la FaÈ›a Cerbului #3', 'Raport formare speologica - curs nr. 48. Am instruit 291 cursanti. Durata cursului: 148 zile. Am efectuat 439 sesiuni practice in pestera. Fiecare cursant a parcurs 250 metri de galerie. Am acoperit 95 module teoretice. Examenul final a fost promovat de 304 participanti. Am distribuit 132 seturi de echipament pentru practica. Feedback-ul mediu: 458 din 10. Urmatorul curs incepe in 8 saptamani.', 'doc_existing_c56_3.txt', 396, NULL, 'text_document', 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2467, 56, 'cave', 1055, 1775820086);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1056, 'Document PeÈ™tera nr. 2 de la FaÈ›a Cerbului #4', 'Raport climatologic subteran - statia 181. Senzorul a inregistrat 411 cicluri complete de temperatura. Temperatura medie anuala: 113 grade Celsius. Amplitudinea termica maxima: 91 grade. Umiditatea relativa medie: 106 procente. Concentratia de CO2: 5 ppm. Curentul de aer maxim masurat: 235 metri pe secunda. Directia predominanta a curentului: sector 437. Datalogerul a functionat 319 zile fara intrerupere. Am descarcat 180 megabytes de date brute. Presiunea barometrica la intrare: 328 mbar. Evaporarea masurata: 28 milimetri pe luna. Am comparat datele cu 322 statii meteorologice de suprafata. Raportul complet include 304 grafice si tabele. Monitorizarea continua de 152 luni confirma stabilitatea climatica.', 'doc_existing_c56_4.txt', 714, NULL, 'text_document', 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2468, 56, 'cave', 1056, 1775820086);
