INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1057, 'Document PeÈ™tera nr. 2 de la FaÈ›a Cerbului #5', 'Raport climatologic subteran - statia 309. Senzorul a inregistrat 385 cicluri complete de temperatura. Temperatura medie anuala: 166 grade Celsius. Amplitudinea termica maxima: 446 grade. Umiditatea relativa medie: 247 procente. Concentratia de CO2: 139 ppm. Curentul de aer maxim masurat: 346 metri pe secunda. Directia predominanta a curentului: sector 105. Datalogerul a functionat 396 zile fara intrerupere. Am descarcat 95 megabytes de date brute. Presiunea barometrica la intrare: 461 mbar. Evaporarea masurata: 160 milimetri pe luna. Am comparat datele cu 236 statii meteorologice de suprafata. Raportul complet include 37 grafice si tabele. Monitorizarea continua de 167 luni confirma stabilitatea climatica.', 'doc_existing_c56_5.txt', 716, NULL, 'text_document', 1775820086);
