INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1058, 'Document PeÈ™tera nr. 2 de la FaÈ›a Cerbului #6', 'Raport climatologic subteran - statia 402. Senzorul a inregistrat 180 cicluri complete de temperatura. Temperatura medie anuala: 259 grade Celsius. Amplitudinea termica maxima: 59 grade. Umiditatea relativa medie: 209 procente. Concentratia de CO2: 114 ppm. Curentul de aer maxim masurat: 41 metri pe secunda. Directia predominanta a curentului: sector 116. Datalogerul a functionat 480 zile fara intrerupere. Am descarcat 420 megabytes de date brute. Presiunea barometrica la intrare: 24 mbar. Evaporarea masurata: 443 milimetri pe luna. Am comparat datele cu 317 statii meteorologice de suprafata. Raportul complet include 213 grafice si tabele. Monitorizarea continua de 496 luni confirma stabilitatea climatica.', 'doc_existing_c56_6.txt', 715, NULL, 'text_document', 1775820086);
