INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1059, 'Document PeÈ™tera nr. 2 de la FaÈ›a Cerbului #7', 'Nota de mentenanta balize - traseul 476. Am verificat 134 balize reflectorizante. Dintre acestea, 32 au fost inlocuite. Am adaugat 348 balize noi in zonele nemarcate. Distanta medie intre balize: 294 metri. Am folosit 166 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 14 metri cu lampa frontala. Am eliminat 328 marcaje vechi si confuze. Traseul total balizat: 212 metri. Urmatoarea verificare: peste 55 luni. Materialul consumat: 119 benzi reflectorizante.', 'doc_existing_c56_7.txt', 482, NULL, 'text_document', 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2476, 56, 'cave', 1059, 1775820086);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1060, 'Document PeÈ™tera nr. 2 de la FaÈ›a Cerbului #8', 'Raport formare speologica - curs nr. 373. Am instruit 481 cursanti. Durata cursului: 457 zile. Am efectuat 8 sesiuni practice in pestera. Fiecare cursant a parcurs 135 metri de galerie. Am acoperit 5 module teoretice. Examenul final a fost promovat de 178 participanti. Am distribuit 455 seturi de echipament pentru practica. Feedback-ul mediu: 37 din 10. Urmatorul curs incepe in 464 saptamani.', 'doc_existing_c56_8.txt', 395, NULL, 'text_document', 1775820086);
