INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1061, 'Document PeÈ™tera nr. 2 de la FaÈ›a Cerbului #9', 'Fisa tehnica echipare put - verticala nr. 142. Adancimea: 398 metri. Am instalat 353 spituri din otel inoxidabil. Distanta intre spituri: 269 metri. Lungimea corzii principale: 453 metri. Coarda de siguranta: 272 metri. Am montat 133 protectoare de franghie. Fractionarea se face la 435 metri de buza putului. Deviatia este la 202 metri sub fractionare. Am testat echiparea cu 433 coborari. Ultimul control al spiturilor: acum 303 luni.', 'doc_existing_c56_9.txt', 436, NULL, 'text_document', 1775820086);
