INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1062, 'Document PeÈ™tera nr. 2 de la FaÈ›a Cerbului #10', 'Inventar echipament - depozit subteran 97. Total corzi disponibile: 367 metri. Dintre acestea, 381 metri necesita inlocuire. Am verificat 13 carabiniere si 218 plachete. Corzi statice diametru 10mm: 98 bucati. Am adaugat 113 saci de transport noi. Lampi de rezerva: 245 bucati cu baterii pline. Stocul de carbid: 154 kilograme. Truse de prim ajutor: 269 complete, verificate. Echipamentul este depozitat la 257 metri de intrare. Urmatoarea verificare programata peste 210 saptamani. Am retras din uz 265 echipamente expirate. Bugetul anual de echipament: 136 lei.', 'doc_existing_c56_10.txt', 563, NULL, 'text_document', 1775820086);
