INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1069, 'Document Avenul nr. 3 din Poiana PleÈ™iÈ›a #1', 'Raport climatologic subteran - statia 299. Senzorul a inregistrat 462 cicluri complete de temperatura. Temperatura medie anuala: 402 grade Celsius. Amplitudinea termica maxima: 377 grade. Umiditatea relativa medie: 494 procente. Concentratia de CO2: 65 ppm. Curentul de aer maxim masurat: 5 metri pe secunda. Directia predominanta a curentului: sector 241. Datalogerul a functionat 490 zile fara intrerupere. Am descarcat 344 megabytes de date brute. Presiunea barometrica la intrare: 351 mbar. Evaporarea masurata: 186 milimetri pe luna. Am comparat datele cu 499 statii meteorologice de suprafata. Raportul complet include 133 grafice si tabele. Monitorizarea continua de 122 luni confirma stabilitatea climatica.', 'doc_existing_c57_1.txt', 715, NULL, 'text_document', 1775820086);
