INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1084, 'Document PeÈ™tera CaroleÈ™tilor #1', 'Plan de explorare - obiectiv 500. Am identificat 22 galerii laterale neexplorate. Lungimea estimata: 268 metri pe fiecare. Sunt necesare 150 zile de explorare. Echipa recomandata: 302 persoane. Echipament vertical necesar pentru 149 puturi. Am pregatit 402 kilograme de echipament. Rezerva de carbid: 98 kilograme. Punctul de plecare este statia topografica 482. Comunicarea radio va fi testata la 277 puncte. Am obtinut 372 autorizatii necesare. Data planificata: peste 160 saptamani. Bugetul estimat: 2 lei.', 'doc_existing_c58_1.txt', 509, NULL, 'text_document', 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2538, 58, 'cave', 1084, 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2539, 264, 'cave_area', 1084, 1775820086);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1085, 'Document PeÈ™tera CaroleÈ™tilor #2', 'Registru vizitatori - luna 484. Total vizitatori inregistrati: 93. Dintre acestia, 267 au participat la ture ghidate. Am organizat 486 ture pentru grupuri scolare. Media participantilor per tura: 378 persoane. Am distribuit 170 pliante informative. Am colectat 314 chestionare de feedback. Nota medie acordata: 20 din 10. Am inregistrat 251 incidente minore. Veniturile din taxe: 248 lei. Am angajat 119 ghizi suplimentari. Programul de vizitare a fost extins cu 393 ore pe saptamana.', 'doc_existing_c58_2.txt', 484, NULL, 'text_document', 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2540, 58, 'cave', 1085, 1775820086);
