INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1086, 'Document PeÈ™tera CaroleÈ™tilor #3', 'Inventar echipament - depozit subteran 464. Total corzi disponibile: 374 metri. Dintre acestea, 39 metri necesita inlocuire. Am verificat 477 carabiniere si 492 plachete. Corzi statice diametru 10mm: 414 bucati. Am adaugat 465 saci de transport noi. Lampi de rezerva: 483 bucati cu baterii pline. Stocul de carbid: 341 kilograme. Truse de prim ajutor: 306 complete, verificate. Echipamentul este depozitat la 200 metri de intrare. Urmatoarea verificare programata peste 156 saptamani. Am retras din uz 200 echipamente expirate. Bugetul anual de echipament: 80 lei.', 'doc_existing_c58_3.txt', 564, NULL, 'text_document', 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2542, 58, 'cave', 1086, 1775820086);
