INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1087, 'Document PeÈ™tera CaroleÈ™tilor #4', 'Raport climatologic subteran - statia 428. Senzorul a inregistrat 336 cicluri complete de temperatura. Temperatura medie anuala: 81 grade Celsius. Amplitudinea termica maxima: 490 grade. Umiditatea relativa medie: 329 procente. Concentratia de CO2: 388 ppm. Curentul de aer maxim masurat: 164 metri pe secunda. Directia predominanta a curentului: sector 480. Datalogerul a functionat 276 zile fara intrerupere. Am descarcat 326 megabytes de date brute. Presiunea barometrica la intrare: 385 mbar. Evaporarea masurata: 455 milimetri pe luna. Am comparat datele cu 98 statii meteorologice de suprafata. Raportul complet include 409 grafice si tabele. Monitorizarea continua de 428 luni confirma stabilitatea climatica.', 'doc_existing_c58_4.txt', 716, NULL, 'text_document', 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2544, 58, 'cave', 1087, 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2545, 263, 'cave_area', 1087, 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2546, 3671, 'cave_place', 1087, 1775820086);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1088, 'Document PeÈ™tera CaroleÈ™tilor #5', 'Jurnal de expeditie subterana - ziua 332. Am intrat in pestera la ora 199. Parcursul pana la tabara subterana a durat 464 ore. Am transportat 416 kilograme de echipament. La tabara temperatura era de 311 grade. Am montat 121 corturi in sala mare. Rezerva de apa potabila este de 251 litri. Am planificat 369 obiective de explorat. Primul obiectiv se afla la 464 metri de tabara. Comunicarea radio functioneaza pe o distanta de 8 metri. Am verificat starea corzilor pe 227 puturi. Am acumulat 301 ore de topografie. Fotodocumentarea a produs 225 imagini RAW. Urmatoarea tura de explorare incepe in 274 ore. Echipa este formata acum din 226 persoane active. Atmosfera din galeria inferioara contine 435 procente CO2. Am stabilit o limita de siguranta la 382 metri distanta. Stocul de baterii este suficient pentru 148 ore de functionare. Moralul echipei este excelent dupa 178 zile sub pamant.', 'doc_existing_c58_5.txt', 891, NULL, 'text_document', 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2547, 58, 'cave', 1088, 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2548, 3696, 'cave_place', 1088, 1775820086);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1089, 'Document PeÈ™tera CaroleÈ™tilor #6', 'Raport climatologic subteran - statia 201. Senzorul a inregistrat 260 cicluri complete de temperatura. Temperatura medie anuala: 52 grade Celsius. Amplitudinea termica maxima: 182 grade. Umiditatea relativa medie: 179 procente. Concentratia de CO2: 322 ppm. Curentul de aer maxim masurat: 280 metri pe secunda. Directia predominanta a curentului: sector 133. Datalogerul a functionat 45 zile fara intrerupere. Am descarcat 289 megabytes de date brute. Presiunea barometrica la intrare: 170 mbar. Evaporarea masurata: 12 milimetri pe luna. Am comparat datele cu 473 statii meteorologice de suprafata. Raportul complet include 90 grafice si tabele. Monitorizarea continua de 107 luni confirma stabilitatea climatica.', 'doc_existing_c58_6.txt', 714, NULL, 'text_document', 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2549, 58, 'cave', 1089, 1775820086);
