INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1090, 'Document PeÈ™tera CaroleÈ™tilor #7', 'Raport conservare patrimoniu - obiectiv 423. Am evaluat starea a 84 inscriptii istorice. Dintre acestea, 442 necesita interventie urgenta. Am curatat 236 metri patrati de graffiti modern. Am instalat 371 panouri informative la intrare. Bariera de protectie acopera 306 metri liniari. Am documentat 313 urme de vandalism. Raportul a fost transmis autoritatilor locale in 268 exemplare. Am propus clasificarea a 76 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 356 persoane simultan. Am instruit 460 ghizi locali. Costul estimat al lucrarilor: 326 lei. Termenul de finalizare: 326 luni.', 'doc_existing_c58_7.txt', 604, NULL, 'text_document', 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2552, 58, 'cave', 1090, 1775820086);
