INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1091, 'Document PeÈ™tera CaroleÈ™tilor #8', 'Plan de explorare - obiectiv 244. Am identificat 398 galerii laterale neexplorate. Lungimea estimata: 481 metri pe fiecare. Sunt necesare 399 zile de explorare. Echipa recomandata: 137 persoane. Echipament vertical necesar pentru 399 puturi. Am pregatit 176 kilograme de echipament. Rezerva de carbid: 467 kilograme. Punctul de plecare este statia topografica 338. Comunicarea radio va fi testata la 294 puncte. Am obtinut 169 autorizatii necesare. Data planificata: peste 301 saptamani. Bugetul estimat: 226 lei.', 'doc_existing_c58_8.txt', 513, NULL, 'text_document', 1775820086);
