INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1112, 'Document PeÈ™tera nr. 2 din Dealul Bulz #1', 'Nota de mentenanta balize - traseul 323. Am verificat 444 balize reflectorizante. Dintre acestea, 320 au fost inlocuite. Am adaugat 342 balize noi in zonele nemarcate. Distanta medie intre balize: 471 metri. Am folosit 28 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 148 metri cu lampa frontala. Am eliminat 297 marcaje vechi si confuze. Traseul total balizat: 151 metri. Urmatoarea verificare: peste 165 luni. Materialul consumat: 194 benzi reflectorizante.', 'doc_existing_c59_1.txt', 484, NULL, 'text_document', 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2609, 59, 'cave', 1112, 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2610, 266, 'cave_area', 1112, 1775820086);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1113, 'Document PeÈ™tera nr. 2 din Dealul Bulz #2', 'Raport formare speologica - curs nr. 225. Am instruit 92 cursanti. Durata cursului: 194 zile. Am efectuat 469 sesiuni practice in pestera. Fiecare cursant a parcurs 116 metri de galerie. Am acoperit 247 module teoretice. Examenul final a fost promovat de 61 participanti. Am distribuit 456 seturi de echipament pentru practica. Feedback-ul mediu: 356 din 10. Urmatorul curs incepe in 332 saptamani.', 'doc_existing_c59_2.txt', 398, NULL, 'text_document', 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2611, 59, 'cave', 1113, 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2612, 265, 'cave_area', 1113, 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2613, 3784, 'cave_place', 1113, 1775820086);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1114, 'Document PeÈ™tera nr. 2 din Dealul Bulz #3', 'Raport conservare patrimoniu - obiectiv 500. Am evaluat starea a 334 inscriptii istorice. Dintre acestea, 498 necesita interventie urgenta. Am curatat 113 metri patrati de graffiti modern. Am instalat 449 panouri informative la intrare. Bariera de protectie acopera 374 metri liniari. Am documentat 105 urme de vandalism. Raportul a fost transmis autoritatilor locale in 366 exemplare. Am propus clasificarea a 338 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 53 persoane simultan. Am instruit 424 ghizi locali. Costul estimat al lucrarilor: 340 lei. Termenul de finalizare: 242 luni.', 'doc_existing_c59_3.txt', 605, NULL, 'text_document', 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2614, 59, 'cave', 1114, 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2615, 3763, 'cave_place', 1114, 1775820086);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1115, 'Document PeÈ™tera nr. 2 din Dealul Bulz #4', 'Inventar echipament - depozit subteran 282. Total corzi disponibile: 183 metri. Dintre acestea, 142 metri necesita inlocuire. Am verificat 276 carabiniere si 251 plachete. Corzi statice diametru 10mm: 173 bucati. Am adaugat 124 saci de transport noi. Lampi de rezerva: 166 bucati cu baterii pline. Stocul de carbid: 268 kilograme. Truse de prim ajutor: 377 complete, verificate. Echipamentul este depozitat la 268 metri de intrare. Urmatoarea verificare programata peste 86 saptamani. Am retras din uz 43 echipamente expirate. Bugetul anual de echipament: 15 lei.', 'doc_existing_c59_4.txt', 563, NULL, 'text_document', 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2616, 59, 'cave', 1115, 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2617, 3766, 'cave_place', 1115, 1775820086);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1116, 'Document PeÈ™tera nr. 2 din Dealul Bulz #5', 'Raport formare speologica - curs nr. 137. Am instruit 498 cursanti. Durata cursului: 417 zile. Am efectuat 347 sesiuni practice in pestera. Fiecare cursant a parcurs 248 metri de galerie. Am acoperit 455 module teoretice. Examenul final a fost promovat de 57 participanti. Am distribuit 478 seturi de echipament pentru practica. Feedback-ul mediu: 259 din 10. Urmatorul curs incepe in 12 saptamani.', 'doc_existing_c59_5.txt', 398, NULL, 'text_document', 1775820086);
