INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1128, 'Document PeÈ™tera "Hotel" #1', 'Jurnal de expeditie subterana - ziua 397. Am intrat in pestera la ora 260. Parcursul pana la tabara subterana a durat 184 ore. Am transportat 152 kilograme de echipament. La tabara temperatura era de 281 grade. Am montat 432 corturi in sala mare. Rezerva de apa potabila este de 203 litri. Am planificat 203 obiective de explorat. Primul obiectiv se afla la 431 metri de tabara. Comunicarea radio functioneaza pe o distanta de 84 metri. Am verificat starea corzilor pe 40 puturi. Am acumulat 361 ore de topografie. Fotodocumentarea a produs 427 imagini RAW. Urmatoarea tura de explorare incepe in 90 ore. Echipa este formata acum din 449 persoane active. Atmosfera din galeria inferioara contine 218 procente CO2. Am stabilit o limita de siguranta la 494 metri distanta. Stocul de baterii este suficient pentru 497 ore de functionare. Moralul echipei este excelent dupa 126 zile sub pamant.', 'doc_existing_c60_1.txt', 890, NULL, 'text_document', 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2648, 60, 'cave', 1128, 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2649, 3796, 'cave_place', 1128, 1775820086);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1129, 'Document PeÈ™tera "Hotel" #2', 'Fisa tehnica echipare put - verticala nr. 293. Adancimea: 53 metri. Am instalat 5 spituri din otel inoxidabil. Distanta intre spituri: 295 metri. Lungimea corzii principale: 121 metri. Coarda de siguranta: 303 metri. Am montat 473 protectoare de franghie. Fractionarea se face la 224 metri de buza putului. Deviatia este la 34 metri sub fractionare. Am testat echiparea cu 38 coborari. Ultimul control al spiturilor: acum 91 luni.', 'doc_existing_c60_2.txt', 430, NULL, 'text_document', 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2650, 60, 'cave', 1129, 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2651, 270, 'cave_area', 1129, 1775820086);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1130, 'Document PeÈ™tera "Hotel" #3', 'Observatii topografice - tura nr. 394. Am efectuat 114 vizari cu busola si clinometrul. Lungimea poligonalei este de 36 metri. Diferenta de nivel totala: 302 metri. Am folosit statia nr. 181 ca baza. Eroarea de inchidere a poligonalei a fost sub 286 procente. Galeria prezinta un azimut predominant de 453 grade. Panta medie a galeriei este de 388 grade. Latimea variaza intre 92 si aproximativ dublu. Inaltimea maxima a sectiunii este de 125 metri. Am setat 490 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 317. Estimare galerie nemasurata: 155 metri. Am notat 280 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:284. Informam administratia ariei protejate despre descoperirea de la sectorul 26.', 'doc_existing_c60_3.txt', 750, NULL, 'text_document', 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2652, 60, 'cave', 1130, 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2653, 3813, 'cave_place', 1130, 1775820086);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1131, 'Document PeÈ™tera "Hotel" #4', 'Nota de mentenanta balize - traseul 447. Am verificat 483 balize reflectorizante. Dintre acestea, 345 au fost inlocuite. Am adaugat 295 balize noi in zonele nemarcate. Distanta medie intre balize: 321 metri. Am folosit 79 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 267 metri cu lampa frontala. Am eliminat 353 marcaje vechi si confuze. Traseul total balizat: 409 metri. Urmatoarea verificare: peste 307 luni. Materialul consumat: 137 benzi reflectorizante.', 'doc_existing_c60_4.txt', 484, NULL, 'text_document', 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2654, 60, 'cave', 1131, 1775820086);
