INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2656, 3842, 'cave_place', 1131, 1775820086);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1132, 'Document PeÈ™tera "Hotel" #5', 'Raport conservare patrimoniu - obiectiv 44. Am evaluat starea a 343 inscriptii istorice. Dintre acestea, 162 necesita interventie urgenta. Am curatat 6 metri patrati de graffiti modern. Am instalat 224 panouri informative la intrare. Bariera de protectie acopera 127 metri liniari. Am documentat 237 urme de vandalism. Raportul a fost transmis autoritatilor locale in 282 exemplare. Am propus clasificarea a 133 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 441 persoane simultan. Am instruit 280 ghizi locali. Costul estimat al lucrarilor: 239 lei. Termenul de finalizare: 58 luni.', 'doc_existing_c60_5.txt', 602, NULL, 'text_document', 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2657, 60, 'cave', 1132, 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2658, 270, 'cave_area', 1132, 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2659, 3838, 'cave_place', 1132, 1775820086);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1133, 'Document PeÈ™tera "Hotel" #6', 'Nota de mentenanta balize - traseul 377. Am verificat 238 balize reflectorizante. Dintre acestea, 150 au fost inlocuite. Am adaugat 273 balize noi in zonele nemarcate. Distanta medie intre balize: 17 metri. Am folosit 284 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 133 metri cu lampa frontala. Am eliminat 200 marcaje vechi si confuze. Traseul total balizat: 316 metri. Urmatoarea verificare: peste 94 luni. Materialul consumat: 85 benzi reflectorizante.', 'doc_existing_c60_6.txt', 482, NULL, 'text_document', 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2660, 60, 'cave', 1133, 1775820086);
