INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1134, 'Document PeÈ™tera "Hotel" #7', 'Jurnal de expeditie subterana - ziua 386. Am intrat in pestera la ora 500. Parcursul pana la tabara subterana a durat 364 ore. Am transportat 215 kilograme de echipament. La tabara temperatura era de 445 grade. Am montat 169 corturi in sala mare. Rezerva de apa potabila este de 365 litri. Am planificat 286 obiective de explorat. Primul obiectiv se afla la 325 metri de tabara. Comunicarea radio functioneaza pe o distanta de 375 metri. Am verificat starea corzilor pe 277 puturi. Am acumulat 136 ore de topografie. Fotodocumentarea a produs 55 imagini RAW. Urmatoarea tura de explorare incepe in 382 ore. Echipa este formata acum din 256 persoane active. Atmosfera din galeria inferioara contine 356 procente CO2. Am stabilit o limita de siguranta la 132 metri distanta. Stocul de baterii este suficient pentru 174 ore de functionare. Moralul echipei este excelent dupa 190 zile sub pamant.', 'doc_existing_c60_7.txt', 892, NULL, 'text_document', 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2662, 60, 'cave', 1134, 1775820086);
