INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1135, 'Document PeÈ™tera "Hotel" #8', 'Raport climatologic subteran - statia 47. Senzorul a inregistrat 482 cicluri complete de temperatura. Temperatura medie anuala: 177 grade Celsius. Amplitudinea termica maxima: 466 grade. Umiditatea relativa medie: 312 procente. Concentratia de CO2: 442 ppm. Curentul de aer maxim masurat: 243 metri pe secunda. Directia predominanta a curentului: sector 324. Datalogerul a functionat 215 zile fara intrerupere. Am descarcat 205 megabytes de date brute. Presiunea barometrica la intrare: 69 mbar. Evaporarea masurata: 58 milimetri pe luna. Am comparat datele cu 41 statii meteorologice de suprafata. Raportul complet include 392 grafice si tabele. Monitorizarea continua de 235 luni confirma stabilitatea climatica.', 'doc_existing_c60_8.txt', 714, NULL, 'text_document', 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2665, 60, 'cave', 1135, 1775820086);
