INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1136, 'Document PeÈ™tera "Hotel" #9', 'Observatii topografice - tura nr. 179. Am efectuat 190 vizari cu busola si clinometrul. Lungimea poligonalei este de 36 metri. Diferenta de nivel totala: 289 metri. Am folosit statia nr. 383 ca baza. Eroarea de inchidere a poligonalei a fost sub 397 procente. Galeria prezinta un azimut predominant de 372 grade. Panta medie a galeriei este de 89 grade. Latimea variaza intre 222 si aproximativ dublu. Inaltimea maxima a sectiunii este de 407 metri. Am setat 444 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 296. Estimare galerie nemasurata: 182 metri. Am notat 451 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:448. Informam administratia ariei protejate despre descoperirea de la sectorul 466.', 'doc_existing_c60_9.txt', 751, NULL, 'text_document', 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2668, 60, 'cave', 1136, 1775820086);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1137, 'Document PeÈ™tera "Hotel" #10', 'Inventar echipament - depozit subteran 247. Total corzi disponibile: 384 metri. Dintre acestea, 105 metri necesita inlocuire. Am verificat 275 carabiniere si 248 plachete. Corzi statice diametru 10mm: 8 bucati. Am adaugat 365 saci de transport noi. Lampi de rezerva: 476 bucati cu baterii pline. Stocul de carbid: 306 kilograme. Truse de prim ajutor: 50 complete, verificate. Echipamentul este depozitat la 249 metri de intrare. Urmatoarea verificare programata peste 414 saptamani. Am retras din uz 454 echipamente expirate. Bugetul anual de echipament: 60 lei.', 'doc_existing_c60_10.txt', 562, NULL, 'text_document', 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2669, 60, 'cave', 1137, 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2670, 3823, 'cave_place', 1137, 1775820086);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1138, 'Document PeÈ™tera "Hotel" #11', 'Plan de explorare - obiectiv 151. Am identificat 410 galerii laterale neexplorate. Lungimea estimata: 348 metri pe fiecare. Sunt necesare 449 zile de explorare. Echipa recomandata: 336 persoane. Echipament vertical necesar pentru 467 puturi. Am pregatit 223 kilograme de echipament. Rezerva de carbid: 79 kilograme. Punctul de plecare este statia topografica 104. Comunicarea radio va fi testata la 468 puncte. Am obtinut 10 autorizatii necesare. Data planificata: peste 180 saptamani. Bugetul estimat: 325 lei.', 'doc_existing_c60_11.txt', 511, NULL, 'text_document', 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2671, 60, 'cave', 1138, 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2672, 3803, 'cave_place', 1138, 1775820086);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1139, 'Document PeÈ™tera "Hotel" #12', 'Observatii topografice - tura nr. 58. Am efectuat 395 vizari cu busola si clinometrul. Lungimea poligonalei este de 208 metri. Diferenta de nivel totala: 416 metri. Am folosit statia nr. 477 ca baza. Eroarea de inchidere a poligonalei a fost sub 468 procente. Galeria prezinta un azimut predominant de 197 grade. Panta medie a galeriei este de 168 grade. Latimea variaza intre 149 si aproximativ dublu. Inaltimea maxima a sectiunii este de 292 metri. Am setat 452 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 430. Estimare galerie nemasurata: 321 metri. Am notat 354 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:152. Informam administratia ariei protejate despre descoperirea de la sectorul 160.', 'doc_existing_c60_12.txt', 752, NULL, 'text_document', 1775820086);
