INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1150, 'Document PeÈ™tera de la Mal #1', 'Raport formare speologica - curs nr. 24. Am instruit 312 cursanti. Durata cursului: 89 zile. Am efectuat 177 sesiuni practice in pestera. Fiecare cursant a parcurs 62 metri de galerie. Am acoperit 284 module teoretice. Examenul final a fost promovat de 276 participanti. Am distribuit 94 seturi de echipament pentru practica. Feedback-ul mediu: 29 din 10. Urmatorul curs incepe in 482 saptamani.', 'doc_existing_c61_1.txt', 395, NULL, 'text_document', 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2696, 61, 'cave', 1150, 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2697, 277, 'cave_area', 1150, 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2698, 3891, 'cave_place', 1150, 1775820086);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1151, 'Document PeÈ™tera de la Mal #2', 'Raport conservare patrimoniu - obiectiv 248. Am evaluat starea a 6 inscriptii istorice. Dintre acestea, 154 necesita interventie urgenta. Am curatat 301 metri patrati de graffiti modern. Am instalat 416 panouri informative la intrare. Bariera de protectie acopera 440 metri liniari. Am documentat 282 urme de vandalism. Raportul a fost transmis autoritatilor locale in 186 exemplare. Am propus clasificarea a 34 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 115 persoane simultan. Am instruit 98 ghizi locali. Costul estimat al lucrarilor: 263 lei. Termenul de finalizare: 244 luni.', 'doc_existing_c61_2.txt', 602, NULL, 'text_document', 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2699, 61, 'cave', 1151, 1775820086);
