INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1159, 'Document PeÈ™tera nr. 1 din Bulz #1', 'Inventar echipament - depozit subteran 146. Total corzi disponibile: 172 metri. Dintre acestea, 310 metri necesita inlocuire. Am verificat 185 carabiniere si 497 plachete. Corzi statice diametru 10mm: 277 bucati. Am adaugat 415 saci de transport noi. Lampi de rezerva: 218 bucati cu baterii pline. Stocul de carbid: 239 kilograme. Truse de prim ajutor: 442 complete, verificate. Echipamentul este depozitat la 100 metri de intrare. Urmatoarea verificare programata peste 270 saptamani. Am retras din uz 59 echipamente expirate. Bugetul anual de echipament: 336 lei.', 'doc_existing_c62_1.txt', 565, NULL, 'text_document', 1775820086);
