INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1160, 'Document PeÈ™tera nr. 1 din Bulz #2', 'Raport formare speologica - curs nr. 346. Am instruit 293 cursanti. Durata cursului: 239 zile. Am efectuat 402 sesiuni practice in pestera. Fiecare cursant a parcurs 126 metri de galerie. Am acoperit 115 module teoretice. Examenul final a fost promovat de 497 participanti. Am distribuit 271 seturi de echipament pentru practica. Feedback-ul mediu: 98 din 10. Urmatorul curs incepe in 51 saptamani.', 'doc_existing_c62_2.txt', 398, NULL, 'text_document', 1775820086);
