INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1161, 'Document PeÈ™tera nr. 1 din Bulz #3', 'Raport climatologic subteran - statia 455. Senzorul a inregistrat 95 cicluri complete de temperatura. Temperatura medie anuala: 311 grade Celsius. Amplitudinea termica maxima: 446 grade. Umiditatea relativa medie: 92 procente. Concentratia de CO2: 95 ppm. Curentul de aer maxim masurat: 222 metri pe secunda. Directia predominanta a curentului: sector 57. Datalogerul a functionat 69 zile fara intrerupere. Am descarcat 274 megabytes de date brute. Presiunea barometrica la intrare: 82 mbar. Evaporarea masurata: 45 milimetri pe luna. Am comparat datele cu 462 statii meteorologice de suprafata. Raportul complet include 188 grafice si tabele. Monitorizarea continua de 357 luni confirma stabilitatea climatica.', 'doc_existing_c62_3.txt', 711, NULL, 'text_document', 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2725, 62, 'cave', 1161, 1775820086);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1162, 'Document PeÈ™tera nr. 1 din Bulz #4', 'Raport formare speologica - curs nr. 411. Am instruit 49 cursanti. Durata cursului: 244 zile. Am efectuat 111 sesiuni practice in pestera. Fiecare cursant a parcurs 184 metri de galerie. Am acoperit 151 module teoretice. Examenul final a fost promovat de 51 participanti. Am distribuit 4 seturi de echipament pentru practica. Feedback-ul mediu: 407 din 10. Urmatorul curs incepe in 465 saptamani.', 'doc_existing_c62_4.txt', 396, NULL, 'text_document', 1775820086);
