INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1163, 'Document PeÈ™tera nr. 1 din Bulz #5', 'Jurnal de expeditie subterana - ziua 261. Am intrat in pestera la ora 105. Parcursul pana la tabara subterana a durat 333 ore. Am transportat 210 kilograme de echipament. La tabara temperatura era de 219 grade. Am montat 108 corturi in sala mare. Rezerva de apa potabila este de 304 litri. Am planificat 163 obiective de explorat. Primul obiectiv se afla la 262 metri de tabara. Comunicarea radio functioneaza pe o distanta de 171 metri. Am verificat starea corzilor pe 163 puturi. Am acumulat 69 ore de topografie. Fotodocumentarea a produs 271 imagini RAW. Urmatoarea tura de explorare incepe in 493 ore. Echipa este formata acum din 127 persoane active. Atmosfera din galeria inferioara contine 405 procente CO2. Am stabilit o limita de siguranta la 386 metri distanta. Stocul de baterii este suficient pentru 251 ore de functionare. Moralul echipei este excelent dupa 494 zile sub pamant.', 'doc_existing_c62_5.txt', 892, NULL, 'text_document', 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2729, 62, 'cave', 1163, 1775820086);
