INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1165, 'Document PeÈ™tera nr. 1 din Bulz #7', 'Registru vizitatori - luna 47. Total vizitatori inregistrati: 493. Dintre acestia, 247 au participat la ture ghidate. Am organizat 446 ture pentru grupuri scolare. Media participantilor per tura: 352 persoane. Am distribuit 138 pliante informative. Am colectat 367 chestionare de feedback. Nota medie acordata: 175 din 10. Am inregistrat 125 incidente minore. Veniturile din taxe: 35 lei. Am angajat 132 ghizi suplimentari. Programul de vizitare a fost extins cu 379 ore pe saptamana.', 'doc_existing_c62_7.txt', 484, NULL, 'text_document', 1775820086);
