INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1167, 'Document PeÈ™tera nr. 1 din Bulz #9', 'Raport conservare patrimoniu - obiectiv 59. Am evaluat starea a 283 inscriptii istorice. Dintre acestea, 446 necesita interventie urgenta. Am curatat 424 metri patrati de graffiti modern. Am instalat 49 panouri informative la intrare. Bariera de protectie acopera 430 metri liniari. Am documentat 142 urme de vandalism. Raportul a fost transmis autoritatilor locale in 140 exemplare. Am propus clasificarea a 471 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 237 persoane simultan. Am instruit 393 ghizi locali. Costul estimat al lucrarilor: 195 lei. Termenul de finalizare: 355 luni.', 'doc_existing_c62_9.txt', 604, NULL, 'text_document', 1775820086);
