INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1173, 'Document PeÈ™tera nr. 1 din Bulz #15', 'Inventar echipament - depozit subteran 417. Total corzi disponibile: 303 metri. Dintre acestea, 71 metri necesita inlocuire. Am verificat 399 carabiniere si 228 plachete. Corzi statice diametru 10mm: 165 bucati. Am adaugat 217 saci de transport noi. Lampi de rezerva: 432 bucati cu baterii pline. Stocul de carbid: 410 kilograme. Truse de prim ajutor: 331 complete, verificate. Echipamentul este depozitat la 67 metri de intrare. Urmatoarea verificare programata peste 241 saptamani. Am retras din uz 264 echipamente expirate. Bugetul anual de echipament: 164 lei.', 'doc_existing_c62_15.txt', 564, NULL, 'text_document', 1775820086);
