INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1174, 'Document PeÈ™tera nr. 1 din Bulz #16', 'Observatii topografice - tura nr. 71. Am efectuat 125 vizari cu busola si clinometrul. Lungimea poligonalei este de 475 metri. Diferenta de nivel totala: 299 metri. Am folosit statia nr. 455 ca baza. Eroarea de inchidere a poligonalei a fost sub 290 procente. Galeria prezinta un azimut predominant de 294 grade. Panta medie a galeriei este de 468 grade. Latimea variaza intre 95 si aproximativ dublu. Inaltimea maxima a sectiunii este de 404 metri. Am setat 331 borne fixe din otel inoxidabil. Urmatoarea sesiune va incepe de la statia 338. Estimare galerie nemasurata: 420 metri. Am notat 18 caracteristici morfologice particulare. Planul rezultat va fi la scara 1:259. Informam administratia ariei protejate despre descoperirea de la sectorul 404.', 'doc_existing_c62_16.txt', 750, NULL, 'text_document', 1775820086);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2751, 62, 'cave', 1174, 1775820086);
